import type { PublicCard } from '../../../types';

export const startupFundamentalsCards: PublicCard[] = [
  // === Ideation & Validation (1-35) ===
  { id: 'dc-startup-0001', deck_id: 'deck-startup-fundamentals', front: 'What is the Lean Startup methodology?', back: 'A framework by Eric Ries that emphasizes rapid iteration through the Build-Measure-Learn loop. Start with hypotheses, build a minimal product, measure results, and learn whether to pivot or persevere. Reduces waste by validating ideas before heavy investment.', sort_order: 1 , front_translations: {"de":"Was ist die Lean-Startup-Methodik?"}, back_translations: {"de":"Ein Framework von Eric Ries, das schnelle Iteration durch den Build-Measure-Learn-Zyklus betont. Man beginnt mit Hypothesen, baut ein minimales Produkt, misst die Ergebnisse und lernt, ob man pivotieren oder durchhalten sollte. Reduziert Verschwendung, indem Ideen vor grossen Investitionen validiert werden."}},
  { id: 'dc-startup-0002', deck_id: 'deck-startup-fundamentals', front: 'What is an MVP (Minimum Viable Product)?', back: 'The simplest version of a product that lets you test your core hypothesis with real users. It is not a prototype — it is a functional product with just enough features to gather validated learning. Examples: Dropbox demo video, Zappos manual shoe fulfillment.', sort_order: 2 , front_translations: {"de":"Was ist ein MVP (Minimum Viable Product)?"}, back_translations: {"de":"Die einfachste Version eines Produkts, mit der man die Kernhypothese mit echten Nutzern testen kann. Es ist kein Prototyp - es ist ein funktionsfähiges Produkt mit gerade genug Features, um validiertes Lernen zu ermöglichen. Beispiele: Dropbox-Demovideo, manueller Schuhversand bei Zappos."}},
  { id: 'dc-startup-0003', deck_id: 'deck-startup-fundamentals', front: 'What is problem-first thinking in startup ideation?', back: 'An approach where you start by identifying a real, painful problem before thinking about solutions. The best startups solve problems people already spend time, money, or effort trying to fix. Avoid building a solution in search of a problem.', sort_order: 3 , front_translations: {"de":"Was ist problemorientiertes Denken bei der Startup-Ideenfindung?"}, back_translations: {"de":"Ein Ansatz, bei dem man zuerst ein echtes, schmerzhaftes Problem identifiziert, bevor man über Lösungen nachdenkt. Die besten Startups lösen Probleme, für die Menschen bereits Zeit, Geld oder Aufwand investieren. Vermeide es, eine Lösung zu baun, die ein Problem sucht."}},
  { id: 'dc-startup-0004', deck_id: 'deck-startup-fundamentals', front: 'What does "scratch your own itch" mean in startup context?', back: 'Building a product that solves a problem you personally experience. This gives you deep understanding of the user pain point and built-in motivation. Examples: Basecamp was built because 37signals needed a project management tool for their own consulting work.', sort_order: 4 , front_translations: {"de":"Was bedeutet \"Scratch your own itch\" im Startup-Kontext?"}, back_translations: {"de":"Ein Produkt baun, das ein Problem löst, das man selbst erlebt. Das verschafft tiefes Verständnis für den Schmerzpunkt der Nutzer und intrinsische Motivation. Beispiel: Basecamp wurde entwickelt, weil 37signals ein Projektmanagement-Tool für die eigene Beratungsarbeit brauchte."}},
  { id: 'dc-startup-0005', deck_id: 'deck-startup-fundamentals', front: 'What is problem-solution fit?', back: 'The stage where you have validated that a real problem exists and your proposed solution effectively addresses it. It comes before product-market fit and means customers acknowledge the problem and find your solution compelling enough to use.', sort_order: 5 , front_translations: {"de":"Was ist Problem-Solution Fit?"}, back_translations: {"de":"Die Phase, in der validiert wurde, dass ein echtes Problem existiert und die vorgeschlagene Lösung es effektiv adressiert. Sie kommt vor dem Product-Market Fit und bedeutet, dass Kunden das Problem anerkennen und die Lösung überzeugend genug finden, um sie zu nutzen."}},
  { id: 'dc-startup-0006', deck_id: 'deck-startup-fundamentals', front: 'What are customer discovery interviews?', back: 'Structured conversations with potential customers to understand their problems, needs, and behaviors. The goal is to listen and learn, not to pitch your product. Ask about past behavior and real experiences rather than hypothetical future actions.', sort_order: 6 , front_translations: {"de":"Was sind Customer-Discovery-Interviews?"}, back_translations: {"de":"Strukturierte Gespräche mit potenziellen Kunden, um deren Probleme, Bedürfnisse und Verhaltensweisen zu verstehen. Das Ziel ist zuhören und lernen, nicht das eigene Produkt pitchen. Frage nach vergangenem Verhalten und realen Erfahrungen statt nach hypothetischen zukünftigen Handlungen."}},
  { id: 'dc-startup-0007', deck_id: 'deck-startup-fundamentals', front: 'What is the Build-Measure-Learn loop?', back: 'The core cycle of the Lean Startup. Build a minimal experiment, measure the results with actionable metrics, and learn whether your hypothesis was correct. The goal is to complete this loop as quickly as possible to accelerate validated learning.', sort_order: 7 , front_translations: {"de":"Was ist der Build-Measure-Learn-Zyklus?"}, back_translations: {"de":"Der Kernzyklus des Lean Startup. Bau ein minimales Experiment, miss die Ergebnisse mit umsetzbaren Metriken und lerne, ob die Hypothese korrekt war. Das Ziel ist, diesen Zyklus so schnell wie möglich zu durchlaufen, um validiertes Lernen zu beschleunigen."}},
  { id: 'dc-startup-0008', deck_id: 'deck-startup-fundamentals', front: 'What is a concierge MVP?', back: 'A validation technique where you manually deliver the service to each customer instead of building technology. It lets you test demand and learn about customer needs with zero development cost. Example: Food on the Table manually planned meals for early users before automating.', sort_order: 8 , front_translations: {"de":"Was ist ein Concierge MVP?"}, back_translations: {"de":"Eine Validierungstechnik, bei der man den Service manuell an jeden Kunden liefert, anstatt Technologie zu entwickeln. So kann man Nachfrage testen und Kundenbedürfnisse ohne Entwicklungskosten kennenlernen. Beispiel: Food on the Table plante Mahlzeiten manuell für frühe Nutzer, bevor es automatisiert wurde."}},
  { id: 'dc-startup-0009', deck_id: 'deck-startup-fundamentals', front: 'What is a Wizard of Oz MVP?', back: 'A type of MVP where the front end appears fully automated to the user, but a human is manually performing the work behind the scenes. It tests whether customers want the product without building the full technology. Useful for testing complex AI or automation ideas.', sort_order: 9 , front_translations: {"de":"Was ist ein Wizard-of-Oz-MVP?"}, back_translations: {"de":"Ein MVP-Typ, bei dem das Frontend für den Nutzer vollautomatisiert erscheint, aber im Hintergrund ein Mensch die Arbeit manuell erledigt. Es testet, ob Kunden das Produkt wollen, ohne die komplette Technologie zu entwickeln. Nutzlich zum Testen komplexer KI- oder Automatisierungsideen."}},
  { id: 'dc-startup-0010', deck_id: 'deck-startup-fundamentals', front: 'How can a landing page test validate a startup idea?', back: 'Create a simple landing page describing your value proposition with a sign-up or pre-order button. Drive traffic via ads and measure conversion rates. If people sign up or attempt to pay, it signals real demand. Tools like Unbounce or Carrd make this fast and cheap.', sort_order: 10 , front_translations: {"de":"Wie kann ein Landing-Page-Test eine Startup-Idee validieren?"}, back_translations: {"de":"Erstelle eine einfache Landing Page, die dein Wertversprechen beschreibt, mit einem Anmelde- oder Vorbestell-Button. Leite Traffic über Anzeigen darauf und miss die Conversion Rate. Wenn sich Leute anmelden oder versuchen zu bezahlen, signalisiert das echte Nachfrage. Tools wie Unbounce oder Carrd machen das schnell und günstig."}},
  { id: 'dc-startup-0011', deck_id: 'deck-startup-fundamentals', front: 'What is TAM (Total Addressable Market)?', back: 'The total revenue opportunity available if a product achieved 100% market share. It represents the entire demand for a product or service worldwide. Investors use TAM to assess the maximum potential of a business opportunity.', sort_order: 11 , front_translations: {"de":"Was ist TAM (Total Addressable Market)?"}, back_translations: {"de":"Die gesamte Umsatzmölichkeit, wenn ein Produkt 100% Marktanteil erreichen würde. Es repräsentiert die komplette Nachfrage nach einem Produkt oder Service weltweit. Investoren nutzen TAM, um das maximale Potenzial einer Geschäftsmöglichkeit zu bewerten."}},
  { id: 'dc-startup-0012', deck_id: 'deck-startup-fundamentals', front: 'What is SAM (Serviceable Addressable Market)?', back: 'The portion of TAM that your product can realistically serve, given geographic, regulatory, or product constraints. It narrows the total market to the segment you can actually reach with your current business model and capabilities.', sort_order: 12 , front_translations: {"de":"Was ist SAM (Serviceable Addressable Market)?"}, back_translations: {"de":"Der Anteil des TAM, den dein Produkt realistisch bedienen kann, unter Berücksichtigung geografischer, regulatorischer oder produktbezogener Einschränkungen. Er grenzt den Gesamtmarkt auf das Segment ein, das du mit deinem aktuellen Geschäftsmodell und deinen Fähigkeiten tatsächlich erreichen kannst."}},
  { id: 'dc-startup-0013', deck_id: 'deck-startup-fundamentals', front: 'What is SOM (Serviceable Obtainable Market)?', back: 'The realistic portion of SAM you can capture in the near term, considering competition, resources, and go-to-market strategy. This is the most practical metric for early-stage startups to estimate achievable revenue in the first few years.', sort_order: 13 , front_translations: {"de":"Was ist SOM (Serviceable Obtainable Market)?"}, back_translations: {"de":"Der realistische Anteil des SAM, den du kurzfristig erobern kannst, unter Berücksichtigung von Wettbewerb, Ressourcen und Go-to-Market-Strategie. Dies ist die praktischste Kennzahl für Early-Stage-Startups, um den erreichbaren Umsatz in den ersten Jahren abzuschätzen."}},
  { id: 'dc-startup-0014', deck_id: 'deck-startup-fundamentals', front: 'How do you conduct effective customer discovery interviews?', back: 'Use open-ended questions about past behavior, not future intentions. Ask about their biggest frustrations, current solutions, and how much they spend. Never pitch your idea — just listen. The Mom Test by Rob Fitzpatrick recommends asking questions even your mom would not lie about.', sort_order: 14 , front_translations: {"de":"Wie führt man effektive Customer-Discovery-Interviews?"}, back_translations: {"de":"Verwende offene Fragen über vergangenes Verhalten, nicht über zukünftige Absichten. Frage nach den grössten Frustrationen, aktuellen Lösungen und wie viel sie ausgeben. Pitche nie deine Idee - höre einfach zu. Der Mom Test von Rob Fitzpatrick empfiehlt Fragen, bei denen selbst deine Mutter nicht lügen würde."}},
  { id: 'dc-startup-0015', deck_id: 'deck-startup-fundamentals', front: 'What is a competitive moat?', back: 'A sustainable competitive advantage that protects a business from competitors. Common moats include network effects, proprietary technology, brand loyalty, switching costs, economies of scale, and regulatory barriers. Warren Buffett popularized the concept.', sort_order: 15 , front_translations: {"de":"Was ist ein Wettbewerbsvorteil (Competitive Moat)?"}, back_translations: {"de":"Ein nachhaltiger Wettbewerbsvorteil, der ein Unternehmen vor Konkurrenten schützt. Häufige Moats sind Netzwerkeffekte, proprietäre Technologie, Markentreü, Wechselkosten, Skaleneffekte und regulatorische Barrieren. Warren Buffett hat das Konzept populär gemacht."}},
  { id: 'dc-startup-0016', deck_id: 'deck-startup-fundamentals', front: 'What is an unfair advantage in a startup?', back: 'Something that cannot be easily copied or bought by competitors. Examples include unique expertise, a strong personal network, insider knowledge, proprietary data, or a dream team. It gives your startup a head start that others cannot replicate quickly.', sort_order: 16 , front_translations: {"de":"Was ist ein Unfair Advantage bei einem Startup?"}, back_translations: {"de":"Etwas, das von Wettbewerbern nicht einfach kopiert oder gekauft werden kann. Beispiele sind einzigartige Expertise, ein starkes persönliches Netzwerk, Insiderwissen, proprietäre Daten oder ein Dreamteam. Es verschafft deinem Startup einen Vorsprung, den andere nicht schnell replizieren können."}},
  { id: 'dc-startup-0017', deck_id: 'deck-startup-fundamentals', front: 'What is a smoke test in startup validation?', back: 'A technique to measure customer interest before building anything. Common methods include fake door tests (a button for a feature that does not exist yet), pre-order pages, and ad campaigns driving to sign-up forms. It measures intent to buy, not just interest.', sort_order: 17 , front_translations: {"de":"Was ist ein Smoke Test bei der Startup-Validierung?"}, back_translations: {"de":"Eine Technik, um Kundeninteresse zu messen, bevor etwas gebaut wird. Gängige Methoden sind Fake-Door-Tests (ein Button für ein Feature, das noch nicht existiert), Vorbestell-Seiten und Werbekampagnen, die auf Anmeldeformulare führen. Es misst die Kaufabsicht, nicht nur Interesse."}},
  { id: 'dc-startup-0018', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between a hypothesis and an assumption in a startup?', back: 'A hypothesis is a testable statement about what you believe is true (e.g., "Users will pay $20/month for this"). An assumption is an untested belief underlying your business. Good founders identify their riskiest assumptions and convert them into testable hypotheses first.', sort_order: 18 , front_translations: {"de":"Was ist der Unterschied zwischen einer Hypothese und einer Annahme bei einem Startup?"}, back_translations: {"de":"Eine Hypothese ist eine testbare Aussage über das, was man für wahr hält (z.B. \"Nutzer werden 20$/Monat dafür bezahlen\"). Eine Annahme ist eine ungetestete Ueberzeugung, die dem Geschäftsmodell zugrunde liegt. Gute Gründer identifizieren ihre riskantesten Annahmen und wandeln sie zuerst in testbare Hypothesen um."}},
  { id: 'dc-startup-0019', deck_id: 'deck-startup-fundamentals', front: 'What is the "Mom Test" in customer interviews?', back: 'A book by Rob Fitzpatrick that teaches how to ask questions so that even your mom would give honest, useful feedback. The key rules: talk about their life instead of your idea, ask about specifics in the past instead of opinions about the future, and listen more than you talk.', sort_order: 19 , front_translations: {"de":"Was ist der \"Mom Test\" bei Kundeninterviews?"}, back_translations: {"de":"Ein Buch von Rob Fitzpatrick, das lehrt, wie man Fragen stellt, sodass selbst die eigene Mutter ehrliches, nützliches Feedback gibt. Die Kernregeln: Ueber ihr Leben sprechen statt über deine Idee, nach konkreten Erfahrungen in der Vergangenheit fragen statt nach Meinungen über die Zukunft, und mehr zuhören als reden."}},
  { id: 'dc-startup-0020', deck_id: 'deck-startup-fundamentals', front: 'What are the top-down vs bottom-up approaches to market sizing?', back: 'Top-down starts with a large market figure and narrows it based on your addressable segment. Bottom-up starts with unit economics (price x number of potential customers you can reach). Bottom-up is generally more credible for startups because it is grounded in real numbers.', sort_order: 20 , front_translations: {"de":"Was sind die Top-Down- vs. Bottom-Up-Ansätze zur Marktgrössenbestimmung?"}, back_translations: {"de":"Top-Down beginnt mit einer grossen Marktzahl und grenzt sie basierend auf dem adressierbaren Segment ein. Bottom-Up startet mit Unit Economics (Preis x Anzahl erreichbarer potenzieller Kunden). Bottom-Up ist für Startups generell glaubwürdiger, weil es auf realen Zahlen basiert."}},
  { id: 'dc-startup-0021', deck_id: 'deck-startup-fundamentals', front: 'What is a leap-of-faith assumption?', back: 'The riskiest assumption underlying your startup that, if proven wrong, would make the entire business model fail. Examples: "People will share photos with strangers" (Instagram) or "People will sleep in a stranger house" (Airbnb). Test these first.', sort_order: 21 , front_translations: {"de":"Was ist eine Leap-of-Faith-Annahme?"}, back_translations: {"de":"Die riskanteste Annahme hinter deinem Startup, die, wenn sie sich als falsch erweist, das gesamte Geschäftsmodell zum Scheitern bringen würde. Beispiele: \"Menschen werden Fotos mit Fremden teilen\" (Instagram) oder \"Menschen werden im Haus eines Fremden schlafen\" (Airbnb). Teste diese zuerst."}},
  { id: 'dc-startup-0022', deck_id: 'deck-startup-fundamentals', front: 'How do you identify a good startup problem to solve?', back: 'Look for problems that are frequent (happen often), intense (cause real pain), and that people are already paying money or significant effort to solve. The best problems exist at the intersection of personal experience, market demand, and your unique skill set.', sort_order: 22 , front_translations: {"de":"Wie identifiziert man ein gutes Startup-Problem?"}, back_translations: {"de":"Suche nach Problemen, die häufig auftreten, intensiv sind (echten Schmerz verursachen) und für die Menschen bereits Geld oder erheblichen Aufwand investieren. Die besten Probleme liegen an der Schnittstelle von persönlicher Erfahrung, Marktnachfrage und dem eigenen einzigartigen Skillset."}},
  { id: 'dc-startup-0023', deck_id: 'deck-startup-fundamentals', front: 'What is a value hypothesis?', back: 'A testable assumption about whether your product delivers enough value that customers will use it and pay for it. It answers the question: "Does this product solve a real problem well enough that people will choose it over alternatives?" Validate this before a growth hypothesis.', sort_order: 23 , front_translations: {"de":"Was ist eine Value Hypothesis?"}, back_translations: {"de":"Eine testbare Annahme darüber, ob dein Produkt genug Wert liefert, damit Kunden es nutzen und dafür bezahlen. Sie beantwortet die Frage: \"Löst dieses Produkt ein echtes Problem gut genug, dass Menschen es gegenüber Alternativen wählen?\" Validiere diese vor der Growth Hypothesis."}},
  { id: 'dc-startup-0024', deck_id: 'deck-startup-fundamentals', front: 'What is a growth hypothesis?', back: 'A testable assumption about how new customers will discover and adopt your product. It addresses whether your product can spread through viral sharing, word of mouth, paid acquisition, or other channels. Test this after validating your value hypothesis.', sort_order: 24 , front_translations: {"de":"Was ist eine Growth Hypothesis?"}, back_translations: {"de":"Eine testbare Annahme darüber, wie neü Kunden dein Produkt entdecken und annehmen werden. Sie adressiert, ob sich dein Produkt durch virales Teilen, Mundpropaganda, bezahlte Akquise oder andere Kanäle verbreiten kann. Teste diese nach der Validierung der Value Hypothesis."}},
  { id: 'dc-startup-0025', deck_id: 'deck-startup-fundamentals', front: 'What is competitive analysis for startups?', back: 'A systematic assessment of direct and indirect competitors including their strengths, weaknesses, pricing, features, and market positioning. Use it to find gaps in the market and differentiate your offering. Tools include SWOT analysis, feature comparison matrices, and Porter Five Forces.', sort_order: 25 , front_translations: {"de":"Was ist eine Wettbewerbsanalyse für Startups?"}, back_translations: {"de":"Eine systematische Bewertung direkter und indirekter Wettbewerber einschliesslich ihrer Stärken, Schwächen, Preisgestaltung, Features und Marktpositionierung. Nutze sie, um Marktlücken zu finden und dein Angebot zu differenzieren. Tools: SWOT-Analyse, Feature-Vergleichsmatrizen und Porters Five Forces."}},
  { id: 'dc-startup-0026', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between direct and indirect competitors?', back: 'Direct competitors offer a similar product solving the same problem (Uber vs Lyft). Indirect competitors solve the same problem differently (Uber vs public transit). When validating a market, consider both — indirect competitors often reveal that demand exists for a solution.', sort_order: 26 , front_translations: {"de":"Was ist der Unterschied zwischen direkten und indirekten Wettbewerbern?"}, back_translations: {"de":"Direkte Wettbewerber bieten ein ähnliches Produkt, das dasselbe Problem löst (Uber vs. Lyft). Indirekte Wettbewerber lösen dasselbe Problem auf andere Weise (Uber vs. öffentlicher Nahverkehr). Bei der Marktvalidierung sollte man beide berücksichtigen - indirekte Wettbewerber zeigen oft, dass Nachfrage nach einer Lösung existiert."}},
  { id: 'dc-startup-0027', deck_id: 'deck-startup-fundamentals', front: 'What is the "hair on fire" problem concept?', back: 'A problem so urgent and painful that customers will use even an imperfect solution to fix it. These problems lead to the fastest product adoption because the customer is already actively seeking a solution. They represent the best opportunities for MVP-stage startups.', sort_order: 27 , front_translations: {"de":"Was ist das \"Hair on Fire\"-Problemkonzept?"}, back_translations: {"de":"Ein Problem, das so dringend und schmerzhaft ist, dass Kunden selbst eine unvollkommene Lösung nutzen werden. Diese Probleme führen zur schnellsten Produktadoption, weil der Kunde bereits aktiv nach einer Lösung sucht. Sie repräsentieren die besten Chancen für Startups in der MVP-Phase."}},
  { id: 'dc-startup-0028', deck_id: 'deck-startup-fundamentals', front: 'What is a pre-mortem exercise for startup ideas?', back: 'A mental exercise where you imagine your startup has failed and work backward to identify the most likely reasons. This helps surface hidden assumptions and risks before you invest significant time and money. It is more effective than optimistic forward-looking planning alone.', sort_order: 28 , front_translations: {"de":"Was ist eine Pre-Mortem-Uebung für Startup-Ideen?"}, back_translations: {"de":"Eine Gedankenübung, bei der man sich vorstellt, das Startup sei gescheitert, und rückwärts die wahrscheinlichsten Gründe identifiziert. Das hilft, versteckte Annahmen und Risiken aufzudecken, bevor man erheblich Zeit und Geld investiert. Es ist effektiver als rein optimistische vorausschauende Planung."}},
  { id: 'dc-startup-0029', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between a feature and a product for MVP purposes?', back: 'A feature is a single capability (e.g., photo filters). A product is a complete solution that delivers value on its own. A common mistake is building a feature disguised as a product. Your MVP should be a standalone product that solves one core problem, not a collection of features.', sort_order: 29 , front_translations: {"de":"Was ist der Unterschied zwischen einem Feature und einem Produkt für MVP-Zwecke?"}, back_translations: {"de":"Ein Feature ist eine einzelne Fähigkeit (z.B. Fotofilter). Ein Produkt ist eine vollständige Lösung, die eigenständig Wert liefert. Ein häufiger Fehler ist, ein Feature als Produkt zu verkleiden. Dein MVP sollte ein eigenständiges Produkt sein, das ein Kernproblem löst, keine Sammlung von Features."}},
  { id: 'dc-startup-0030', deck_id: 'deck-startup-fundamentals', front: 'What is validated learning?', back: 'The process of demonstrating empirically that a team has discovered valuable truths about a business through experiments. It is the primary unit of progress in the Lean Startup. Each experiment should produce measurable evidence that confirms or denies a specific hypothesis.', sort_order: 30 , front_translations: {"de":"Was ist Validated Learning?"}, back_translations: {"de":"Der Prozess, empirisch zu zeigen, dass ein Team wertvolle Erkenntnisse über ein Geschäft durch Experimente gewonnen hat. Es ist die primäre Fortschrittseinheit im Lean Startup. Jedes Experiment sollte messbare Belege liefern, die eine bestimmte Hypothese bestätigen oder widerlegen."}},
  { id: 'dc-startup-0031', deck_id: 'deck-startup-fundamentals', front: 'What are vanity metrics vs actionable metrics?', back: 'Vanity metrics look good on paper but do not drive decisions (e.g., total sign-ups, page views). Actionable metrics help you make business decisions (e.g., conversion rate, retention rate, revenue per user). Focus on metrics that inform whether to pivot or persevere.', sort_order: 31 , front_translations: {"de":"Was sind Vanity Metrics vs. Actionable Metrics?"}, back_translations: {"de":"Vanity Metrics sehen auf dem Papier gut aus, treiben aber keine Entscheidungen (z.B. Gesamtanmeldungen, Seitenaufrufe). Actionable Metrics helfen bei Geschäftsentscheidungen (z.B. Conversion Rate, Retention Rate, Umsatz pro Nutzer). Konzentriere dich auf Metriken, die informieren, ob du pivotieren oder durchhalten solltest."}},
  { id: 'dc-startup-0032', deck_id: 'deck-startup-fundamentals', front: 'What is the innovator dilemma relevant to startup opportunities?', back: 'Clayton Christensen showed that large companies often ignore emerging markets because they are too small. This creates opportunities for startups to enter underserved segments with simpler, cheaper solutions and eventually move upmarket. Disruption comes from below.', sort_order: 32 , front_translations: {"de":"Was ist das Innovator\'s Dilemma im Kontext von Startup-Chancen?"}, back_translations: {"de":"Clayton Christensen zeigte, dass grosse Unternehmen aufkommende Märkte oft ignorieren, weil sie zu klein sind. Das schafft Chancen für Startups, unterversorgte Segmente mit einfacheren, günstigeren Lösungen zu bedienen und schliesslich in höhere Marktsegmente vorzudringen. Disruption kommt von unten."}},
  { id: 'dc-startup-0033', deck_id: 'deck-startup-fundamentals', front: 'What is a beachhead market?', back: 'A small, well-defined market segment you target first before expanding. Coined by Geoffrey Moore, it means focusing all resources on winning one niche completely, then leveraging that success to enter adjacent markets. Facebook started with Harvard students before expanding.', sort_order: 33 , front_translations: {"de":"Was ist ein Beachhead Market?"}, back_translations: {"de":"Ein kleines, klar definiertes Marktsegment, das man zuerst anvisiert, bevor man expandiert. Von Geoffrey Moore geprägt, bedeutet es, alle Ressourcen auf das Gewinnen einer Nische zu konzentrieren und diesen Erfolg dann für den Eintritt in angrenzende Märkte zu nutzen. Facebook startete mit Harvard-Studenten vor der Expansion."}},
  { id: 'dc-startup-0034', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between a vision, strategy, and product in a startup?', back: 'The vision is the long-term goal that rarely changes. The strategy is the plan to achieve the vision and may pivot based on learning. The product is the concrete implementation of the strategy and changes frequently through iteration. Vision stays fixed while tactics evolve.', sort_order: 34 , front_translations: {"de":"Was ist der Unterschied zwischen Vision, Strategie und Produkt bei einem Startup?"}, back_translations: {"de":"Die Vision ist das langfristige Ziel, das sich selten ändert. Die Strategie ist der Plan zur Erreichung der Vision und kann basierend auf Erkenntnissen pivotieren. Das Produkt ist die konkrete Umsetzung der Strategie und ändert sich häufig durch Iteration. Die Vision bleibt fix, während die Taktik sich entwickelt."}},
  { id: 'dc-startup-0035', deck_id: 'deck-startup-fundamentals', front: 'What is a design sprint and how does it help validation?', back: 'A five-day process developed at Google Ventures to rapidly prototype and test ideas with real users. Day 1: Map the problem. Day 2: Sketch solutions. Day 3: Decide on the best. Day 4: Build a realistic prototype. Day 5: Test with five users. Compresses months of work into one week.', sort_order: 35 , front_translations: {"de":"Was ist ein Design Sprint und wie hilft er bei der Validierung?"}, back_translations: {"de":"Ein fünftägiger Prozess, entwickelt bei Google Ventures, um Ideen schnell zu prototypisieren und mit echten Nutzern zu testen. Tag 1: Problem kartieren. Tag 2: Lösungen skizzieren. Tag 3: Die beste auswählen. Tag 4: Realistischen Prototyp baun. Tag 5: Mit fünf Nutzern testen. Komprimiert Monate Arbeit in eine Woche."}},

  // === Business Models & Strategy (36-70) ===
  { id: 'dc-startup-0036', deck_id: 'deck-startup-fundamentals', front: 'What is a SaaS (Software as a Service) business model?', back: 'A model where software is hosted centrally and customers pay a recurring subscription (monthly or annually) to access it. Key metrics include MRR, churn, and LTV. Examples: Slack, Salesforce, Zoom. SaaS is attractive because of predictable recurring revenue.', sort_order: 36 , front_translations: {"de":"Was ist ein SaaS (Software as a Service) Geschäftsmodell?"}, back_translations: {"de":"Ein Modell, bei dem Software zentral gehostet wird und Kunden ein wiederkehrendes Abonnement (monatlich oder jährlich) für den Zugang bezahlen. Wichtige Kennzahlen sind MRR, Churn und LTV. Beispiele: Slack, Salesforce, Zoom. SaaS ist attraktiv wegen planbarer wiederkehrender Einnahmen."}},
  { id: 'dc-startup-0037', deck_id: 'deck-startup-fundamentals', front: 'What is a marketplace business model?', back: 'A platform that connects buyers and sellers, earning revenue through transaction fees or commissions. The main challenge is solving the chicken-and-egg problem: you need both supply and demand. Examples: Airbnb, Uber, Etsy. Network effects make marketplaces defensible once established.', sort_order: 37 , front_translations: {"de":"Was ist ein Marktplatz-Geschäftsmodell?"}, back_translations: {"de":"Eine Plattform, die Käufer und Verkäufer verbindet und durch Transaktionsgebühren oder Provisionen Umsatz erzielt. Die grösste Herausforderung ist das Henne-Ei-Problem: Man braucht sowohl Angebot als auch Nachfrage. Beispiele: Airbnb, Uber, Etsy. Netzwerkeffekte machen Marktplätze nach der Etablierung verteidigungsfähig."}},
  { id: 'dc-startup-0038', deck_id: 'deck-startup-fundamentals', front: 'What is a freemium business model?', back: 'A model offering a free basic tier to attract users and a paid premium tier with advanced features. The free tier drives acquisition while the paid tier generates revenue. Typically 2-5% of free users convert to paid. Examples: Spotify, Dropbox, Slack.', sort_order: 38 , front_translations: {"de":"Was ist ein Freemium-Geschäftsmodell?"}, back_translations: {"de":"Ein Modell mit einer kostenlosen Basisstufe zur Nutzergewinnung und einer kostenpflichtigen Premium-Stufe mit erweiterten Features. Die kostenlose Stufe treibt die Akquise, die bezahlte generiert Umsatz. Typischerweise konvertieren 2-5% der kostenlosen Nutzer zu zahlenden. Beispiele: Spotify, Dropbox, Slack."}},
  { id: 'dc-startup-0039', deck_id: 'deck-startup-fundamentals', front: 'What is CAC (Customer Acquisition Cost)?', back: 'The total cost of acquiring a new customer, including marketing, sales, and onboarding expenses. Calculated as total acquisition spend divided by the number of new customers acquired. A healthy business needs LTV to be at least 3x CAC.', sort_order: 39 , front_translations: {"de":"Was ist CAC (Customer Acquisition Cost)?"}, back_translations: {"de":"Die Gesamtkosten für die Gewinnung eines neün Kunden, einschliesslich Marketing-, Vertriebs- und Onboarding-Ausgaben. Berechnet als Gesamtausgaben für Akquise geteilt durch die Anzahl gewonnener Neukunden. Ein gesundes Unternehmen braucht einen LTV von mindestens 3x CAC."}},
  { id: 'dc-startup-0040', deck_id: 'deck-startup-fundamentals', front: 'What is LTV (Lifetime Value)?', back: 'The total revenue a business expects to earn from a single customer over the entire relationship. Calculated as average revenue per user multiplied by average customer lifespan. LTV should be significantly higher than CAC for a sustainable business — ideally 3x or more.', sort_order: 40 , front_translations: {"de":"Was ist LTV (Lifetime Value)?"}, back_translations: {"de":"Der Gesamtumsatz, den ein Unternehmen von einem einzelnen Kunden über die gesamte Geschäftsbeziehung erwartet. Berechnet als durchschnittlicher Umsatz pro Nutzer multipliziert mit der durchschnittlichen Kundenlebensdauer. LTV sollte deutlich höher als CAC sein - idealerweise 3x oder mehr."}},
  { id: 'dc-startup-0041', deck_id: 'deck-startup-fundamentals', front: 'What is the LTV:CAC ratio and why does it matter?', back: 'The ratio of customer lifetime value to customer acquisition cost. A ratio of 3:1 or higher is considered healthy for most startups. Below 1:1 means you lose money on every customer. Above 5:1 may mean you are underinvesting in growth.', sort_order: 41 , front_translations: {"de":"Was ist das LTV:CAC-Verhältnis und warum ist es wichtig?"}, back_translations: {"de":"Das Verhältnis von Customer Lifetime Value zu Customer Acquisition Cost. Ein Verhältnis von 3:1 oder höher gilt für die meisten Startups als gesund. Unter 1:1 bedeutet, dass man mit jedem Kunden Geld verliert. Ueber 5:1 kann bedeuten, dass man zu wenig in Wachstum investiert."}},
  { id: 'dc-startup-0042', deck_id: 'deck-startup-fundamentals', front: 'What is churn rate?', back: 'The percentage of customers who stop using your product or cancel their subscription during a given period. Monthly churn of 5% means you lose about 46% of customers per year. Reducing churn is often more impactful than acquiring new customers.', sort_order: 42 , front_translations: {"de":"Was ist die Churn Rate?"}, back_translations: {"de":"Der Prozentsatz der Kunden, die ein Produkt nicht mehr nutzen oder ihr Abonnement in einem bestimmten Zeitraum kündigen. 5% monatlicher Churn bedeutet, dass man etwa 46% der Kunden pro Jahr verliert. Churn zu reduzieren ist oft wirkungsvoller als neü Kunden zu gewinnen."}},
  { id: 'dc-startup-0043', deck_id: 'deck-startup-fundamentals', front: 'What is the CAC payback period?', back: 'The number of months it takes to recover the cost of acquiring a customer through their revenue contributions. A payback period under 12 months is generally considered healthy for SaaS businesses. Shorter payback means faster cash flow and less risk.', sort_order: 43 , front_translations: {"de":"Was ist die CAC-Amortisationszeit?"}, back_translations: {"de":"Die Anzahl der Monate, die es dauert, die Kosten für die Kundengewinnung durch deren Umsatzbeiträge zurückzugewinnen. Eine Amortisationszeit unter 12 Monaten gilt für SaaS-Unternehmen generell als gesund. Kürzere Amortisation bedeutet schnelleren Cashflow und weniger Risiko."}},
  { id: 'dc-startup-0044', deck_id: 'deck-startup-fundamentals', front: 'What is value-based pricing?', back: 'Setting prices based on the perceived value to the customer rather than the cost to produce. If your product saves a customer $1,000/month, charging $200/month is justified regardless of your costs. This approach captures more value and often results in higher margins.', sort_order: 44 , front_translations: {"de":"Was ist wertbasierte Preisgestaltung?"}, back_translations: {"de":"Preise werden basierend auf dem wahrgenommenen Wert für den Kunden festgelegt, nicht auf den Produktionskosten. Wenn dein Produkt einem Kunden 1.000$/Monat spart, sind 200$/Monat gerechtfertigt, unabhängig von deinen Kosten. Dieser Ansatz erfasst mehr Wert und führt oft zu höheren Margen."}},
  { id: 'dc-startup-0045', deck_id: 'deck-startup-fundamentals', front: 'What is penetration pricing strategy?', back: 'Setting a low initial price to quickly gain market share and attract a large customer base. Once established, prices can be raised. Useful in competitive markets where network effects matter. Risk: customers may anchor on the low price and resist increases.', sort_order: 45 , front_translations: {"de":"Was ist eine Penetrationspreisstrategie?"}, back_translations: {"de":"Ein niedriger Anfangspreis, um schnell Marktanteile zu gewinnen und eine grosse Kundenbasis aufzubaun. Nach der Etablierung können die Preise erhöht werden. Nutzlich in wettbewerbsintensiven Märkten, in denen Netzwerkeffekte wichtig sind. Risiko: Kunden könnten sich am niedrigen Preis orientieren und Erhöhungen ablehnen."}},
  { id: 'dc-startup-0046', deck_id: 'deck-startup-fundamentals', front: 'What is price skimming strategy?', back: 'Launching at a high price targeting early adopters willing to pay a premium, then gradually lowering the price to reach broader segments. Common in technology and innovation-driven products. Apple uses this approach with new iPhone launches.', sort_order: 46 , front_translations: {"de":"Was ist eine Skimming-Preisstrategie?"}, back_translations: {"de":"Markteinführung zu einem hohen Preis für Early Adopter, die bereit sind einen Aufpreis zu zahlen, dann schrittweise Preissenkung für breitere Segmente. Gängig bei technologie- und innovationsgetriebenen Produkten. Apple nutzt diesen Ansatz bei neün iPhone-Einführungen."}},
  { id: 'dc-startup-0047', deck_id: 'deck-startup-fundamentals', front: 'What is the Business Model Canvas?', back: 'A strategic management tool by Alexander Osterwalder that maps a business model on one page using nine blocks: Key Partners, Key Activities, Key Resources, Value Propositions, Customer Relationships, Channels, Customer Segments, Cost Structure, and Revenue Streams.', sort_order: 47 , front_translations: {"de":"Was ist das Business Model Canvas?"}, back_translations: {"de":"Ein strategisches Management-Tool von Alexander Osterwalder, das ein Geschäftsmodell auf einer Seite in neun Blöcken abbildet: Schlüsselpartner, Schlüsselaktivitäten, Schlüsselressourcen, Wertversprechen, Kundenbeziehungen, Kanäle, Kundensegmente, Kostenstruktur und Einnahmeqüllen."}},
  { id: 'dc-startup-0048', deck_id: 'deck-startup-fundamentals', front: 'What is the Lean Canvas?', back: 'An adaptation of the Business Model Canvas by Ash Maurya, designed specifically for startups. It replaces Key Partners, Key Activities, Key Resources, and Customer Relationships with Problem, Solution, Key Metrics, and Unfair Advantage. Focuses on risk and uncertainty.', sort_order: 48 , front_translations: {"de":"Was ist das Lean Canvas?"}, back_translations: {"de":"Eine Adaption des Business Model Canvas von Ash Maurya, speziell für Startups entwickelt. Es ersetzt Schlüsselpartner, Schlüsselaktivitäten, Schlüsselressourcen und Kundenbeziehungen durch Problem, Lösung, Schlüsselmetriken und Unfair Advantage. Fokussiert auf Risiko und Unsicherheit."}},
  { id: 'dc-startup-0049', deck_id: 'deck-startup-fundamentals', front: 'What is recurring revenue and why is it valuable?', back: 'Revenue that repeats predictably through subscriptions or ongoing contracts. It is highly valued because it provides predictable cash flow, higher customer lifetime value, and easier financial forecasting. Recurring revenue businesses typically receive higher valuations from investors.', sort_order: 49 , front_translations: {"de":"Was sind wiederkehrende Einnahmen und warum sind sie wertvoll?"}, back_translations: {"de":"Einnahmen, die sich vorhersehbar durch Abonnements oder laufende Verträge wiederholen. Sie werden hoch geschätzt, weil sie planbaren Cashflow, höheren Customer Lifetime Value und einfachere Finanzprognosen ermöglichen. Unternehmen mit wiederkehrenden Einnahmen erhalten typischerweise höhere Bewertungen von Investoren."}},
  { id: 'dc-startup-0050', deck_id: 'deck-startup-fundamentals', front: 'What is MRR (Monthly Recurring Revenue)?', back: 'The predictable revenue a subscription business earns each month. Calculated by multiplying the number of paying customers by the average revenue per user. MRR growth rate is one of the most important metrics for SaaS startups when fundraising.', sort_order: 50 , front_translations: {"de":"Was ist MRR (Monthly Recurring Revenue)?"}, back_translations: {"de":"Die planbare Einnahme, die ein Abonnement-Unternehmen jeden Monat erzielt. Berechnet durch Multiplikation der Anzahl zahlender Kunden mit dem durchschnittlichen Umsatz pro Nutzer. Die MRR-Wachstumsrate ist eine der wichtigsten Kennzahlen für SaaS-Startups beim Fundraising."}},
  { id: 'dc-startup-0051', deck_id: 'deck-startup-fundamentals', front: 'What is ARR (Annual Recurring Revenue)?', back: 'The annualized value of recurring subscription revenue, calculated as MRR multiplied by 12. It is the standard metric for measuring the size and growth of SaaS businesses. Investors often use ARR multiples to value SaaS companies.', sort_order: 51 , front_translations: {"de":"Was ist ARR (Annual Recurring Revenue)?"}, back_translations: {"de":"Der annualisierte Wert wiederkehrender Abo-Einnahmen, berechnet als MRR multipliziert mit 12. ARR ist die Standardkennzahl zur Messung der Grösse und des Wachstums von SaaS-Unternehmen. Investoren verwenden häufig ARR-Multiplikatoren zur Bewertung von SaaS-Firmen."}},
  { id: 'dc-startup-0052', deck_id: 'deck-startup-fundamentals', front: 'What are network effects?', back: 'When a product becomes more valuable as more people use it. Direct network effects: each user makes it better for all others (telephone, social media). Indirect network effects: more users attract complementary products (more iPhone users attract more app developers).', sort_order: 52 , front_translations: {"de":"Was sind Netzwerkeffekte?"}, back_translations: {"de":"Wenn ein Produkt wertvoller wird, je mehr Menschen es nutzen. Direkte Netzwerkeffekte: Jeder Nutzer verbessert das Produkt für alle anderen (Telefon, Social Media). Indirekte Netzwerkeffekte: Mehr Nutzer ziehen ergänzende Produkte an (mehr iPhone-Nutzer ziehen mehr App-Entwickler an)."}},
  { id: 'dc-startup-0053', deck_id: 'deck-startup-fundamentals', front: 'What is a platform business model?', back: 'A model that creates value by facilitating exchanges between two or more interdependent groups. Unlike traditional linear businesses, platforms do not own inventory — they connect producers and consumers. Examples: Apple App Store, YouTube, Amazon Marketplace.', sort_order: 53 , front_translations: {"de":"Was ist ein Plattform-Geschäftsmodell?"}, back_translations: {"de":"Ein Modell, das Wert schafft, indem es den Austausch zwischen zwei oder mehr voneinander abhängigen Gruppen ermöglicht. Im Gegensatz zu traditionellen linearen Unternehmen besitzen Plattformen kein Inventar — sie verbinden Produzenten und Konsumenten. Beispiele: Apple App Store, YouTube, Amazon Marketplace."}},
  { id: 'dc-startup-0054', deck_id: 'deck-startup-fundamentals', front: 'What is the chicken-and-egg problem in marketplaces?', back: 'The challenge of needing both supply (sellers) and demand (buyers) for a marketplace to function, but neither side wants to join without the other. Solutions include subsidizing one side, starting with a niche, or creating standalone value for one side first.', sort_order: 54 , front_translations: {"de":"Was ist das Henne-Ei-Problem bei Marktplätzen?"}, back_translations: {"de":"Die Herausforderung, dass ein Marktplatz sowohl Angebot (Verkäufer) als auch Nachfrage (Käufer) braucht, aber keine Seite beitreten will, ohne dass die andere bereits da ist. Lösungen umfassen die Subventionierung einer Seite, den Start in einer Nische oder die Schaffung eines eigenständigen Nutzens für eine Seite zuerst."}},
  { id: 'dc-startup-0055', deck_id: 'deck-startup-fundamentals', front: 'What is unit economics?', back: 'The revenue and costs associated with a single unit of your business (one customer, one transaction, one product sold). Healthy unit economics mean you earn more from each customer than it costs to acquire and serve them. Negative unit economics are unsustainable long term.', sort_order: 55 , front_translations: {"de":"Was ist Unit Economics?"}, back_translations: {"de":"Die Einnahmen und Kosten, die mit einer einzelnen Einheit deines Geschäfts verbunden sind (ein Kunde, eine Transaktion, ein verkauftes Produkt). Gesunde Unit Economics bedeuten, dass du mit jedem Kunden mehr verdienst, als es kostet, ihn zu gewinnen und zu bedienen. Negative Unit Economics sind langfristig nicht tragbar."}},
  { id: 'dc-startup-0056', deck_id: 'deck-startup-fundamentals', front: 'What is an advertising-based business model?', back: 'A model where the product is offered free to users, and revenue comes from advertisers paying to reach that user base. Requires massive scale to be profitable. Key metrics include DAU/MAU, engagement, and CPM. Examples: Google Search, Facebook, YouTube.', sort_order: 56 , front_translations: {"de":"Was ist ein werbebasiertes Geschäftsmodell?"}, back_translations: {"de":"Ein Modell, bei dem das Produkt den Nutzern kostenlos angeboten wird und die Einnahmen von Werbetreibenden stammen, die für den Zugang zur Nutzerbasis zahlen. Erfordert massive Skalierung, um profitabel zu sein. Wichtige Kennzahlen sind DAU/MAU, Engagement und CPM. Beispiele: Google Search, Facebook, YouTube."}},
  { id: 'dc-startup-0057', deck_id: 'deck-startup-fundamentals', front: 'What is a transaction fee business model?', back: 'A model where the platform takes a percentage of each transaction it facilitates. Common in payment processors, marketplaces, and fintech. Examples: Stripe (2.9% + 30 cents), Airbnb (3% host fee + up to 14% guest fee), PayPal.', sort_order: 57 , front_translations: {"de":"Was ist ein Transaktionsgebühren-Geschäftsmodell?"}, back_translations: {"de":"Ein Modell, bei dem die Plattform einen Prozentsatz jeder vermittelten Transaktion einbehält. Verbreitet bei Zahlungsdienstleistern, Marktplätzen und Fintech. Beispiele: Stripe (2,9% + 30 Cent), Airbnb (3% Gastgebergebühr + bis zu 14% Gastgebühr), PayPal."}},
  { id: 'dc-startup-0058', deck_id: 'deck-startup-fundamentals', front: 'What is cost-plus pricing?', back: 'A pricing strategy where you calculate your total cost to deliver the product and add a markup percentage. Simple to implement but often leaves money on the table because it ignores the perceived value to the customer. More common in manufacturing than in software.', sort_order: 58 , front_translations: {"de":"Was ist Cost-Plus-Pricing?"}, back_translations: {"de":"Eine Preisstrategie, bei der du deine Gesamtkosten für die Produktlieferung berechnest und einen prozentualen Aufschlag hinzufügst. Einfach umzusetzen, lässt aber oft Geld auf dem Tisch, weil der wahrgenommene Wert für den Kunden ignoriert wird. Häufiger in der Fertigung als bei Software."}},
  { id: 'dc-startup-0059', deck_id: 'deck-startup-fundamentals', front: 'What is a subscription business model?', back: 'A model where customers pay a recurring fee (weekly, monthly, or annually) for continued access to a product or service. Benefits include predictable revenue, higher LTV, and lower churn compared to one-time purchases. Examples: Netflix, Dollar Shave Club, Adobe Creative Cloud.', sort_order: 59 , front_translations: {"de":"Was ist ein Abo-Geschäftsmodell?"}, back_translations: {"de":"Ein Modell, bei dem Kunden eine wiederkehrende Gebühr (wöchentlich, monatlich oder jährlich) für den fortlaufenden Zugang zu einem Produkt oder Service zahlen. Vorteile sind planbare Einnahmen, höherer LTV und geringere Abwanderung im Vergleich zu Einmalkäufen. Beispiele: Netflix, Dollar Shave Club, Adobe Creative Cloud."}},
  { id: 'dc-startup-0060', deck_id: 'deck-startup-fundamentals', front: 'What are switching costs and why do they matter?', back: 'The costs (financial, time, effort, data migration) a customer incurs when moving to a competitor. High switching costs create customer lock-in and reduce churn. Enterprise software often has high switching costs, making it a strong defensive moat.', sort_order: 60 , front_translations: {"de":"Was sind Wechselkosten und warum sind sie wichtig?"}, back_translations: {"de":"Die Kosten (finanziell, zeitlich, Aufwand, Datenmigration), die einem Kunden beim Wechsel zu einem Wettbewerber entstehen. Hohe Wechselkosten erzeugen Kundenbindung und reduzieren Abwanderung. Enterprise-Software hat oft hohe Wechselkosten, was sie zu einem starken Wettbewerbsvorteil macht."}},
  { id: 'dc-startup-0061', deck_id: 'deck-startup-fundamentals', front: 'What is gross margin and why is it important for startups?', back: 'Revenue minus cost of goods sold, divided by revenue. High gross margins (70%+) indicate a scalable business because most revenue flows to the bottom line. Software businesses typically have 80-90% gross margins, while physical product businesses might have 30-50%.', sort_order: 61 , front_translations: {"de":"Was ist die Bruttomarge und warum ist sie für Startups wichtig?"}, back_translations: {"de":"Umsatz minus Herstellungskosten, geteilt durch den Umsatz. Hohe Bruttomargen (70%+) deuten auf ein skalierbares Geschäft hin, da der Grossteil des Umsatzes am Ende übrig bleibt. Software-Unternehmen haben typischerweise 80-90% Bruttomarge, während physische Produkte bei 30-50% liegen können."}},
  { id: 'dc-startup-0062', deck_id: 'deck-startup-fundamentals', front: 'What is a razor-and-blade business model?', back: 'A model where the primary product is sold at low cost or a loss, while recurring consumables or accessories generate the main profit. Named after Gillette selling cheap razors and expensive blades. Modern examples: printers and ink cartridges, game consoles and games.', sort_order: 62 , front_translations: {"de":"Was ist ein Razor-and-Blade-Geschäftsmodell?"}, back_translations: {"de":"Ein Modell, bei dem das Hauptprodukt zu niedrigen Kosten oder mit Verlust verkauft wird, während wiederkehrende Verbrauchsmaterialien oder Zubehör den Hauptgewinn erzeugen. Benannt nach Gillettes Strategie, günstige Rasierer und teure Klingen zu verkaufen. Moderne Beispiele: Drucker und Tintenpatronen, Spielekonsolen und Spiele."}},
  { id: 'dc-startup-0063', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between B2B and B2C startups?', back: 'B2B (business-to-business) sells to companies, typically with longer sales cycles, higher contract values, and relationship-based selling. B2C (business-to-consumer) sells to individuals, with shorter sales cycles, lower price points, and volume-based growth.', sort_order: 63 , front_translations: {"de":"Was ist der Unterschied zwischen B2B- und B2C-Startups?"}, back_translations: {"de":"B2B (Business-to-Business) verkauft an Unternehmen, typischerweise mit längeren Verkaufszyklen, höheren Vertragswerten und beziehungsbasiertem Vertrieb. B2C (Business-to-Consumer) verkauft an Endverbraucher, mit kürzeren Verkaufszyklen, niedrigeren Preispunkten und volumenbasiertem Wachstum."}},
  { id: 'dc-startup-0064', deck_id: 'deck-startup-fundamentals', front: 'What is negative churn?', back: 'When expansion revenue from existing customers (through upsells, cross-sells, or usage increases) exceeds the revenue lost from churned customers. Negative churn means your revenue grows even without adding new customers. It is a powerful indicator of product-market fit.', sort_order: 64 , front_translations: {"de":"Was ist negative Abwanderung (Negative Churn)?"}, back_translations: {"de":"Wenn die Expansionserlöse von Bestandskunden (durch Upsells, Cross-Sells oder Nutzungssteigerungen) die durch abgewanderte Kunden verlorenen Einnahmen übersteigen. Negative Churn bedeutet, dass dein Umsatz wächst, auch ohne neü Kunden zu gewinnen. Es ist ein starker Indikator für Product-Market Fit."}},
  { id: 'dc-startup-0065', deck_id: 'deck-startup-fundamentals', front: 'What is a value proposition?', back: 'A clear statement of why a customer should choose your product over alternatives. It defines the specific benefit you deliver, who you deliver it to, and how you do it differently. A strong value proposition addresses a specific pain point and communicates measurable results.', sort_order: 65 , front_translations: {"de":"Was ist ein Wertversprechen (Value Proposition)?"}, back_translations: {"de":"Eine klare Aussage darüber, warum ein Kunde dein Produkt gegenüber Alternativen wählen sollte. Es definiert den konkreten Nutzen, den du lieferst, an wen du ihn lieferst und wie du dich unterscheidest. Ein starkes Wertversprechen adressiert einen bestimmten Schmerzpunkt und kommuniziert messbare Ergebnisse."}},
  { id: 'dc-startup-0066', deck_id: 'deck-startup-fundamentals', front: 'What is the land-and-expand sales strategy?', back: 'Starting with a small initial deal or free tier within an organization, then expanding usage across teams and departments over time. Common in SaaS B2B. Slack, Dropbox, and Atlassian all grew this way — individual teams adopted the product and it spread organically.', sort_order: 66 , front_translations: {"de":"Was ist die Land-and-Expand-Vertriebsstrategie?"}, back_translations: {"de":"Beginn mit einem kleinen Erstauftrag oder einem kostenlosen Tier innerhalb einer Organisation, dann schrittweise Ausweitung der Nutzung über Teams und Abteilungen hinweg. Verbreitet im SaaS-B2B-Bereich. Slack, Dropbox und Atlassian wuchsen so — einzelne Teams übernahmen das Produkt und es verbreitete sich organisch."}},
  { id: 'dc-startup-0067', deck_id: 'deck-startup-fundamentals', front: 'What are economies of scale?', back: 'Cost advantages that companies gain as production volume increases, because fixed costs are spread across more units. Startups that achieve economies of scale can offer lower prices or higher margins. This creates a competitive moat against smaller competitors.', sort_order: 67 , front_translations: {"de":"Was sind Skaleneffekte (Economies of Scale)?"}, back_translations: {"de":"Kostenvorteile, die Unternehmen erzielen, wenn das Produktionsvolumen steigt, da Fixkosten auf mehr Einheiten verteilt werden. Startups, die Skaleneffekte erreichen, können niedrigere Preise oder höhere Margen anbieten. Dies schafft einen Wettbewerbsvorteil gegenüber kleineren Konkurrenten."}},
  { id: 'dc-startup-0068', deck_id: 'deck-startup-fundamentals', front: 'What is the flywheel effect in business strategy?', back: 'A self-reinforcing cycle where each element of the business feeds the next, creating compounding momentum. Amazon example: lower prices attract more customers, more customers attract more sellers, more sellers increase selection, which allows even lower prices.', sort_order: 68 , front_translations: {"de":"Was ist der Flywheel-Effekt in der Geschäftsstrategie?"}, back_translations: {"de":"Ein sich selbst verstärkender Kreislauf, bei dem jedes Element des Geschäfts das nächste antreibt und zunehmenden Schwung erzeugt. Amazon-Beispiel: Niedrigere Preise ziehen mehr Kunden an, mehr Kunden ziehen mehr Verkäufer an, mehr Verkäufer erhöhen die Auswahl, was noch niedrigere Preise ermöglicht."}},
  { id: 'dc-startup-0069', deck_id: 'deck-startup-fundamentals', front: 'What is revenue diversification and why does it matter?', back: 'Having multiple sources of revenue rather than depending on a single one. It reduces risk if one revenue stream declines. However, early-stage startups should usually focus on one revenue stream until it is working well before diversifying.', sort_order: 69 , front_translations: {"de":"Was ist Umsatzdiversifikation und warum ist sie wichtig?"}, back_translations: {"de":"Mehrere Einnahmeqüllen zu haben, anstatt von einer einzigen abhängig zu sein. Dies reduziert das Risiko, falls eine Einnahmeqülle zurückgeht. Allerdings sollten sich Startups in der Frühphase meist auf eine Einnahmeqülle konzentrieren, bis diese gut funktioniert, bevor sie diversifizieren."}},
  { id: 'dc-startup-0070', deck_id: 'deck-startup-fundamentals', front: 'What is a loss leader strategy?', back: 'Selling a product at a loss to attract customers who then purchase profitable products or services. Amazon sold Kindle devices at near cost to drive ebook and Prime subscription sales. Startups use this when the lifetime value of the customer relationship exceeds the initial loss.', sort_order: 70 , front_translations: {"de":"Was ist eine Loss-Leader-Strategie?"}, back_translations: {"de":"Ein Produkt mit Verlust zu verkaufen, um Kunden anzuziehen, die dann profitable Produkte oder Dienstleistungen kaufen. Amazon verkaufte Kindle-Geräte nahezu zum Selbstkostenpreis, um E-Book- und Prime-Abo-Verkäufe zu fördern. Startups nutzen dies, wenn der Kundenlebenszeitwert den anfänglichen Verlust übersteigt."}},

  // === Product Development (71-100) ===
  { id: 'dc-startup-0071', deck_id: 'deck-startup-fundamentals', front: 'What is product-market fit?', back: 'The point where your product satisfies strong market demand. Marc Andreessen describes it as "being in a good market with a product that can satisfy that market." Signs include organic growth, high retention, and customers who would be very disappointed if the product disappeared.', sort_order: 71 , front_translations: {"de":"Was ist Product-Market Fit?"}, back_translations: {"de":"Der Punkt, an dem dein Produkt eine starke Marktnachfrage befriedigt. Marc Andreessen beschreibt es als \"in einem guten Markt zu sein mit einem Produkt, das diesen Markt bedienen kann.\" Anzeichen sind organisches Wachstum, hohe Retention und Kunden, die sehr enttäuscht wären, wenn das Produkt verschwinden würde."}},
  { id: 'dc-startup-0072', deck_id: 'deck-startup-fundamentals', front: 'What is the Sean Ellis test for product-market fit?', back: 'Ask users: "How would you feel if you could no longer use this product?" If 40% or more answer "very disappointed," you likely have product-market fit. This survey-based test was developed by Sean Ellis and is used widely by growth-stage startups.', sort_order: 72 , front_translations: {"de":"Was ist der Sean-Ellis-Test für Product-Market Fit?"}, back_translations: {"de":"Frage Nutzer: \"Wie würdest du dich fühlen, wenn du dieses Produkt nicht mehr nutzen könntest?\" Wenn 40% oder mehr mit \"sehr enttäuscht\" antworten, hast du wahrscheinlich Product-Market Fit. Dieser umfragebasierte Test wurde von Sean Ellis entwickelt und wird breit von wachstumsstarken Startups genutzt."}},
  { id: 'dc-startup-0073', deck_id: 'deck-startup-fundamentals', front: 'What is Agile development?', back: 'An iterative approach to software development that emphasizes flexibility, collaboration, and delivering working software in short cycles (sprints). Instead of planning everything upfront (Waterfall), teams adapt to changes and continuously deliver value based on user feedback.', sort_order: 73 , front_translations: {"de":"Was ist agile Softwareentwicklung?"}, back_translations: {"de":"Ein iterativer Ansatz der Softwareentwicklung, der Flexibilität, Zusammenarbeit und die Lieferung funktionierender Software in kurzen Zyklen (Sprints) betont. Statt alles im Voraus zu planen (Wasserfall), passen sich Teams an Veränderungen an und liefern kontinuierlich Mehrwert basierend auf Nutzerfeedback."}},
  { id: 'dc-startup-0074', deck_id: 'deck-startup-fundamentals', front: 'What is a sprint in Agile development?', back: 'A fixed time period (usually 1-2 weeks) during which a team completes a set amount of work. Each sprint includes planning, daily standups, execution, a review, and a retrospective. Sprints keep teams focused and enable frequent delivery of working features.', sort_order: 74 , front_translations: {"de":"Was ist ein Sprint in der agilen Entwicklung?"}, back_translations: {"de":"Ein fester Zeitraum (meist 1-2 Wochen), in dem ein Team eine definierte Menge an Arbeit erledigt. Jeder Sprint umfasst Planung, tägliche Standups, Umsetzung, ein Review und eine Retrospektive. Sprints halten Teams fokussiert und ermöglichen häufige Auslieferung funktionierender Features."}},
  { id: 'dc-startup-0075', deck_id: 'deck-startup-fundamentals', front: 'What is a user story in product development?', back: 'A short, informal description of a feature from the end user perspective, written as: "As a [type of user], I want [goal] so that [benefit]." User stories focus on value delivered to the user rather than technical specifications. They keep development customer-centric.', sort_order: 75 , front_translations: {"de":"Was ist eine User Story in der Produktentwicklung?"}, back_translations: {"de":"Eine kurze, informelle Beschreibung eines Features aus der Perspektive des Endnutzers, geschrieben als: \"Als [Nutzertyp] möchte ich [Ziel], damit [Nutzen].\" User Stories konzentrieren sich auf den gelieferten Wert für den Nutzer statt auf technische Spezifikationen. Sie halten die Entwicklung kundenorientiert."}},
  { id: 'dc-startup-0076', deck_id: 'deck-startup-fundamentals', front: 'What is the RICE framework for feature prioritization?', back: 'A scoring model that evaluates features by Reach (how many users are affected), Impact (how much it affects each user), Confidence (how certain you are about estimates), and Effort (how much work it requires). Score = (Reach x Impact x Confidence) / Effort.', sort_order: 76 , front_translations: {"de":"Was ist das RICE-Framework zur Feature-Priorisierung?"}, back_translations: {"de":"Ein Bewertungsmodell, das Features nach Reach (wie viele Nutzer betroffen sind), Impact (wie stark jeder Nutzer betroffen ist), Confidence (wie sicher die Schätzungen sind) und Effort (wie viel Aufwand nötig ist) bewertet. Score = (Reach x Impact x Confidence) / Effort."}},
  { id: 'dc-startup-0077', deck_id: 'deck-startup-fundamentals', front: 'What is the MoSCoW method for prioritization?', back: 'A technique that categorizes features into Must have (critical), Should have (important but not vital), Could have (nice to have), and Will not have (out of scope for now). Helps teams focus on essentials and make trade-off decisions when resources are limited.', sort_order: 77 , front_translations: {"de":"Was ist die MoSCoW-Methode zur Priorisierung?"}, back_translations: {"de":"Eine Technik, die Features in Must have (kritisch), Should have (wichtig, aber nicht entscheidend), Could have (wäre schön) und Will not have (derzeit ausserhalb des Umfangs) einteilt. Hilft Teams, sich auf das Wesentliche zu konzentrieren und Abwägungen bei begrenzten Ressourcen zu treffen."}},
  { id: 'dc-startup-0078', deck_id: 'deck-startup-fundamentals', front: 'What is the Kano model for feature analysis?', back: 'A model classifying features into three categories: Basic (expected, cause dissatisfaction if missing), Performance (satisfaction proportional to quality), and Delighters (unexpected features that create excitement). Helps teams invest in features with the highest impact on satisfaction.', sort_order: 78 , front_translations: {"de":"Was ist das Kano-Modell zur Feature-Analyse?"}, back_translations: {"de":"Ein Modell, das Features in drei Kategorien einteilt: Basis (erwartet, verursacht Unzufriedenheit bei Fehlen), Leistung (Zufriedenheit proportional zur Qualität) und Begeisterung (unerwartete Features, die Begeisterung auslösen). Hilft Teams, in Features mit der grössten Auswirkung auf die Zufriedenheit zu investieren."}},
  { id: 'dc-startup-0079', deck_id: 'deck-startup-fundamentals', front: 'What is user onboarding and why is it critical?', back: 'The process of guiding new users to experience the core value of your product as quickly as possible. Poor onboarding is a top reason for churn. Best practices include reducing time-to-value, using progressive disclosure, and celebrating small wins during the first session.', sort_order: 79 , front_translations: {"de":"Was ist User Onboarding und warum ist es entscheidend?"}, back_translations: {"de":"Der Prozess, neü Nutzer so schnell wie möglich zum Kernwert deines Produkts zu führen. Schlechtes Onboarding ist ein Hauptgrund für Abwanderung. Best Practices umfassen die Verkürzung der Time-to-Value, Progressive Disclosure und das Feiern kleiner Erfolge während der ersten Sitzung."}},
  { id: 'dc-startup-0080', deck_id: 'deck-startup-fundamentals', front: 'What is the "aha moment" in product design?', back: 'The point when a new user first realizes the value of your product. For Facebook, it was adding 7 friends in 10 days. For Slack, it was sending 2,000 team messages. Identifying and optimizing the path to this moment dramatically improves activation and retention rates.', sort_order: 80 , front_translations: {"de":"Was ist der \"Aha-Moment\" im Produktdesign?"}, back_translations: {"de":"Der Punkt, an dem ein neür Nutzer erstmals den Wert deines Produkts erkennt. Bei Facebook waren es 7 Freunde in 10 Tagen. Bei Slack waren es 2.000 Team-Nachrichten. Die Identifikation und Optimierung des Wegs zu diesem Moment verbessert Aktivierungs- und Retentionsraten drastisch."}},
  { id: 'dc-startup-0081', deck_id: 'deck-startup-fundamentals', front: 'What is technical debt?', back: 'The implied cost of future rework caused by choosing quick, easy solutions now instead of better approaches that take longer. Some technical debt is strategic (shipping faster to validate). Too much creates maintenance burden, slow development, and unreliable software.', sort_order: 81 , front_translations: {"de":"Was ist technische Schuld (Technical Debt)?"}, back_translations: {"de":"Die impliziten Kosten zukünftiger Nacharbeit, die durch die Wahl schneller, einfacher Lösungen anstelle besserer, aber zeitaufwändigerer Ansätze entstehen. Etwas technische Schuld ist strategisch sinnvoll (schneller ausliefern zur Validierung). Zu viel davon führt zu Wartungsaufwand, langsamer Entwicklung und unzuverlässiger Software."}},
  { id: 'dc-startup-0082', deck_id: 'deck-startup-fundamentals', front: 'When should a startup build vs buy technology?', back: 'Build when the technology is your core competitive advantage or does not exist in the market. Buy (or use existing tools/APIs) when it is a commodity or not core to your value proposition. Early-stage startups should almost always buy non-core components to focus limited resources.', sort_order: 82 , front_translations: {"de":"Wann sollte ein Startup Technologie selbst baun oder kaufen?"}, back_translations: {"de":"Selbst baun, wenn die Technologie dein zentraler Wettbewerbsvorteil ist oder nicht am Markt existiert. Kaufen (oder vorhandene Tools/APIs nutzen), wenn es ein Standardprodukt ist oder nicht zum Kern deines Wertversprechens gehört. Frühphasen-Startups sollten fast immer Nicht-Kern-Komponenten kaufen, um begrenzte Ressourcen zu fokussieren."}},
  { id: 'dc-startup-0083', deck_id: 'deck-startup-fundamentals', front: 'What is a product roadmap?', back: 'A strategic document that outlines the vision, direction, and planned evolution of a product over time. For startups, keep it flexible — a roadmap is a plan, not a promise. Focus on outcomes and problems to solve rather than a fixed list of features.', sort_order: 83 , front_translations: {"de":"Was ist eine Produkt-Roadmap?"}, back_translations: {"de":"Ein strategisches Dokument, das die Vision, Richtung und geplante Weiterentwicklung eines Produkts über die Zeit beschreibt. Für Startups gilt: Halte sie flexibel — eine Roadmap ist ein Plan, kein Versprechen. Konzentriere dich auf Ergebnisse und zu lösende Probleme statt auf eine feste Feature-Liste."}},
  { id: 'dc-startup-0084', deck_id: 'deck-startup-fundamentals', front: 'What is retention rate and why is it the most important metric?', back: 'The percentage of users who continue using your product over time. High retention means your product delivers ongoing value. Without strong retention, growth is like filling a leaky bucket — you acquire users but they leave. Retention is the foundation of sustainable growth.', sort_order: 84 , front_translations: {"de":"Was ist die Retentionsrate und warum ist sie die wichtigste Kennzahl?"}, back_translations: {"de":"Der Prozentsatz der Nutzer, die dein Produkt über die Zeit weiter nutzen. Hohe Retention bedeutet, dass dein Produkt dauerhaften Wert liefert. Ohne starke Retention ist Wachstum wie das Füllen eines undichten Eimers — du gewinnst Nutzer, aber sie gehen wieder. Retention ist das Fundament nachhaltigen Wachstums."}},
  { id: 'dc-startup-0085', deck_id: 'deck-startup-fundamentals', front: 'What is a daily active user to monthly active user (DAU/MAU) ratio?', back: 'A measure of how frequently users engage with your product. A ratio above 50% indicates high stickiness (users come back most days). Social media apps like Facebook aim for 60%+. A low ratio suggests your product is useful but not habit-forming.', sort_order: 85 , front_translations: {"de":"Was ist das Verhältnis von täglich aktiven zu monatlich aktiven Nutzern (DAU/MAU)?"}, back_translations: {"de":"Ein Mass dafür, wie häufig Nutzer mit deinem Produkt interagieren. Ein Verhältnis über 50% zeigt hohe Stickiness an (Nutzer kommen fast täglich zurück). Social-Media-Apps wie Facebook streben 60%+ an. Ein niedriges Verhältnis deutet darauf hin, dass dein Produkt nützlich, aber nicht gewohnheitsbildend ist."}},
  { id: 'dc-startup-0086', deck_id: 'deck-startup-fundamentals', front: 'What is the concept of iteration in product development?', back: 'Continuously improving your product through repeated cycles of building, measuring, and learning. Each iteration refines the product based on real user feedback and data. Successful startups iterate rapidly — shipping small improvements weekly rather than big releases quarterly.', sort_order: 86 , front_translations: {"de":"Was ist das Konzept der Iteration in der Produktentwicklung?"}, back_translations: {"de":"Die kontinuierliche Verbesserung deines Produkts durch wiederholte Zyklen aus Baun, Messen und Lernen. Jede Iteration verfeinert das Produkt basierend auf echtem Nutzerfeedback und Daten. Erfolgreiche Startups iterieren schnell — sie liefern wöchentlich kleine Verbesserungen statt grosser quartalsweiser Releases."}},
  { id: 'dc-startup-0087', deck_id: 'deck-startup-fundamentals', front: 'What is scope creep and how do startups avoid it?', back: 'The gradual expansion of a project beyond its original goals, adding features and complexity without clear justification. Avoid it by defining clear success criteria upfront, saying no to non-essential features, and maintaining a disciplined product backlog with strict prioritization.', sort_order: 87 , front_translations: {"de":"Was ist Scope Creep und wie vermeiden Startups ihn?"}, back_translations: {"de":"Die schleichende Ausweitung eines Projekts über seine ursprünglichen Ziele hinaus, mit zusätzlichen Features und Komplexität ohne klare Begründung. Vermeidung durch klare Erfolgskriterien vorab, Nein-Sagen zu nicht-essentiellen Features und ein diszipliniertes Product Backlog mit strikter Priorisierung."}},
  { id: 'dc-startup-0088', deck_id: 'deck-startup-fundamentals', front: 'What is a North Star metric?', back: 'The single metric that best captures the core value your product delivers to customers. For Airbnb it is nights booked, for Facebook it is daily active users, for Slack it is messages sent. Aligning the team around one North Star metric improves focus and decision-making.', sort_order: 88 , front_translations: {"de":"Was ist eine North-Star-Metrik?"}, back_translations: {"de":"Die einzelne Kennzahl, die den Kernwert, den dein Produkt den Kunden liefert, am besten erfasst. Für Airbnb sind es gebuchte Nächte, für Facebook die täglich aktiven Nutzer, für Slack die gesendeten Nachrichten. Die Ausrichtung des Teams auf eine North-Star-Metrik verbessert Fokus und Entscheidungsfindung."}},
  { id: 'dc-startup-0089', deck_id: 'deck-startup-fundamentals', front: 'What is progressive disclosure in UX design?', back: 'A design technique that shows only the essential information and options upfront, revealing complexity gradually as users need it. It reduces cognitive overload for new users while keeping advanced features accessible for power users. Critical for products with complex functionality.', sort_order: 89 , front_translations: {"de":"Was ist Progressive Disclosure im UX-Design?"}, back_translations: {"de":"Eine Designtechnik, die zunächst nur die wesentlichen Informationen und Optionen zeigt und Komplexität schrittweise enthüllt, wenn Nutzer sie benötigen. Sie reduziert die kognitive Ueberlastung für neü Nutzer, während erweiterte Funktionen für Power-User zugänglich bleiben. Entscheidend für Produkte mit komplexer Funktionalität."}},
  { id: 'dc-startup-0090', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between UX and UI?', back: 'UX (User Experience) is the overall feel and flow of using a product — including ease of use, efficiency, and satisfaction. UI (User Interface) is the visual design — buttons, colors, typography, and layout. Good UX with bad UI is usable but ugly; good UI with bad UX is pretty but frustrating.', sort_order: 90 , front_translations: {"de":"Was ist der Unterschied zwischen UX und UI?"}, back_translations: {"de":"UX (User Experience) ist das Gesamterlebnis bei der Nutzung eines Produkts — einschliesslich Benutzerfreundlichkeit, Effizienz und Zufriedenheit. UI (User Interface) ist das visülle Design — Buttons, Farben, Typografie und Layout. Gute UX mit schlechter UI ist nutzbar, aber hässlich; gute UI mit schlechter UX ist hübsch, aber frustrierend."}},
  { id: 'dc-startup-0091', deck_id: 'deck-startup-fundamentals', front: 'What is a feature flag (feature toggle)?', back: 'A technique that lets you enable or disable features without deploying new code. Useful for A/B testing, gradual rollouts, and quickly turning off problematic features. Tools like LaunchDarkly or Flagsmith make this easy. Essential for rapid experimentation at scale.', sort_order: 91 , front_translations: {"de":"Was ist ein Feature Flag (Feature Toggle)?"}, back_translations: {"de":"Eine Technik, mit der du Features aktivieren oder deaktivieren kannst, ohne neün Code zu deployen. Nutzlich für A/B-Tests, schrittweise Rollouts und das schnelle Abschalten problematischer Features. Tools wie LaunchDarkly oder Flagsmith machen dies einfach. Unverzichtbar für schnelles Experimentieren im grossen Massstab."}},
  { id: 'dc-startup-0092', deck_id: 'deck-startup-fundamentals', front: 'What is continuous deployment?', back: 'A practice where code changes are automatically deployed to production after passing automated tests. It enables teams to ship multiple times per day with confidence. Combined with feature flags, it lets startups iterate and experiment faster than competitors.', sort_order: 92 , front_translations: {"de":"Was ist Continuous Deployment?"}, back_translations: {"de":"Eine Praxis, bei der Code-Aenderungen nach dem Bestehen automatisierter Tests automatisch in die Produktion deployed werden. Sie ermöglicht es Teams, mehrmals täglich mit Vertraün auszuliefern. In Kombination mit Feature Flags können Startups schneller iterieren und experimentieren als die Konkurrenz."}},
  { id: 'dc-startup-0093', deck_id: 'deck-startup-fundamentals', front: 'What is a product-led growth (PLG) strategy?', back: 'A go-to-market strategy where the product itself is the primary driver of acquisition, activation, and expansion. Users can try and get value from the product without talking to sales. Examples: Slack, Zoom, Calendly. Requires an excellent self-serve experience and low friction onboarding.', sort_order: 93 , front_translations: {"de":"Was ist eine Product-Led-Growth-Strategie (PLG)?"}, back_translations: {"de":"Eine Go-to-Market-Strategie, bei der das Produkt selbst der primäre Treiber für Akquisition, Aktivierung und Expansion ist. Nutzer können das Produkt ausprobieren und Wert daraus ziehen, ohne mit dem Vertrieb zu sprechen. Beispiele: Slack, Zoom, Calendly. Erfordert eine hervorragende Self-Service-Erfahrung und reibungsloses Onboarding."}},
  { id: 'dc-startup-0094', deck_id: 'deck-startup-fundamentals', front: 'What is a cohort analysis?', back: 'Grouping users by their start date (or another shared trait) and tracking their behavior over time. It reveals whether newer cohorts retain better than older ones, indicating product improvements. Essential for understanding true retention trends rather than aggregated averages.', sort_order: 94 , front_translations: {"de":"Was ist eine Kohortenanalyse?"}, back_translations: {"de":"Die Gruppierung von Nutzern nach ihrem Startdatum (oder einem anderen gemeinsamen Merkmal) und die Verfolgung ihres Verhaltens über die Zeit. Sie zeigt, ob neüre Kohorten besser binden als ältere, was auf Produktverbesserungen hindeutet. Unverzichtbar, um echte Retentionstrends statt aggregierter Durchschnitte zu verstehen."}},
  { id: 'dc-startup-0095', deck_id: 'deck-startup-fundamentals', front: 'What is the Jobs-to-be-Done (JTBD) framework?', back: 'A theory that customers "hire" products to accomplish specific jobs in their lives. Focus on the job (e.g., "help me pass time during my commute") rather than demographics. Milkshake example by Clayton Christensen: people "hired" milkshakes for a boring commute, not because they liked dairy.', sort_order: 95 , front_translations: {"de":"Was ist das Jobs-to-be-Done-Framework (JTBD)?"}, back_translations: {"de":"Eine Theorie, dass Kunden Produkte \"anstellen\", um bestimmte Aufgaben in ihrem Leben zu erledigen. Fokussiere dich auf die Aufgabe (z.B. \"hilf mir, die Zeit beim Pendeln zu vertreiben\") statt auf Demografie. Milchshake-Beispiel von Clayton Christensen: Menschen \"stellten\" Milchshakes für eine langweilige Pendelfahrt \"an\", nicht weil sie Milchprodukte mochten."}},
  { id: 'dc-startup-0096', deck_id: 'deck-startup-fundamentals', front: 'What is a product analytics tool and which ones do startups use?', back: 'Software that tracks user behavior within your product. Popular tools include Mixpanel (event tracking), Amplitude (product analytics), PostHog (open source), and Google Analytics. They help you understand which features are used, where users drop off, and what drives conversion.', sort_order: 96 , front_translations: {"de":"Was ist ein Product-Analytics-Tool und welche nutzen Startups?"}, back_translations: {"de":"Software, die das Nutzerverhalten innerhalb deines Produkts erfasst. Beliebte Tools sind Mixpanel (Event-Tracking), Amplitude (Product Analytics), PostHog (Open Source) und Google Analytics. Sie helfen zu verstehen, welche Features genutzt werden, wo Nutzer abspringen und was Conversion antreibt."}},
  { id: 'dc-startup-0097', deck_id: 'deck-startup-fundamentals', front: 'What is a beta launch strategy?', back: 'Releasing your product to a limited group of early users before a full public launch. Benefits include gathering feedback, finding bugs, and building a community of advocates. Offer beta users special access or pricing in exchange for their time and honest feedback.', sort_order: 97 , front_translations: {"de":"Was ist eine Beta-Launch-Strategie?"}, back_translations: {"de":"Die Veröffentlichung deines Produkts an eine begrenzte Gruppe frühzeitiger Nutzer vor dem öffentlichen Launch. Vorteile sind das Sammeln von Feedback, das Finden von Bugs und der Aufbau einer Community von Fürsprechern. Biete Beta-Nutzern speziellen Zugang oder Preise im Gegenzug für ihre Zeit und ehrliches Feedback."}},
  { id: 'dc-startup-0098', deck_id: 'deck-startup-fundamentals', front: 'What is time-to-value (TTV) and why does it matter?', back: 'The time it takes for a new user to experience the core benefit of your product. Shorter TTV leads to higher activation and retention rates. Optimize by simplifying onboarding, using templates or sample data, and guiding users directly to the most valuable feature first.', sort_order: 98 , front_translations: {"de":"Was ist Time-to-Value (TTV) und warum ist sie wichtig?"}, back_translations: {"de":"Die Zeit, die ein neür Nutzer braucht, um den Kernnutzen deines Produkts zu erleben. Kürzere TTV führt zu höheren Aktivierungs- und Retentionsraten. Optimiere durch vereinfachtes Onboarding, Vorlagen oder Beispieldaten und die direkte Führung der Nutzer zum wertvollsten Feature zuerst."}},
  { id: 'dc-startup-0099', deck_id: 'deck-startup-fundamentals', front: 'What is a feedback loop in product development?', back: 'A mechanism for collecting user input and turning it into product improvements. Effective feedback loops include in-app surveys, user interviews, support tickets, analytics data, and feature request boards. The faster the loop, the faster you improve the product.', sort_order: 99 , front_translations: {"de":"Was ist eine Feedbackschleife in der Produktentwicklung?"}, back_translations: {"de":"Ein Mechanismus zum Sammeln von Nutzereingaben und deren Umsetzung in Produktverbesserungen. Effektive Feedbackschleifen umfassen In-App-Umfragen, Nutzerinterviews, Support-Tickets, Analysedaten und Feature-Reqüst-Boards. Je schneller die Schleife, desto schneller verbesserst du das Produkt."}},
  { id: 'dc-startup-0100', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between a monolith and microservices architecture?', back: 'A monolith is a single, unified codebase where all components are tightly coupled. Microservices split the application into small, independent services. Startups should almost always start with a monolith for speed and simplicity, then migrate to microservices only when scale demands it.', sort_order: 100 , front_translations: {"de":"Was ist der Unterschied zwischen Monolith- und Microservices-Architektur?"}, back_translations: {"de":"Ein Monolith ist eine einzelne, einheitliche Codebasis, in der alle Komponenten eng gekoppelt sind. Microservices teilen die Anwendung in kleine, unabhängige Dienste auf. Startups sollten fast immer mit einem Monolithen starten für Geschwindigkeit und Einfachheit, und erst zu Microservices migrieren, wenn die Skalierung es erfordert."}},

  // === Fundraising & Finance (101-145) ===
  { id: 'dc-startup-0101', deck_id: 'deck-startup-fundamentals', front: 'What is bootstrapping a startup?', back: 'Funding your business with personal savings, revenue, or minimal external capital instead of raising from investors. Benefits include full ownership, no dilution, and forced discipline. Drawbacks include slower growth and personal financial risk. Mailchimp bootstrapped to $12B.', sort_order: 101 , front_translations: {"de":"Was bedeutet Bootstrapping bei einem Startup?"}, back_translations: {"de":"Das Unternehmen mit eigenen Ersparnissen, Umsätzen oder minimalem externen Kapital finanzieren, anstatt Investoren einzubeziehen. Vorteile: volle Eigentümerschaft, keine Verwässerung und erzwungene Disziplin. Nachteile: langsameres Wachstum und persönliches finanzielles Risiko. Mailchimp wurde bis auf $12 Mrd. gebootstrappt."}},
  { id: 'dc-startup-0102', deck_id: 'deck-startup-fundamentals', front: 'What is angel investing?', back: 'High-net-worth individuals who invest personal money in early-stage startups in exchange for equity. Angel investments typically range from $25K to $500K. Angels often provide mentorship and connections in addition to capital. Many are former entrepreneurs themselves.', sort_order: 102 , front_translations: {"de":"Was ist Angel Investing?"}, back_translations: {"de":"Vermögende Privatpersonen, die ihr eigenes Geld in Startups in der Frühphase investieren und dafür Unternehmensanteile erhalten. Angel-Investments liegen typischerweise zwischen $25K und $500K. Angels bieten neben Kapital oft auch Mentoring und Kontakte. Viele sind selbst ehemalige Gründer."}},
  { id: 'dc-startup-0103', deck_id: 'deck-startup-fundamentals', front: 'What is venture capital (VC)?', back: 'Professional investment firms that invest pooled money from limited partners into high-growth startups in exchange for equity. VCs invest larger amounts than angels, typically $1M-$100M+. They expect outsized returns (10x+) and usually seek board seats and significant influence.', sort_order: 103 , front_translations: {"de":"Was ist Venture Capital (VC)?"}, back_translations: {"de":"Professionelle Investmentfirmen, die gebündeltes Geld von Limited Partners in wachstumsstarke Startups investieren und dafür Anteile erhalten. VCs investieren größere Beträge als Angels, typischerweise $1M–$100M+. Sie erwarten überproportionale Renditen (10x+) und streben in der Regel Aufsichtsratssitze und erheblichen Einfluss an."}},
  { id: 'dc-startup-0104', deck_id: 'deck-startup-fundamentals', front: 'What is a pre-seed funding round?', back: 'The earliest formal fundraising stage, typically $50K-$500K, used to validate an idea or build an initial prototype. Investors are usually friends, family, angel investors, or pre-seed focused funds. The startup may only have a team and an idea at this stage.', sort_order: 104 , front_translations: {"de":"Was ist eine Pre-Seed-Finanzierungsrunde?"}, back_translations: {"de":"Die früheste formelle Finanzierungsphase, typischerweise $50K–$500K, um eine Idee zu validieren oder einen ersten Prototyp zu baun. Investoren sind meist Freunde, Familie, Angel-Investoren oder auf Pre-Seed spezialisierte Fonds. Das Startup hat zu diesem Zeitpunkt möglicherweise nur ein Team und eine Idee."}},
  { id: 'dc-startup-0105', deck_id: 'deck-startup-fundamentals', front: 'What is a seed funding round?', back: 'An early funding round, typically $500K-$3M, to build the product, hire initial team members, and find product-market fit. Investors include angel investors, seed-stage VC funds, and accelerators. The startup usually has a working MVP and early traction.', sort_order: 105 , front_translations: {"de":"Was ist eine Seed-Finanzierungsrunde?"}, back_translations: {"de":"Eine frühe Finanzierungsrunde, typischerweise $500K–$3M, um das Produkt zu entwickeln, erste Teammitglieder einzustellen und Product-Market Fit zu finden. Investoren sind Angel-Investoren, Seed-Stage-VC-Fonds und Accelerators. Das Startup hat meist ein funktionierendes MVP und erste Traktion."}},
  { id: 'dc-startup-0106', deck_id: 'deck-startup-fundamentals', front: 'What is a Series A funding round?', back: 'Typically the first major institutional VC round, ranging from $3M-$15M. At this stage, the startup should demonstrate product-market fit, meaningful revenue or growth metrics, and a clear path to scaling. Investors expect a proven business model and a plan for rapid growth.', sort_order: 106 , front_translations: {"de":"Was ist eine Series-A-Finanzierungsrunde?"}, back_translations: {"de":"Typischerweise die erste große institutionelle VC-Runde mit $3M–$15M. In dieser Phase sollte das Startup Product-Market Fit, aussagekräftige Umsatz- oder Wachstumskennzahlen und einen klaren Skalierungsplan vorweisen. Investoren erwarten ein bewährtes Geschäftsmodell und einen Plan für schnelles Wachstum."}},
  { id: 'dc-startup-0107', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between Series A, B, and C rounds?', back: 'Series A focuses on scaling a proven product ($3-15M). Series B funds rapid expansion, hiring, and market penetration ($15-50M). Series C and beyond finance further scale, international expansion, or pre-IPO growth ($50M+). Each round involves higher valuations and larger checks.', sort_order: 107 , front_translations: {"de":"Was ist der Unterschied zwischen Series A, B und C Runden?"}, back_translations: {"de":"Series A konzentriert sich auf die Skalierung eines bewährten Produkts ($3–15M). Series B finanziert schnelle Expansion, Einstellungen und Marktdurchdringung ($15–50M). Series C und darüber hinaus finanzieren weitere Skalierung, internationale Expansion oder Pre-IPO-Wachstum ($50M+). Jede Runde beinhaltet höhere Bewertungen und größere Investitionsbeträge."}},
  { id: 'dc-startup-0108', deck_id: 'deck-startup-fundamentals', front: 'What is a term sheet?', back: 'A non-binding document outlining the key terms of an investment deal, including valuation, investment amount, equity percentage, board seats, liquidation preferences, and anti-dilution provisions. It serves as the basis for negotiation before drafting final legal agreements.', sort_order: 108 , front_translations: {"de":"Was ist ein Term Sheet?"}, back_translations: {"de":"Ein unverbindliches Dokument, das die wesentlichen Bedingungen eines Investment-Deals festlegt, einschließlich Bewertung, Investitionssumme, Anteilsprozentsatz, Aufsichtsratssitze, Liquidation Preferences und Verwässerungsschutzklauseln. Es dient als Verhandlungsgrundlage vor Erstellung der endgültigen rechtlichen Vereinbarungen."}},
  { id: 'dc-startup-0109', deck_id: 'deck-startup-fundamentals', front: 'What is pre-money valuation?', back: 'The value of a company immediately before receiving a new investment. If a startup has a pre-money valuation of $4M and raises $1M, the post-money valuation is $5M. The investor owns 20% ($1M / $5M). Pre-money valuation is a key negotiation point in fundraising.', sort_order: 109 , front_translations: {"de":"Was ist eine Pre-Money-Bewertung?"}, back_translations: {"de":"Der Wert eines Unternehmens unmittelbar vor Erhalt einer neün Investition. Hat ein Startup eine Pre-Money-Bewertung von $4M und erhält $1M, beträgt die Post-Money-Bewertung $5M. Der Investor besitzt 20% ($1M / $5M). Die Pre-Money-Bewertung ist ein zentraler Verhandlungspunkt bei der Finanzierung."}},
  { id: 'dc-startup-0110', deck_id: 'deck-startup-fundamentals', front: 'What is post-money valuation?', back: 'The value of a company immediately after receiving a new investment. Calculated as pre-money valuation plus the investment amount. Post-money valuation determines what percentage of the company each investor owns after the round closes.', sort_order: 110 , front_translations: {"de":"Was ist eine Post-Money-Bewertung?"}, back_translations: {"de":"Der Wert eines Unternehmens unmittelbar nach Erhalt einer neün Investition. Berechnet als Pre-Money-Bewertung plus Investitionsbetrag. Die Post-Money-Bewertung bestimmt, welchen Prozentsatz des Unternehmens jeder Investor nach Abschluss der Runde besitzt."}},
  { id: 'dc-startup-0111', deck_id: 'deck-startup-fundamentals', front: 'What is a cap table (capitalization table)?', back: 'A spreadsheet showing the ownership structure of a company, including shares held by founders, investors, employees, and option holders. It tracks all equity issuances, conversions, and dilution over time. Keeping a clean cap table is essential for fundraising.', sort_order: 111 , front_translations: {"de":"Was ist ein Cap Table (Kapitalisierungstabelle)?"}, back_translations: {"de":"Eine Tabelle, die die Eigentümerstruktur eines Unternehmens zeigt, einschließlich der Anteile von Gründern, Investoren, Mitarbeitern und Optionsinhabern. Sie erfasst alle Ausgaben von Anteilen, Umwandlungen und Verwässerungen über die Zeit. Ein sauberer Cap Table ist essenziell für die Finanzierung."}},
  { id: 'dc-startup-0112', deck_id: 'deck-startup-fundamentals', front: 'What is equity dilution?', back: 'The reduction in existing shareholders ownership percentage when new shares are issued (e.g., during a funding round). If a founder owns 100% and gives 20% to investors, the founder is diluted to 80%. Dilution is expected but founders should monitor cumulative impact.', sort_order: 112 , front_translations: {"de":"Was ist Equity Dilution (Anteilsverwässerung)?"}, back_translations: {"de":"Die Verringerung des Eigentumsanteils bestehender Gesellschafter, wenn neü Anteile ausgegeben werden (z. B. bei einer Finanzierungsrunde). Besitzt ein Gründer 100% und gibt 20% an Investoren ab, wird der Gründer auf 80% verwässert. Verwässerung ist normal, aber Gründer sollten die kumulative Auswirkung im Blick behalten."}},
  { id: 'dc-startup-0113', deck_id: 'deck-startup-fundamentals', front: 'What is a SAFE (Simple Agreement for Future Equity)?', back: 'An investment instrument created by Y Combinator where an investor provides capital in exchange for the right to receive equity at a future priced round. SAFEs are simpler and cheaper than convertible notes — no interest rate, no maturity date. They include a valuation cap and/or discount.', sort_order: 113 , front_translations: {"de":"Was ist ein SAFE (Simple Agreement for Future Equity)?"}, back_translations: {"de":"Ein von Y Combinator entwickeltes Investmentinstrument, bei dem ein Investor Kapital im Austausch für das Recht auf Anteile bei einer zukünftigen bewerteten Runde bereitstellt. SAFEs sind einfacher und günstiger als Convertible Notes – kein Zinssatz, kein Fälligkeitsdatum. Sie beinhalten einen Valuation Cap und/oder einen Discount."}},
  { id: 'dc-startup-0114', deck_id: 'deck-startup-fundamentals', front: 'What is a convertible note?', back: 'A short-term debt instrument that converts into equity at a future funding round. Unlike a SAFE, it has an interest rate and maturity date. Conversion terms include a valuation cap and/or discount rate. If the note reaches maturity without a conversion event, repayment may be required.', sort_order: 114 , front_translations: {"de":"Was ist eine Convertible Note?"}, back_translations: {"de":"Ein kurzfristiges Schuldinstrument, das bei einer zukünftigen Finanzierungsrunde in Eigenkapital umgewandelt wird. Anders als ein SAFE hat es einen Zinssatz und ein Fälligkeitsdatum. Umwandlungsbedingungen umfassen einen Valuation Cap und/oder Discount Rate. Erreicht die Note die Fälligkeit ohne Umwandlungsereignis, kann eine Rückzahlung erforderlich sein."}},
  { id: 'dc-startup-0115', deck_id: 'deck-startup-fundamentals', front: 'What is a valuation cap on a SAFE or convertible note?', back: 'The maximum valuation at which the investment converts to equity. If the cap is $5M and the Series A prices the company at $10M, the SAFE investor converts at $5M, getting twice as many shares. It protects early investors by ensuring they get a minimum ownership percentage.', sort_order: 115 , front_translations: {"de":"Was ist ein Valuation Cap bei einem SAFE oder einer Convertible Note?"}, back_translations: {"de":"Die maximale Bewertung, zu der die Investition in Anteile umgewandelt wird. Liegt der Cap bei $5M und die Series A bewertet das Unternehmen mit $10M, wandelt der SAFE-Investor zu $5M um und erhält doppelt so viele Anteile. Er schützt frühe Investoren, indem er einen Mindest-Eigentumsanteil sichert."}},
  { id: 'dc-startup-0116', deck_id: 'deck-startup-fundamentals', front: 'What is a discount rate on a convertible note?', back: 'A percentage discount (typically 15-25%) that early investors receive on the share price at the next funding round. If the Series A price is $1/share with a 20% discount, note holders convert at $0.80/share. It rewards early investors for taking on more risk.', sort_order: 116 , front_translations: {"de":"Was ist eine Discount Rate bei einer Convertible Note?"}, back_translations: {"de":"Ein prozentualer Rabatt (typischerweise 15–25%), den frühe Investoren auf den Aktienpreis der nächsten Finanzierungsrunde erhalten. Liegt der Series-A-Preis bei $1/Aktie mit 20% Discount, wandeln Noteholders zu $0,80/Aktie um. Er belohnt frühe Investoren für das höhere Risiko."}},
  { id: 'dc-startup-0117', deck_id: 'deck-startup-fundamentals', front: 'What should a startup pitch deck include?', back: 'Key slides: Problem, Solution, Market Size (TAM/SAM/SOM), Product Demo, Business Model, Traction/Metrics, Competition, Team, Financial Projections, and The Ask (how much you are raising and how you will use the funds). Keep it to 10-15 slides maximum.', sort_order: 117 , front_translations: {"de":"Was sollte ein Startup Pitch Deck enthalten?"}, back_translations: {"de":"Wichtige Folien: Problem, Lösung, Marktgröße (TAM/SAM/SOM), Produktdemo, Geschäftsmodell, Traktion/Kennzahlen, Wettbewerb, Team, Finanzprognosen und der Ask (wie viel Kapital benötigt wird und wofür es eingesetzt wird). Maximal 10–15 Folien."}},
  { id: 'dc-startup-0118', deck_id: 'deck-startup-fundamentals', front: 'What is due diligence in startup fundraising?', back: 'The investigation process investors conduct before committing capital. It covers financials, legal documents, cap table, customer references, technology review, team background checks, and market analysis. Founders should maintain a clean data room to speed up the process.', sort_order: 118 , front_translations: {"de":"Was ist Dü Diligence bei der Startup-Finanzierung?"}, back_translations: {"de":"Der Prüfungsprozess, den Investoren vor einer Kapitalzusage durchführen. Er umfasst Finanzen, Rechtsdokumente, Cap Table, Kundenreferenzen, Technologie-Review, Hintergrundprüfungen des Teams und Marktanalyse. Gründer sollten einen aufgeräumten Data Room pflegen, um den Prozess zu beschleunigen."}},
  { id: 'dc-startup-0119', deck_id: 'deck-startup-fundamentals', front: 'What is burn rate?', back: 'The rate at which a startup spends cash, usually measured monthly. Gross burn is total monthly spending. Net burn is total spending minus revenue. If you spend $100K/month and earn $30K, your net burn is $70K/month. Monitoring burn rate is critical for survival.', sort_order: 119 , front_translations: {"de":"Was ist die Burn Rate?"}, back_translations: {"de":"Die Rate, mit der ein Startup Geld ausgibt, üblicherweise monatlich gemessen. Gross Burn sind die gesamten monatlichen Ausgaben. Net Burn sind die Gesamtausgaben minus Einnahmen. Gibst du $100K/Monat aus und verdienst $30K, beträgt dein Net Burn $70K/Monat. Die Überwachung der Burn Rate ist überlebenswichtig."}},
  { id: 'dc-startup-0120', deck_id: 'deck-startup-fundamentals', front: 'What is runway?', back: 'The amount of time a startup can operate before running out of cash, calculated as cash on hand divided by monthly net burn rate. If you have $700K and burn $70K/month, you have 10 months of runway. Most startups should maintain at least 12-18 months of runway.', sort_order: 120 , front_translations: {"de":"Was ist die Runway?"}, back_translations: {"de":"Die Zeitspanne, die ein Startup operieren kann, bevor das Geld ausgeht – berechnet als vorhandenes Kapital geteilt durch die monatliche Net Burn Rate. Hast du $700K und verbrennst $70K/Monat, hast du 10 Monate Runway. Die meisten Startups sollten mindestens 12–18 Monate Runway haben."}},
  { id: 'dc-startup-0121', deck_id: 'deck-startup-fundamentals', front: 'What is a break-even point?', back: 'The point at which total revenue equals total costs, meaning the business is no longer losing money. Reaching break-even is a significant milestone because it means the company can sustain itself without external funding. Calculate as Fixed Costs / (Price - Variable Cost per Unit).', sort_order: 121 , front_translations: {"de":"Was ist der Break-Even-Point?"}, back_translations: {"de":"Der Punkt, an dem der Gesamtumsatz die Gesamtkosten deckt und das Unternehmen kein Geld mehr verliert. Das Erreichen des Break-Even ist ein wichtiger Meilenstein, weil das Unternehmen sich ohne externe Finanzierung tragen kann. Berechnung: Fixkosten / (Preis – variable Kosten pro Einheit)."}},
  { id: 'dc-startup-0122', deck_id: 'deck-startup-fundamentals', front: 'What is a liquidation preference?', back: 'A term in venture deals that determines the order and amount investors get paid when a company is sold or liquidated. A 1x liquidation preference means the investor gets their money back before common shareholders receive anything. Participating preferences let investors double-dip.', sort_order: 122 , front_translations: {"de":"Was ist eine Liquidation Preference?"}, back_translations: {"de":"Eine Klausel in Venture-Deals, die die Reihenfolge und Höhe der Auszahlung an Investoren bei einem Verkauf oder einer Liquidation bestimmt. Eine 1x Liquidation Preference bedeutet, dass der Investor sein Geld zurückerhält, bevor Stammaktionäre etwas bekommen. Participating Preferences erlauben Investoren eine doppelte Beteiligung."}},
  { id: 'dc-startup-0123', deck_id: 'deck-startup-fundamentals', front: 'What is anti-dilution protection?', back: 'A clause protecting investors from dilution if future rounds occur at a lower valuation (down round). The two common types are full ratchet (most investor-friendly, adjusts price to new lower price) and weighted average (more balanced, adjusts proportionally). Most deals use broad-based weighted average.', sort_order: 123 , front_translations: {"de":"Was ist ein Verwässerungsschutz (Anti-Dilution Protection)?"}, back_translations: {"de":"Eine Klausel, die Investoren vor Verwässerung schützt, wenn zukünftige Runden zu einer niedrigeren Bewertung stattfinden (Down Round). Die zwei gängigen Typen sind Full Ratchet (am investorenfreundlichsten, passt den Preis auf den neün niedrigeren Preis an) und Weighted Average (ausgewogener, passt proportional an). Die meisten Deals nutzen Broad-Based Weighted Average."}},
  { id: 'dc-startup-0124', deck_id: 'deck-startup-fundamentals', front: 'What is a down round?', back: 'A funding round where the company raises money at a lower valuation than the previous round. It signals the company has not met expectations and results in significant dilution for existing shareholders. Down rounds can trigger anti-dilution provisions and damage morale.', sort_order: 124 , front_translations: {"de":"Was ist eine Down Round?"}, back_translations: {"de":"Eine Finanzierungsrunde, bei der das Unternehmen Geld zu einer niedrigeren Bewertung als in der vorherigen Runde aufnimmt. Es signalisiert, dass das Unternehmen die Erwartungen nicht erfüllt hat, und führt zu erheblicher Verwässerung der bestehenden Anteilseigner. Down Rounds können Verwässerungsschutzklauseln auslösen und die Moral schädigen."}},
  { id: 'dc-startup-0125', deck_id: 'deck-startup-fundamentals', front: 'What is an equity split between co-founders?', back: 'The division of ownership among co-founders at the start. Common approaches: equal split for equal contribution, or adjusted based on idea origination, time commitment, and skills. Advisors recommend deciding early and using vesting schedules to protect against early departures.', sort_order: 125 , front_translations: {"de":"Was ist ein Equity Split zwischen Mitgründern?"}, back_translations: {"de":"Die Aufteilung der Eigentumsanteile unter den Mitgründern zu Beginn. Gängige Ansätze: gleiche Aufteilung bei gleichem Beitrag oder angepasst nach Ideenursprung, Zeitaufwand und Fähigkeiten. Berater empfehlen, dies früh zu entscheiden und Vesting-Schedules zu nutzen, um sich vor frühzeitigem Ausscheiden zu schützen."}},
  { id: 'dc-startup-0126', deck_id: 'deck-startup-fundamentals', front: 'What is Y Combinator (YC)?', back: 'The most prominent startup accelerator, founded in 2005. YC invests $500K for ~7% equity, provides three months of mentorship, and culminates in Demo Day where startups pitch to investors. Alumni include Airbnb, Stripe, Dropbox, and DoorDash.', sort_order: 126 , front_translations: {"de":"Was ist Y Combinator (YC)?"}, back_translations: {"de":"Der bekannteste Startup-Accelerator, gegründet 2005. YC investiert $500K für ca. 7% Anteile, bietet drei Monate Mentoring und endet mit dem Demo Day, an dem Startups vor Investoren pitchen. Alumni sind u. a. Airbnb, Stripe, Dropbox und DoorDash."}},
  { id: 'dc-startup-0127', deck_id: 'deck-startup-fundamentals', front: 'What is a startup accelerator?', back: 'A fixed-term program (typically 3-6 months) that provides startups with mentorship, education, resources, and often seed funding in exchange for equity (usually 5-10%). Programs end with a demo day. Top accelerators include YC, Techstars, and 500 Global.', sort_order: 127 , front_translations: {"de":"Was ist ein Startup-Accelerator?"}, back_translations: {"de":"Ein zeitlich begrenztes Programm (typischerweise 3–6 Monate), das Startups Mentoring, Weiterbildung, Ressourcen und oft Seed-Finanzierung im Austausch für Anteile (meist 5–10%) bietet. Die Programme enden mit einem Demo Day. Zu den Top-Accelerators gehören YC, Techstars und 500 Global."}},
  { id: 'dc-startup-0128', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between an accelerator and an incubator?', back: 'Accelerators have fixed timelines (3-6 months), take equity, and focus on rapid growth for existing startups. Incubators provide longer-term support (1-5 years), may not take equity, and help nurture very early ideas into viable businesses. Accelerators are more intense and selective.', sort_order: 128 , front_translations: {"de":"Was ist der Unterschied zwischen einem Accelerator und einem Inkubator?"}, back_translations: {"de":"Accelerators haben feste Laufzeiten (3–6 Monate), nehmen Anteile und konzentrieren sich auf schnelles Wachstum bestehender Startups. Inkubatoren bieten längerfristige Unterstützung (1–5 Jahre), nehmen möglicherweise keine Anteile und helfen, sehr frühe Ideen zu tragfähigen Unternehmen zu entwickeln. Accelerators sind intensiver und selektiver."}},
  { id: 'dc-startup-0129', deck_id: 'deck-startup-fundamentals', front: 'What is a financial model for a startup?', back: 'A spreadsheet projecting revenue, expenses, cash flow, and key metrics over 3-5 years. It includes assumptions about growth rate, pricing, headcount, and costs. Investors use it to assess viability and capital needs. Focus on the assumptions, not precise numbers.', sort_order: 129 , front_translations: {"de":"Was ist ein Finanzmodell für ein Startup?"}, back_translations: {"de":"Eine Tabellenkalkulation, die Umsatz, Ausgaben, Cashflow und Schlüsselkennzahlen über 3–5 Jahre projiziert. Sie enthält Annahmen zu Wachstumsrate, Preisgestaltung, Personalplanung und Kosten. Investoren nutzen sie, um die Tragfähigkeit und den Kapitalbedarf zu bewerten. Fokus auf die Annahmen, nicht auf exakte Zahlen."}},
  { id: 'dc-startup-0130', deck_id: 'deck-startup-fundamentals', front: 'What are revenue projections and how should startups approach them?', back: 'Forecasts of future revenue based on growth assumptions. Build them bottom-up using realistic inputs: number of customers you can acquire, conversion rates, average revenue per user, and churn. Avoid top-down projections like "we just need 1% of this giant market."', sort_order: 130 , front_translations: {"de":"Was sind Umsatzprognosen und wie sollten Startups sie erstellen?"}, back_translations: {"de":"Vorhersagen über künftige Umsätze basierend auf Wachstumsannahmen. Erstelle sie Bottom-up mit realistischen Inputs: Anzahl akquirierbarer Kunden, Conversion Rates, durchschnittlicher Umsatz pro Nutzer und Churn. Vermeide Top-down-Projektionen wie „Wir brauchen nur 1% dieses riesigen Marktes.\""}},
  { id: 'dc-startup-0131', deck_id: 'deck-startup-fundamentals', front: 'What is a pro rata right?', back: 'An investor right to participate in future funding rounds to maintain their ownership percentage. If an investor owns 10% and has pro rata rights, they can invest enough in the next round to keep their 10% stake. It protects investors from dilution.', sort_order: 131 , front_translations: {"de":"Was ist ein Pro-Rata-Recht?"}, back_translations: {"de":"Ein Investorenrecht, an zukünftigen Finanzierungsrunden teilzunehmen, um den eigenen Eigentumsanteil aufrechtzürhalten. Besitzt ein Investor 10% und hat Pro-Rata-Rechte, kann er in der nächsten Runde genug investieren, um seinen 10%-Anteil zu behalten. Es schützt Investoren vor Verwässerung."}},
  { id: 'dc-startup-0132', deck_id: 'deck-startup-fundamentals', front: 'What is a board of directors in a startup?', back: 'A group of individuals who oversee the company strategy, governance, and major decisions. Early-stage boards typically have 3-5 members: founders, investor representatives, and independent directors. The board hires/fires the CEO, approves budgets, and guides strategy.', sort_order: 132 , front_translations: {"de":"Was ist ein Board of Directors bei einem Startup?"}, back_translations: {"de":"Eine Gruppe von Personen, die über Unternehmensstrategie, Governance und wichtige Entscheidungen wacht. Boards in der Frühphase haben typischerweise 3–5 Mitglieder: Gründer, Investorenvertreter und unabhängige Mitglieder. Das Board stellt den CEO ein/entlässt ihn, genehmigt Budgets und leitet die Strategie."}},
  { id: 'dc-startup-0133', deck_id: 'deck-startup-fundamentals', front: 'What is a data room for fundraising?', back: 'A secure repository (often virtual) containing key documents investors review during due diligence: financials, legal documents, cap table, customer contracts, team info, IP documentation, and metrics. Having a well-organized data room speeds up the fundraising process.', sort_order: 133 , front_translations: {"de":"Was ist ein Data Room für die Finanzierung?"}, back_translations: {"de":"Ein sicheres Repository (oft virtüll) mit wichtigen Dokumenten, die Investoren bei der Dü Diligence prüfen: Finanzen, Rechtsdokumente, Cap Table, Kundenverträge, Teaminfos, IP-Dokumentation und Kennzahlen. Ein gut organisierter Data Room beschleunigt den Finanzierungsprozess."}},
  { id: 'dc-startup-0134', deck_id: 'deck-startup-fundamentals', front: 'What is preferred stock vs common stock?', back: 'Preferred stock is issued to investors and carries special rights: liquidation preference, anti-dilution protection, and voting rights. Common stock is held by founders and employees and has fewer protections. In a sale, preferred stockholders get paid first.', sort_order: 134 , front_translations: {"de":"Was ist der Unterschied zwischen Preferred Stock und Common Stock?"}, back_translations: {"de":"Preferred Stock wird an Investoren ausgegeben und bietet besondere Rechte: Liquidation Preference, Verwässerungsschutz und Stimmrechte. Common Stock wird von Gründern und Mitarbeitern gehalten und hat weniger Schutzrechte. Bei einem Verkauf werden Preferred-Stock-Inhaber zuerst ausgezahlt."}},
  { id: 'dc-startup-0135', deck_id: 'deck-startup-fundamentals', front: 'What is a bridge round?', back: 'A smaller funding round designed to bridge a company to its next major round. Often structured as convertible notes or SAFEs. Companies raise bridge rounds when they need more runway but are not ready for a full priced round. Can signal either momentum or distress.', sort_order: 135 , front_translations: {"de":"Was ist eine Bridge Round?"}, back_translations: {"de":"Eine kleinere Finanzierungsrunde, die ein Unternehmen bis zur nächsten großen Runde überbrücken soll. Oft als Convertible Notes oder SAFEs strukturiert. Unternehmen nutzen Bridge Rounds, wenn sie mehr Runway brauchen, aber noch nicht bereit für eine vollständig bewertete Runde sind. Kann sowohl Momentum als auch Probleme signalisieren."}},
  { id: 'dc-startup-0136', deck_id: 'deck-startup-fundamentals', front: 'What is a lead investor?', back: 'The primary investor in a funding round who negotiates the terms, sets the valuation, and often takes a board seat. Having a reputable lead investor signals quality to other investors and makes it easier to fill the rest of the round.', sort_order: 136 , front_translations: {"de":"Was ist ein Lead Investor?"}, back_translations: {"de":"Der Hauptinvestor einer Finanzierungsrunde, der die Bedingungen verhandelt, die Bewertung festlegt und oft einen Aufsichtsratssitz einnimmt. Ein renommierter Lead Investor signalisiert anderen Investoren Qualität und erleichtert es, den Rest der Runde zu füllen."}},
  { id: 'dc-startup-0137', deck_id: 'deck-startup-fundamentals', front: 'What is traction and how do investors evaluate it?', back: 'Evidence that your startup is gaining momentum. Key traction metrics include revenue growth, user growth, engagement metrics, retention rates, and notable partnerships or customers. Investors want to see consistent month-over-month growth and signs of product-market fit.', sort_order: 137 , front_translations: {"de":"Was ist Traktion und wie bewerten Investoren sie?"}, back_translations: {"de":"Der Nachweis, dass dein Startup an Dynamik gewinnt. Wichtige Traktionskennzahlen sind Umsatzwachstum, Nutzerwachstum, Engagement-Metriken, Retention Rates und bedeutende Partnerschaften oder Kunden. Investoren wollen konsistentes Monat-für-Monat-Wachstum und Anzeichen von Product-Market Fit sehen."}},
  { id: 'dc-startup-0138', deck_id: 'deck-startup-fundamentals', front: 'What is a startup valuation method at the early stage?', back: 'Early-stage valuations are more art than science. Methods include comparable company analysis, the Berkus method (assigning value to risk reduction factors), the scorecard method (adjusting based on team, market, product), and the venture capital method (working backward from expected exit).', sort_order: 138 , front_translations: {"de":"Wie werden Startups in der Frühphase bewertet?"}, back_translations: {"de":"Bewertungen in der Frühphase sind mehr Kunst als Wissenschaft. Methoden umfassen Comparable Company Analysis, die Berkus-Methode (Wert basierend auf Risikominderungsfaktoren), die Scorecard-Methode (Anpassung basierend auf Team, Markt, Produkt) und die Venture-Capital-Methode (Rückrechnung vom erwarteten Exit)."}},
  { id: 'dc-startup-0139', deck_id: 'deck-startup-fundamentals', front: 'What is the venture capital method of valuation?', back: 'Work backward from an expected exit value: if you expect a $100M exit in 5 years and the VC wants 10x return, the post-money valuation today should be $10M. For a $2M investment, the VC would own 20%. This method anchors valuation to investor return expectations.', sort_order: 139 , front_translations: {"de":"Was ist die Venture-Capital-Methode der Bewertung?"}, back_translations: {"de":"Rückwärts vom erwarteten Exit-Wert rechnen: Erwartet man einen $100M-Exit in 5 Jahren und der VC will 10x Rendite, sollte die Post-Money-Bewertung heute $10M betragen. Bei einer $2M-Investition besäße der VC 20%. Diese Methode verankert die Bewertung an den Renditeerwartungen der Investoren."}},
  { id: 'dc-startup-0140', deck_id: 'deck-startup-fundamentals', front: 'What is the typical equity investors expect at each stage?', back: 'Pre-seed: 10-15% for $100K-$500K. Seed: 15-25% for $500K-$3M. Series A: 15-30% for $3-15M. These are rough ranges and vary by market, team, and traction. Founders should aim to retain 50%+ ownership through Series A for meaningful control and motivation.', sort_order: 140 , front_translations: {"de":"Wie viel Equity erwarten Investoren typischerweise in jeder Phase?"}, back_translations: {"de":"Pre-Seed: 10–15% für $100K–$500K. Seed: 15–25% für $500K–$3M. Series A: 15–30% für $3–15M. Dies sind grobe Richtwerte, die je nach Markt, Team und Traktion variieren. Gründer sollten bis zur Series A über 50% Eigentum behalten, um eine sinnvolle Kontrolle und Motivation zu sichern."}},
  { id: 'dc-startup-0141', deck_id: 'deck-startup-fundamentals', front: 'What is a pitch deck narrative structure?', back: 'The most effective pitch decks tell a story: start with the problem (create urgency), present the solution (your product), prove the opportunity (market size), show traction (evidence it works), introduce the team (why you will win), and close with the ask (what you need to get to the next level).', sort_order: 141 , front_translations: {"de":"Was ist eine Pitch-Deck-Erzählstruktur?"}, back_translations: {"de":"Die effektivsten Pitch Decks erzählen eine Geschichte: Beginne mit dem Problem (Dringlichkeit erzeugen), präsentiere die Lösung (dein Produkt), belege die Chance (Marktgröße), zeige Traktion (Beweis, dass es funktioniert), stelle das Team vor (warum ihr gewinnen werdet) und schließe mit dem Ask (was ihr braucht, um das nächste Level zu erreichen)."}},
  { id: 'dc-startup-0142', deck_id: 'deck-startup-fundamentals', front: 'What are common mistakes in startup fundraising?', back: 'Raising too much or too little, giving up too much equity too early, not having a clear use of funds, targeting wrong investors, poor storytelling, no clear metrics, and not creating urgency. Also: fundraising takes longer than expected — plan for 3-6 months.', sort_order: 142 , front_translations: {"de":"Welche häufigen Fehler gibt es bei der Startup-Finanzierung?"}, back_translations: {"de":"Zu viel oder zu wenig Kapital aufnehmen, zu früh zu viele Anteile abgeben, keine klare Mittelverwendung, falsche Investoren ansprechen, schlechtes Storytelling, keine klaren Kennzahlen und keine Dringlichkeit erzeugen. Außerdem: Fundraising dauert länger als erwartet – plane 3–6 Monate ein."}},
  { id: 'dc-startup-0143', deck_id: 'deck-startup-fundamentals', front: 'What is investor-founder fit and why does it matter?', back: 'The alignment between a founder and investor on vision, expectations, communication style, and involvement level. Good investor-founder fit means the investor adds value beyond money through relevant expertise, connections, and constructive support. Bad fit can lead to conflicts and forced pivots.', sort_order: 143 , front_translations: {"de":"Was ist Investor-Founder Fit und warum ist er wichtig?"}, back_translations: {"de":"Die Übereinstimmung zwischen Gründer und Investor hinsichtlich Vision, Erwartungen, Kommunikationsstil und Grad der Einbindung. Guter Investor-Founder Fit bedeutet, dass der Investor über das Geld hinaus Mehrwert bietet – durch relevante Expertise, Kontakte und konstruktive Unterstützung. Schlechter Fit kann zu Konflikten und erzwungenen Pivots führen."}},
  { id: 'dc-startup-0144', deck_id: 'deck-startup-fundamentals', front: 'What is a rolling close in fundraising?', back: 'Accepting investments as they come in rather than waiting for the entire round to be committed before closing. Common with SAFEs and convertible notes. It lets startups access capital faster, but requires careful management of different investor terms.', sort_order: 144 , front_translations: {"de":"Was ist ein Rolling Close beim Fundraising?"}, back_translations: {"de":"Investitionen annehmen, sobald sie eintreffen, anstatt auf die Zusage der gesamten Runde zu warten. Üblich bei SAFEs und Convertible Notes. Es ermöglicht Startups schnelleren Zugang zu Kapital, erfordert aber sorgfältiges Management unterschiedlicher Investorenbedingungen."}},
  { id: 'dc-startup-0145', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between revenue-based financing and equity financing?', back: 'Revenue-based financing provides capital in exchange for a percentage of future revenue until a fixed amount is repaid (typically 1.5-3x the investment). Unlike equity financing, founders retain full ownership. It works best for companies with predictable, recurring revenue.', sort_order: 145 , front_translations: {"de":"Was ist der Unterschied zwischen Revenue-Based Financing und Equity Financing?"}, back_translations: {"de":"Revenue-Based Financing stellt Kapital im Austausch für einen Prozentsatz zukünftiger Einnahmen bereit, bis ein fester Betrag zurückgezahlt ist (typischerweise 1,5–3x der Investition). Anders als bei Equity Financing behalten Gründer das volle Eigentum. Es eignet sich am besten für Unternehmen mit planbaren, wiederkehrenden Einnahmen."}},

  // === Marketing & Growth (146-195) ===
  { id: 'dc-startup-0146', deck_id: 'deck-startup-fundamentals', front: 'What is growth hacking?', back: 'A marketing approach focused on rapid experimentation across channels and product features to identify the most efficient ways to grow a business. Coined by Sean Ellis. It blends marketing, product development, and data analysis. Famous example: Hotmail adding "Get your free email" to every outgoing message.', sort_order: 146 , front_translations: {"de":"Was ist Growth Hacking?"}, back_translations: {"de":"Ein Marketingansatz, der auf schnelles Experimentieren über verschiedene Kanäle und Produktfeatures setzt, um die effizientesten Wachstumswege zu finden. Geprägt von Sean Ellis. Er verbindet Marketing, Produktentwicklung und Datenanalyse. Berühmtes Beispiel: Hotmail fügte jeder ausgehenden E-Mail „Get your free email\" hinzu."}},
  { id: 'dc-startup-0147', deck_id: 'deck-startup-fundamentals', front: 'What is the AARRR (Pirate Metrics) framework?', back: 'A funnel framework by Dave McClure: Acquisition (how users find you), Activation (first great experience), Retention (users come back), Revenue (users pay), Referral (users tell others). Focus on the weakest stage first — fixing a leaky bucket before pouring more water in.', sort_order: 147 , front_translations: {"de":"Was ist das AARRR-Framework (Pirate Metrics)?"}, back_translations: {"de":"Ein Funnel-Framework von Dave McClure: Acquisition (wie Nutzer dich finden), Activation (erstes großartiges Erlebnis), Retention (Nutzer kommen zurück), Revenue (Nutzer zahlen), Referral (Nutzer empfehlen weiter). Konzentriere dich zuerst auf die schwächste Stufe – erst den löchrigen Eimer reparieren, bevor man mehr Wasser hineingießt."}},
  { id: 'dc-startup-0148', deck_id: 'deck-startup-fundamentals', front: 'What is SEO (Search Engine Optimization) for startups?', back: 'Optimizing your website to rank higher in search engine results for relevant queries. Includes technical SEO (site speed, mobile-friendly), on-page SEO (keywords, content quality), and off-page SEO (backlinks, domain authority). SEO is a long-term channel but provides sustainable free traffic.', sort_order: 148 , front_translations: {"de":"Was ist SEO (Suchmaschinenoptimierung) für Startups?"}, back_translations: {"de":"Die Optimierung deiner Website für höhere Platzierungen in Suchergebnissen bei relevanten Anfragen. Umfasst technisches SEO (Ladezeit, Mobilfreundlichkeit), On-Page-SEO (Keywords, Inhaltsqualität) und Off-Page-SEO (Backlinks, Domain Authority). SEO ist ein langfristiger Kanal, liefert aber nachhaltigen kostenlosen Traffic."}},
  { id: 'dc-startup-0149', deck_id: 'deck-startup-fundamentals', front: 'What is content marketing?', back: 'Creating valuable, relevant content (blog posts, videos, guides, podcasts) to attract and engage your target audience. It builds trust and authority, improves SEO, and generates inbound leads. HubSpot built a $30B+ company largely through content marketing.', sort_order: 149 , front_translations: {"de":"Was ist Content Marketing?"}, back_translations: {"de":"Das Erstellen wertvoller, relevanter Inhalte (Blogbeiträge, Videos, Leitfäden, Podcasts), um die Zielgruppe anzuziehen und zu binden. Es baut Vertraün und Autorität auf, verbessert SEO und generiert Inbound-Leads. HubSpot baute ein $30 Mrd.+ Unternehmen größtenteils durch Content Marketing auf."}},
  { id: 'dc-startup-0150', deck_id: 'deck-startup-fundamentals', front: 'What is paid acquisition and when should startups use it?', back: 'Paying for advertising on platforms like Google Ads, Facebook/Meta Ads, or LinkedIn to acquire customers. Use it when you have validated your unit economics (LTV > 3x CAC) and want to scale predictably. Start with small budgets, test multiple creatives, and measure ROI rigorously.', sort_order: 150 , front_translations: {"de":"Was ist Paid Acquisition und wann sollten Startups sie nutzen?"}, back_translations: {"de":"Bezahlte Werbung auf Plattformen wie Google Ads, Facebook/Meta Ads oder LinkedIn, um Kunden zu gewinnen. Einsetzen, wenn die Unit Economics validiert sind (LTV > 3x CAC) und man planbar skalieren möchte. Mit kleinen Budgets starten, verschiedene Creatives testen und den ROI konseqünt messen."}},
  { id: 'dc-startup-0151', deck_id: 'deck-startup-fundamentals', front: 'What is a conversion funnel?', back: 'The journey a potential customer takes from first awareness to becoming a paying customer. Each stage has a conversion rate. For example: 1000 visitors, 100 sign up (10%), 30 activate (30%), 10 subscribe (33%). Improving any stage has a multiplicative effect on revenue.', sort_order: 151 , front_translations: {"de":"Was ist ein Conversion Funnel?"}, back_translations: {"de":"Die Reise, die ein potenzieller Kunde von der ersten Wahrnehmung bis zum zahlenden Kunden durchläuft. Jede Stufe hat eine Conversion Rate. Beispiel: 1000 Besucher, 100 melden sich an (10 %), 30 aktivieren (30 %), 10 abonnieren (33 %). Die Verbesserung jeder Stufe wirkt sich multiplikativ auf den Umsatz aus."}},
  { id: 'dc-startup-0152', deck_id: 'deck-startup-fundamentals', front: 'What is a referral program and how should startups design one?', back: 'A structured system that rewards existing users for bringing in new users. Effective programs offer two-sided incentives (both referrer and referee get value). Dropbox grew 3900% in 15 months by offering extra storage for referrals. The reward should align with your product value.', sort_order: 152 , front_translations: {"de":"Was ist ein Empfehlungsprogramm und wie sollten Startups eines gestalten?"}, back_translations: {"de":"Ein strukturiertes System, das bestehende Nutzer dafür belohnt, neü Nutzer zu gewinnen. Effektive Programme bieten beidseitige Anreize (sowohl der Empfehlende als auch der Empfohlene erhalten einen Vorteil). Dropbox wuchs in 15 Monaten um 3900 %, indem sie zusätzlichen Speicherplatz für Empfehlungen anboten. Die Belohnung sollte zum Produktwert passen."}},
  { id: 'dc-startup-0153', deck_id: 'deck-startup-fundamentals', front: 'What is a viral loop?', back: 'A mechanism where each new user naturally invites or exposes other potential users to the product as part of normal usage. The viral coefficient (K-factor) is the number of new users each existing user generates. If K > 1, growth is exponential. Examples: shared documents, social posts.', sort_order: 153 , front_translations: {"de":"Was ist ein Viral Loop?"}, back_translations: {"de":"Ein Mechanismus, bei dem jeder neü Nutzer im Rahmen der normalen Nutzung andere potenzielle Nutzer auf das Produkt aufmerksam macht oder einlädt. Der virale Köffizient (K-Faktor) gibt an, wie viele neü Nutzer jeder bestehende Nutzer generiert. Ist K > 1, wächst das Produkt exponentiell. Beispiele: geteilte Dokumente, Social-Media-Posts."}},
  { id: 'dc-startup-0154', deck_id: 'deck-startup-fundamentals', front: 'What is the viral coefficient (K-factor)?', back: 'A metric measuring viral growth: K = (invitations sent per user) x (conversion rate of those invitations). If K > 1, each user brings in more than one new user, creating exponential growth. Even K values below 1 amplify other acquisition channels and reduce effective CAC.', sort_order: 154 , front_translations: {"de":"Was ist der virale Köffizient (K-Faktor)?"}, back_translations: {"de":"Eine Kennzahl zur Messung viralen Wachstums: K = (gesendete Einladungen pro Nutzer) x (Conversion Rate dieser Einladungen). Ist K > 1, bringt jeder Nutzer mehr als einen neün Nutzer, was exponentielles Wachstum erzeugt. Selbst K-Werte unter 1 verstärken andere Akquisitionskanäle und senken die effektiven CAC."}},
  { id: 'dc-startup-0155', deck_id: 'deck-startup-fundamentals', front: 'What is email marketing for startups?', back: 'Using email to nurture leads, onboard users, and retain customers. Key tactics include welcome sequences, educational drip campaigns, product updates, and re-engagement emails. Email has one of the highest ROI among marketing channels. Segment your list and personalize content.', sort_order: 155 , front_translations: {"de":"Was ist E-Mail-Marketing für Startups?"}, back_translations: {"de":"Der Einsatz von E-Mail zur Lead-Pflege, Nutzer-Onboarding und Kundenbindung. Wichtige Taktiken sind Willkommensseqünzen, lehrreiche Drip-Kampagnen, Produktupdates und Re-Engagement-E-Mails. E-Mail hat einen der höchsten ROI unter allen Marketingkanälen. Segmentiere deine Liste und personalisiere die Inhalte."}},
  { id: 'dc-startup-0156', deck_id: 'deck-startup-fundamentals', front: 'What is a drip campaign?', back: 'An automated sequence of emails sent over time based on triggers (sign-up, action, inactivity). Each email builds on the previous one to guide users toward a goal. Example: Day 1 welcome, Day 3 feature highlight, Day 7 case study, Day 14 upgrade offer.', sort_order: 156 , front_translations: {"de":"Was ist eine Drip-Kampagne?"}, back_translations: {"de":"Eine automatisierte Abfolge von E-Mails, die über einen Zeitraum hinweg basierend auf Auslösern (Anmeldung, Aktion, Inaktivität) versendet werden. Jede E-Mail baut auf der vorherigen auf und führt den Nutzer zu einem Ziel. Beispiel: Tag 1 Willkommen, Tag 3 Feature-Highlight, Tag 7 Fallstudie, Tag 14 Upgrade-Angebot."}},
  { id: 'dc-startup-0157', deck_id: 'deck-startup-fundamentals', front: 'What is A/B testing?', back: 'Comparing two versions of a webpage, email, or feature to see which performs better. Show version A to half your audience and version B to the other half, then measure which has better conversion. Test one variable at a time and ensure statistical significance before drawing conclusions.', sort_order: 157 , front_translations: {"de":"Was ist A/B-Testing?"}, back_translations: {"de":"Der Vergleich zweier Versionen einer Webseite, E-Mail oder eines Features, um zu sehen, welche besser abschneidet. Version A wird der einen Hälfte der Zielgruppe gezeigt, Version B der anderen, und dann wird gemessen, welche die bessere Conversion hat. Teste jeweils nur eine Variable und stelle statistische Signifikanz sicher, bevor du Schlüsse ziehst."}},
  { id: 'dc-startup-0158', deck_id: 'deck-startup-fundamentals', front: 'What is landing page optimization?', back: 'Improving a landing page to maximize conversions. Key elements: clear headline, compelling value proposition, social proof (testimonials, logos), strong call to action, minimal distractions, and fast load time. A/B test headlines, images, and CTAs to find the highest converting combination.', sort_order: 158 , front_translations: {"de":"Was ist Landing-Page-Optimierung?"}, back_translations: {"de":"Die Verbesserung einer Landing Page zur Maximierung von Conversions. Wichtige Elemente: klare Überschrift, überzeugendes Wertversprechen, Social Proof (Testimonials, Logos), starker Call to Action, minimale Ablenkungen und schnelle Ladezeit. Teste Überschriften, Bilder und CTAs per A/B-Test, um die beste Kombination zu finden."}},
  { id: 'dc-startup-0159', deck_id: 'deck-startup-fundamentals', front: 'What is a customer persona?', back: 'A fictional, detailed representation of your ideal customer based on real data and research. Includes demographics, goals, frustrations, behavior patterns, and preferred channels. Personas help teams make consistent product and marketing decisions aligned with actual user needs.', sort_order: 159 , front_translations: {"de":"Was ist eine Kunden-Persona?"}, back_translations: {"de":"Eine fiktive, detaillierte Darstellung deines idealen Kunden, basierend auf echten Daten und Recherche. Umfasst Demografie, Ziele, Frustrationen, Verhaltensmuster und bevorzugte Kanäle. Personas helfen Teams, konsistente Produkt- und Marketingentscheidungen zu treffen, die auf reale Nutzerbedürfnisse abgestimmt sind."}},
  { id: 'dc-startup-0160', deck_id: 'deck-startup-fundamentals', front: 'What is ICP (Ideal Customer Profile)?', back: 'A description of the type of company or individual that would benefit most from your product. For B2B, it includes company size, industry, budget, and pain points. For B2C, it covers demographics, behaviors, and needs. Focusing on your ICP improves conversion rates and reduces wasted spend.', sort_order: 160 , front_translations: {"de":"Was ist ein ICP (Ideal Customer Profile)?"}, back_translations: {"de":"Eine Beschreibung des Unternehmens- oder Personentyps, der am meisten von deinem Produkt profitieren würde. Im B2B umfasst es Unternehmensgröße, Branche, Budget und Pain Points. Im B2C deckt es Demografie, Verhaltensweisen und Bedürfnisse ab. Die Konzentration auf dein ICP verbessert Conversion Rates und reduziert verschwendete Ausgaben."}},
  { id: 'dc-startup-0161', deck_id: 'deck-startup-fundamentals', front: 'How can startups build a brand on a limited budget?', back: 'Focus on consistency across all touchpoints: name, logo, voice, colors, and messaging. Tell an authentic founder story. Engage actively on social media. Create valuable content. Build community around your mission. Leverage PR and partnerships. Strong brands are built through trust, not ad spend.', sort_order: 161 , front_translations: {"de":"Wie können Startups mit begrenztem Budget eine Marke aufbaun?"}, back_translations: {"de":"Konzentriere dich auf Konsistenz über alle Berührungspunkte: Name, Logo, Tonalität, Farben und Botschaft. Erzähle eine authentische Gründergeschichte. Sei aktiv in sozialen Medien. Erstelle wertvolle Inhalte. Bau eine Community rund um deine Mission auf. Nutze PR und Partnerschaften. Starke Marken entstehen durch Vertraün, nicht durch Werbebudgets."}},
  { id: 'dc-startup-0162', deck_id: 'deck-startup-fundamentals', front: 'How should startups approach a Product Hunt launch?', back: 'Prepare in advance: build an email list, create compelling visuals, write a clear tagline, and line up supporters to upvote and comment on launch day. Launch on Tuesday-Thursday for best visibility. Engage actively in comments. A successful launch can drive thousands of sign-ups in one day.', sort_order: 162 , front_translations: {"de":"Wie sollten Startups einen Product Hunt Launch angehen?"}, back_translations: {"de":"Bereite dich im Voraus vor: Bau eine E-Mail-Liste auf, erstelle ansprechende Grafiken, schreibe einen klaren Slogan und organisiere Unterstützer für Upvotes und Kommentare am Launchtag. Starte dienstags bis donnerstags für beste Sichtbarkeit. Sei aktiv in den Kommentaren. Ein erfolgreicher Launch kann Tausende von Anmeldungen an einem Tag bringen."}},
  { id: 'dc-startup-0163', deck_id: 'deck-startup-fundamentals', front: 'What is social media marketing for startups?', back: 'Using platforms like Twitter/X, LinkedIn, Instagram, and TikTok to build brand awareness, engage with customers, and drive traffic. Choose 1-2 platforms where your target audience is most active. Consistency matters more than frequency. Share value, not just promotions.', sort_order: 163 , front_translations: {"de":"Was ist Social-Media-Marketing für Startups?"}, back_translations: {"de":"Die Nutzung von Plattformen wie Twitter/X, LinkedIn, Instagram und TikTok zum Aufbau von Markenbekanntheit, zur Interaktion mit Kunden und zur Traffic-Generierung. Wähle 1-2 Plattformen, auf denen deine Zielgruppe am aktivsten ist. Konsistenz ist wichtiger als Häufigkeit. Teile Mehrwert, nicht nur Werbung."}},
  { id: 'dc-startup-0164', deck_id: 'deck-startup-fundamentals', front: 'What is a go-to-market (GTM) strategy?', back: 'A plan for how you will bring your product to market and acquire customers. It covers target audience, value proposition, pricing, distribution channels, marketing strategy, and sales process. A strong GTM strategy aligns product, marketing, and sales around the same customer segments.', sort_order: 164 , front_translations: {"de":"Was ist eine Go-to-Market (GTM) Strategie?"}, back_translations: {"de":"Ein Plan, wie du dein Produkt auf den Markt bringst und Kunden gewinnst. Er umfasst Zielgruppe, Wertversprechen, Preisgestaltung, Vertriebskanäle, Marketingstrategie und Verkaufsprozess. Eine starke GTM-Strategie richtet Produkt, Marketing und Vertrieb auf dieselben Kundensegmente aus."}},
  { id: 'dc-startup-0165', deck_id: 'deck-startup-fundamentals', front: 'What is inbound vs outbound marketing?', back: 'Inbound attracts customers through valuable content, SEO, and social media — customers come to you. Outbound reaches out to prospects through cold emails, calls, ads, and events — you go to customers. Most startups benefit from a mix, weighted by their business model (B2B tends outbound, B2C tends inbound).', sort_order: 165 , front_translations: {"de":"Was ist Inbound- vs. Outbound-Marketing?"}, back_translations: {"de":"Inbound zieht Kunden durch wertvolle Inhalte, SEO und Social Media an – die Kunden kommen zu dir. Outbound spricht Interessenten durch Cold E-Mails, Anrufe, Werbung und Events an – du gehst zu den Kunden. Die meisten Startups profitieren von einer Mischung, gewichtet nach Geschäftsmodell (B2B tendiert zu Outbound, B2C zu Inbound)."}},
  { id: 'dc-startup-0166', deck_id: 'deck-startup-fundamentals', front: 'What is customer acquisition through partnerships?', back: 'Collaborating with complementary businesses to access their customer base. Types include co-marketing (joint content), integrations (connecting products), affiliate programs (commission-based referrals), and distribution partnerships. Choose partners whose customers match your ICP.', sort_order: 166 , front_translations: {"de":"Was ist Kundenakquise durch Partnerschaften?"}, back_translations: {"de":"Die Zusammenarbeit mit komplementären Unternehmen, um deren Kundenstamm zu erreichen. Arten sind Co-Marketing (gemeinsame Inhalte), Integrationen (Produktverknüpfungen), Affiliate-Programme (provisionsbasierte Empfehlungen) und Vertriebspartnerschaften. Wähle Partner, deren Kunden zu deinem ICP passen."}},
  { id: 'dc-startup-0167', deck_id: 'deck-startup-fundamentals', front: 'What is PR (Public Relations) for startups?', back: 'Earning media coverage through press releases, journalist relationships, and compelling stories. Effective startup PR focuses on a unique founder story, innovative technology, impressive traction, or timely industry trends. Free coverage in top publications can drive significant traffic and credibility.', sort_order: 167 , front_translations: {"de":"Was ist PR (Public Relations) für Startups?"}, back_translations: {"de":"Medienberichterstattung durch Pressemitteilungen, Journalistenkontakte und überzeugende Geschichten gewinnen. Effektive Startup-PR konzentriert sich auf eine einzigartige Gründergeschichte, innovative Technologie, beeindruckende Traktion oder aktuelle Branchentrends. Kostenlose Berichterstattung in Top-Medien kann erheblichen Traffic und Glaubwürdigkeit bringen."}},
  { id: 'dc-startup-0168', deck_id: 'deck-startup-fundamentals', front: 'What is CPC (Cost Per Click) in paid advertising?', back: 'The amount you pay each time someone clicks on your ad. Calculated as total ad spend divided by total clicks. Varies widely by industry and platform ($0.50-$50+). Use CPC along with conversion rate to calculate your cost per acquisition and determine profitability.', sort_order: 168 , front_translations: {"de":"Was ist CPC (Cost Per Click) in der bezahlten Werbung?"}, back_translations: {"de":"Der Betrag, den du jedes Mal zahlst, wenn jemand auf deine Anzeige klickt. Berechnet als Gesamtwerbeausgaben geteilt durch Gesamtklicks. Variiert stark nach Branche und Plattform (0,50–50+ $). Verwende CPC zusammen mit der Conversion Rate, um deine Akquisitionskosten pro Kunde zu berechnen und die Rentabilität zu bestimmen."}},
  { id: 'dc-startup-0169', deck_id: 'deck-startup-fundamentals', front: 'What is CPA (Cost Per Acquisition) in marketing?', back: 'The cost to acquire one paying customer through a specific marketing channel. Calculated as total channel spend divided by number of customers acquired. CPA must be lower than LTV for the channel to be profitable. Compare CPA across channels to optimize your marketing budget.', sort_order: 169 , front_translations: {"de":"Was ist CPA (Cost Per Acquisition) im Marketing?"}, back_translations: {"de":"Die Kosten, um über einen bestimmten Marketingkanal einen zahlenden Kunden zu gewinnen. Berechnet als Gesamtausgaben des Kanals geteilt durch die Anzahl gewonnener Kunden. CPA muss niedriger sein als der LTV, damit der Kanal profitabel ist. Vergleiche den CPA über alle Kanäle, um dein Marketingbudget zu optimieren."}},
  { id: 'dc-startup-0170', deck_id: 'deck-startup-fundamentals', front: 'What is organic growth vs paid growth?', back: 'Organic growth comes from word-of-mouth, SEO, content, and product virality — no direct cost per user. Paid growth comes from advertising and sponsorships — predictable but costs money. The best startups build strong organic growth engines first, then amplify with paid channels.', sort_order: 170 , front_translations: {"de":"Was ist organisches vs. bezahltes Wachstum?"}, back_translations: {"de":"Organisches Wachstum entsteht durch Mundpropaganda, SEO, Content und Produktviralität – keine direkten Kosten pro Nutzer. Bezahltes Wachstum kommt durch Werbung und Sponsoring – planbar, aber kostspielig. Die besten Startups baun zuerst starke organische Wachstumsmotoren auf und verstärken diese dann mit bezahlten Kanälen."}},
  { id: 'dc-startup-0171', deck_id: 'deck-startup-fundamentals', front: 'What is community-led growth?', back: 'A strategy where a community of passionate users drives product adoption, feedback, and advocacy. Examples: Notion, Figma, and dbt all built strong communities that created content, answered questions, and attracted new users. Requires genuine investment in community value, not just marketing.', sort_order: 171 , front_translations: {"de":"Was ist Community-geführtes Wachstum?"}, back_translations: {"de":"Eine Strategie, bei der eine Community begeisterter Nutzer Produktadoption, Feedback und Fürsprache vorantreibt. Beispiele: Notion, Figma und dbt haben starke Communities aufgebaut, die Inhalte erstellten, Fragen beantworteten und neü Nutzer anzogen. Erfordert echtes Investment in den Community-Mehrwert, nicht nur Marketing."}},
  { id: 'dc-startup-0172', deck_id: 'deck-startup-fundamentals', front: 'What is a launch strategy for a new startup?', back: 'A coordinated plan to maximize impact when releasing your product. Common elements: build anticipation with a waitlist, launch on Product Hunt and Hacker News, send a press release, activate your network for social sharing, offer limited-time incentives, and capture and respond to all feedback.', sort_order: 172 , front_translations: {"de":"Was ist eine Launch-Strategie für ein neüs Startup?"}, back_translations: {"de":"Ein koordinierter Plan zur Maximierung der Wirkung bei der Veröffentlichung deines Produkts. Typische Elemente: Vorfreude durch eine Warteliste aufbaun, auf Product Hunt und Hacker News launchen, eine Pressemitteilung versenden, dein Netzwerk zum Teilen aktivieren, zeitlich begrenzte Anreize bieten und sämtliches Feedback erfassen und beantworten."}},
  { id: 'dc-startup-0173', deck_id: 'deck-startup-fundamentals', front: 'What is the 80/20 rule (Pareto Principle) applied to marketing?', back: 'Roughly 80% of your results come from 20% of your efforts. In marketing, this means a few channels drive most of your growth. Identify your top-performing channels and double down on them rather than spreading resources thin across many channels.', sort_order: 173 , front_translations: {"de":"Was ist die 80/20-Regel (Pareto-Prinzip) im Marketing?"}, back_translations: {"de":"Ungefähr 80 % deiner Ergebnisse kommen von 20 % deiner Bemühungen. Im Marketing bedeutet das, dass wenige Kanäle den Großteil deines Wachstums antreiben. Identifiziere deine leistungsstärksten Kanäle und investiere verstärkt in diese, anstatt Ressourcen dünn über viele Kanäle zu verteilen."}},
  { id: 'dc-startup-0174', deck_id: 'deck-startup-fundamentals', front: 'What is retention marketing?', back: 'Marketing efforts focused on keeping existing customers engaged and reducing churn. Tactics include personalized emails, in-app messaging, loyalty programs, customer success outreach, and product education. Retaining a customer is 5-25x cheaper than acquiring a new one.', sort_order: 174 , front_translations: {"de":"Was ist Retention Marketing?"}, back_translations: {"de":"Marketingmaßnahmen, die darauf abzielen, bestehende Kunden engagiert zu halten und Abwanderung zu reduzieren. Taktiken umfassen personalisierte E-Mails, In-App-Nachrichten, Treüprogramme, Customer-Success-Ansprache und Produktschulung. Einen Kunden zu halten ist 5-25x günstiger als einen neün zu gewinnen."}},
  { id: 'dc-startup-0175', deck_id: 'deck-startup-fundamentals', front: 'What is a marketing funnel vs a flywheel?', back: 'A funnel is a linear model: awareness, consideration, decision. The flywheel (popularized by HubSpot) is a circular model where happy customers drive referrals and growth, creating self-sustaining momentum. The flywheel better represents how modern growth-oriented companies actually grow.', sort_order: 175 , front_translations: {"de":"Was ist ein Marketing-Funnel vs. ein Flywheel?"}, back_translations: {"de":"Ein Funnel ist ein lineares Modell: Awareness, Consideration, Decision. Das Flywheel (bekannt gemacht durch HubSpot) ist ein kreisförmiges Modell, bei dem zufriedene Kunden Empfehlungen und Wachstum antreiben und so einen selbsterhaltenden Schwung erzeugen. Das Flywheel bildet besser ab, wie moderne wachstumsorientierte Unternehmen tatsächlich wachsen."}},
  { id: 'dc-startup-0176', deck_id: 'deck-startup-fundamentals', front: 'What is activation rate and why does it matter?', back: 'The percentage of signed-up users who complete a key action that indicates they have experienced your core value (e.g., completing onboarding, sending first message, making first project). Low activation is a sign of poor onboarding. Improving it is often the highest-leverage growth fix.', sort_order: 176 , front_translations: {"de":"Was ist die Aktivierungsrate und warum ist sie wichtig?"}, back_translations: {"de":"Der Prozentsatz angemeldeter Nutzer, die eine Schlüsselaktion abschließen, die zeigt, dass sie den Kernwert erfahren haben (z. B. Onboarding abschließen, erste Nachricht senden, erstes Projekt erstellen). Eine niedrige Aktivierung deutet auf schlechtes Onboarding hin. Sie zu verbessern ist oft der wirkungsvollste Wachstumshebel."}},
  { id: 'dc-startup-0177', deck_id: 'deck-startup-fundamentals', front: 'What is a channel-market fit?', back: 'Finding the right acquisition channel for your specific market and product type. Not all channels work for all businesses. B2B SaaS might work best with content marketing and LinkedIn; a consumer app might need TikTok or influencers. Test channels systematically before committing.', sort_order: 177 , front_translations: {"de":"Was ist Channel-Market Fit?"}, back_translations: {"de":"Den richtigen Akquisitionskanal für deinen spezifischen Markt und Produkttyp zu finden. Nicht alle Kanäle funktionieren für alle Unternehmen. B2B-SaaS funktioniert möglicherweise am besten mit Content Marketing und LinkedIn; eine Consumer App braucht vielleicht TikTok oder Influencer. Teste Kanäle systematisch, bevor du dich festlegst."}},
  { id: 'dc-startup-0178', deck_id: 'deck-startup-fundamentals', front: 'What is influencer marketing for startups?', back: 'Partnering with people who have large, engaged followings in your target market. Micro-influencers (1K-100K followers) often have higher engagement rates and lower costs than macro-influencers. Measure ROI through tracking links, promo codes, and attributed sign-ups or sales.', sort_order: 178 , front_translations: {"de":"Was ist Influencer-Marketing für Startups?"}, back_translations: {"de":"Partnerschaften mit Personen, die große, engagierte Followerschaften in deinem Zielmarkt haben. Micro-Influencer (1K-100K Follower) haben oft höhere Engagement-Raten und niedrigere Kosten als Macro-Influencer. Miss den ROI über Tracking-Links, Promo-Codes und zugeordnete Anmeldungen oder Verkäufe."}},
  { id: 'dc-startup-0179', deck_id: 'deck-startup-fundamentals', front: 'What is a waitlist strategy for pre-launch?', back: 'Collecting email addresses from interested potential users before your product is ready. Benefits: validates demand, builds an audience for launch day, and creates exclusivity. Enhance it with referral bonuses (move up the list by sharing), progress updates, and early access for top referrers.', sort_order: 179 , front_translations: {"de":"Was ist eine Wartelisten-Strategie vor dem Launch?"}, back_translations: {"de":"Das Sammeln von E-Mail-Adressen interessierter potenzieller Nutzer, bevor dein Produkt fertig ist. Vorteile: validiert die Nachfrage, baut eine Zielgruppe für den Launchtag auf und erzeugt Exklusivität. Verbessere sie mit Empfehlungsboni (durch Teilen auf der Liste vorrücken), Fortschrittsupdates und Early Access für Top-Empfehler."}},
  { id: 'dc-startup-0180', deck_id: 'deck-startup-fundamentals', front: 'What is customer segmentation?', back: 'Dividing your customer base into groups based on shared characteristics like behavior, demographics, or needs. Segmentation enables personalized marketing, better targeting, and differentiated pricing. Example: Slack segments by team size to tailor messaging and pricing tiers.', sort_order: 180 , front_translations: {"de":"Was ist Kundensegmentierung?"}, back_translations: {"de":"Die Aufteilung deines Kundenstamms in Gruppen anhand gemeinsamer Merkmale wie Verhalten, Demografie oder Bedürfnisse. Segmentierung ermöglicht personalisiertes Marketing, besseres Targeting und differenzierte Preisgestaltung. Beispiel: Slack segmentiert nach Teamgröße, um Botschaften und Preisstufen anzupassen."}},
  { id: 'dc-startup-0181', deck_id: 'deck-startup-fundamentals', front: 'What is a lead magnet?', back: 'A free resource (ebook, template, tool, webinar) offered in exchange for a visitor email address. It starts the relationship and lets you nurture the lead through email marketing. The best lead magnets solve a specific problem related to your paid product.', sort_order: 181 , front_translations: {"de":"Was ist ein Lead Magnet?"}, back_translations: {"de":"Eine kostenlose Ressource (E-Book, Vorlage, Tool, Webinar), die im Austausch gegen die E-Mail-Adresse eines Besuchers angeboten wird. Es startet die Beziehung und ermöglicht die Lead-Pflege durch E-Mail-Marketing. Die besten Lead Magnets lösen ein spezifisches Problem, das mit deinem kostenpflichtigen Produkt zusammenhängt."}},
  { id: 'dc-startup-0182', deck_id: 'deck-startup-fundamentals', front: 'What is NPS (Net Promoter Score)?', back: 'A metric that measures customer loyalty by asking: "How likely are you to recommend this product to a friend?" (0-10 scale). Promoters (9-10) minus Detractors (0-6) = NPS. Scores above 50 are excellent. NPS correlates with organic growth through word-of-mouth.', sort_order: 182 , front_translations: {"de":"Was ist der NPS (Net Promoter Score)?"}, back_translations: {"de":"Eine Kennzahl, die Kundenloyalität misst, indem gefragt wird: „Wie wahrscheinlich ist es, dass Sie dieses Produkt einem Freund empfehlen?\" (Skala 0-10). Promotoren (9-10) minus Detraktoren (0-6) = NPS. Werte über 50 sind ausgezeichnet. Der NPS korreliert mit organischem Wachstum durch Mundpropaganda."}},
  { id: 'dc-startup-0183', deck_id: 'deck-startup-fundamentals', front: 'What is the Hacker News launch strategy?', back: 'Posting a Show HN on news.ycombinator.com to reach a technical, early-adopter audience. Write a clear title, provide a genuine demo, and be responsive in comments. A front-page post can drive 10K-50K visitors in a day. Best for developer tools, SaaS, and technical products.', sort_order: 183 , front_translations: {"de":"Was ist die Hacker News Launch-Strategie?"}, back_translations: {"de":"Einen Show HN auf news.ycombinator.com posten, um ein technisches Early-Adopter-Publikum zu erreichen. Schreibe einen klaren Titel, biete eine echte Demo und sei reaktionsschnell in den Kommentaren. Ein Frontpage-Beitrag kann 10.000-50.000 Besucher an einem Tag bringen. Am besten geeignet für Developer Tools, SaaS und technische Produkte."}},
  { id: 'dc-startup-0184', deck_id: 'deck-startup-fundamentals', front: 'What is a growth experiment?', back: 'A structured test of a hypothesis about what will drive growth. Define the hypothesis, set a success metric, run the test for a fixed period, and analyze results. Examples: testing a new CTA button, trying a different ad audience, or changing onboarding steps. Run many small experiments to find winners.', sort_order: 184 , front_translations: {"de":"Was ist ein Growth Experiment?"}, back_translations: {"de":"Ein strukturierter Test einer Hypothese darüber, was Wachstum antreiben wird. Definiere die Hypothese, lege eine Erfolgsmetrik fest, führe den Test über einen festen Zeitraum durch und analysiere die Ergebnisse. Beispiele: einen neün CTA-Button testen, eine andere Anzeigenzielgruppe ausprobieren oder Onboarding-Schritte ändern. Führe viele kleine Experimente durch, um Gewinner zu finden."}},
  { id: 'dc-startup-0185', deck_id: 'deck-startup-fundamentals', front: 'What is social proof and how do startups use it?', back: 'The psychological phenomenon where people follow the actions and opinions of others. Startups leverage it through customer testimonials, user counts, logos of well-known clients, star ratings, press mentions, and case studies. Social proof is one of the most effective conversion tools.', sort_order: 185 , front_translations: {"de":"Was ist Social Proof und wie nutzen Startups ihn?"}, back_translations: {"de":"Das psychologische Phänomen, bei dem Menschen den Handlungen und Meinungen anderer folgen. Startups nutzen ihn durch Kundenreferenzen, Nutzerzahlen, Logos bekannter Kunden, Sternebewertungen, Presseerwähnungen und Fallstudien. Social Proof ist eines der effektivsten Conversion-Tools."}},
  { id: 'dc-startup-0186', deck_id: 'deck-startup-fundamentals', front: 'What is a call to action (CTA)?', back: 'A prompt that tells the visitor exactly what to do next: "Start Free Trial," "Sign Up Now," "Get Started." Effective CTAs are specific, action-oriented, create urgency, and stand out visually. Test different CTA text, color, and placement to optimize conversion rates.', sort_order: 186 , front_translations: {"de":"Was ist ein Call to Action (CTA)?"}, back_translations: {"de":"Eine Aufforderung, die dem Besucher genau sagt, was er als Nächstes tun soll: „Kostenlos testen\", „Jetzt anmelden\", „Loslegen\". Effektive CTAs sind spezifisch, handlungsorientiert, erzeugen Dringlichkeit und stechen visüll hervor. Teste verschiedene CTA-Texte, Farben und Platzierungen, um die Conversion Rates zu optimieren."}},
  { id: 'dc-startup-0187', deck_id: 'deck-startup-fundamentals', front: 'What is SEO keyword research for startups?', back: 'The process of finding search terms your target customers use and creating content around them. Focus on long-tail keywords with lower competition and higher intent. Tools like Ahrefs, SEMrush, and Google Keyword Planner help identify opportunities. Prioritize keywords aligned with buyer intent.', sort_order: 187 , front_translations: {"de":"Was ist SEO-Keyword-Recherche für Startups?"}, back_translations: {"de":"Der Prozess, Suchbegriffe zu finden, die deine Zielkunden verwenden, und Inhalte dazu zu erstellen. Konzentriere dich auf Long-Tail-Keywords mit geringerem Wettbewerb und höherer Kaufabsicht. Tools wie Ahrefs, SEMrush und der Google Keyword Planner helfen, Chancen zu identifizieren. Priorisiere Keywords, die zur Kaufabsicht passen."}},
  { id: 'dc-startup-0188', deck_id: 'deck-startup-fundamentals', front: 'What is a customer success function?', back: 'A team or role dedicated to ensuring customers achieve their desired outcomes using your product. Unlike support (reactive), customer success is proactive — reaching out to help users adopt features, expand usage, and renew. Critical for reducing churn in SaaS businesses.', sort_order: 188 , front_translations: {"de":"Was ist eine Customer-Success-Funktion?"}, back_translations: {"de":"Ein Team oder eine Rolle, das/die sicherstellt, dass Kunden ihre gewünschten Ergebnisse mit deinem Produkt erreichen. Anders als Support (reaktiv) ist Customer Success proaktiv – man kontaktiert Nutzer, um ihnen bei der Feature-Nutzung, Ausbau der Verwendung und Verlängerung zu helfen. Entscheidend für die Reduzierung von Churn in SaaS-Unternehmen."}},
  { id: 'dc-startup-0189', deck_id: 'deck-startup-fundamentals', front: 'What is a freemium conversion strategy?', back: 'Tactics to move free users to paid plans. Best practices: clearly demonstrate the value of premium features, use usage limits that trigger when users are engaged, send targeted upgrade prompts based on behavior, and offer time-limited trials of premium features.', sort_order: 189 , front_translations: {"de":"Was ist eine Freemium-Conversion-Strategie?"}, back_translations: {"de":"Taktiken, um kostenlose Nutzer zu zahlenden Plänen zu bewegen. Best Practices: den Wert der Premium-Features klar demonstrieren, Nutzungslimits verwenden, die greifen, wenn Nutzer engagiert sind, gezielte Upgrade-Aufforderungen basierend auf dem Verhalten senden und zeitlich begrenzte Testversionen der Premium-Features anbieten."}},
  { id: 'dc-startup-0190', deck_id: 'deck-startup-fundamentals', front: 'What is attribution in marketing?', back: 'Determining which marketing channels and touchpoints deserve credit for a conversion. Models include first-touch (credit to the first interaction), last-touch (credit to the final interaction), and multi-touch (credit distributed across interactions). Proper attribution helps optimize marketing spend.', sort_order: 190 , front_translations: {"de":"Was ist Attribution im Marketing?"}, back_translations: {"de":"Die Bestimmung, welche Marketingkanäle und Berührungspunkte für eine Conversion verantwortlich sind. Modelle umfassen First-Touch (dem ersten Kontaktpunkt zugeordnet), Last-Touch (dem letzten Kontaktpunkt zugeordnet) und Multi-Touch (auf mehrere Kontaktpunkte verteilt). Korrekte Attribution hilft, die Marketingausgaben zu optimieren."}},
  { id: 'dc-startup-0191', deck_id: 'deck-startup-fundamentals', front: 'What is a product-qualified lead (PQL)?', back: 'A lead who has used your product (usually through a free trial or freemium tier) and demonstrated behavior indicating they are likely to become a paying customer. PQLs convert at much higher rates than marketing-qualified leads because they have already experienced value.', sort_order: 191 , front_translations: {"de":"Was ist ein Product-Qualified Lead (PQL)?"}, back_translations: {"de":"Ein Lead, der dein Produkt genutzt hat (meist über eine kostenlose Testversion oder Freemium-Stufe) und Verhalten gezeigt hat, das darauf hindeutet, dass er wahrscheinlich zahlender Kunde wird. PQLs konvertieren deutlich besser als Marketing-Qualified Leads, da sie bereits einen Mehrwert erfahren haben."}},
  { id: 'dc-startup-0192', deck_id: 'deck-startup-fundamentals', front: 'What is cold outreach and when is it effective?', back: 'Contacting potential customers who have not expressed interest, typically via email or LinkedIn. Effective for B2B startups targeting specific companies. Keys to success: personalize each message, lead with value not features, keep it short, and follow up persistently but respectfully.', sort_order: 192 , front_translations: {"de":"Was ist Cold Outreach und wann ist es effektiv?"}, back_translations: {"de":"Die Kontaktaufnahme mit potenziellen Kunden, die noch kein Interesse gezeigt haben, typischerweise per E-Mail oder LinkedIn. Effektiv für B2B-Startups, die bestimmte Unternehmen ansprechen. Erfolgsfaktoren: jede Nachricht personalisieren, mit Mehrwert statt Features führen, kurz halten und beharrlich, aber respektvoll nachfassen."}},
  { id: 'dc-startup-0193', deck_id: 'deck-startup-fundamentals', front: 'What is a marketing channel strategy for early startups?', back: 'Test 2-3 channels at a time with small budgets, measure results rigorously, and double down on what works. The Bullseye Framework by Gabriel Weinberg suggests brainstorming all 19 traction channels, testing the most promising three, and focusing on the single best performer.', sort_order: 193 , front_translations: {"de":"Was ist eine Marketingkanal-Strategie für frühe Startups?"}, back_translations: {"de":"Teste 2-3 Kanäle gleichzeitig mit kleinen Budgets, miss die Ergebnisse rigoros und investiere verstärkt in das, was funktioniert. Das Bullseye Framework von Gabriel Weinberg empfiehlt, alle 19 Traktionskanäle zu brainstormen, die drei vielversprechendsten zu testen und sich auf den einen besten zu konzentrieren."}},
  { id: 'dc-startup-0194', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between brand marketing and performance marketing?', back: 'Brand marketing builds long-term awareness, trust, and emotional connection (harder to measure directly). Performance marketing drives immediate, measurable actions like clicks, sign-ups, or purchases. Early-stage startups usually focus on performance marketing but should build brand over time.', sort_order: 194 , front_translations: {"de":"Was ist der Unterschied zwischen Markenmarketing und Performance Marketing?"}, back_translations: {"de":"Markenmarketing baut langfristiges Bewusstsein, Vertraün und emotionale Bindung auf (schwerer direkt messbar). Performance Marketing treibt sofortige, messbare Aktionen wie Klicks, Anmeldungen oder Käufe an. Startups in der Frühphase fokussieren sich meist auf Performance Marketing, sollten aber mit der Zeit eine Marke aufbaun."}},
  { id: 'dc-startup-0195', deck_id: 'deck-startup-fundamentals', front: 'What is a customer feedback loop in growth?', back: 'A process where customer feedback directly informs product improvements, which then increase satisfaction and drive more referrals. The tighter this loop, the faster you improve. Collect feedback through surveys, support tickets, interviews, and usage analytics. Close the loop by communicating changes back.', sort_order: 195 , front_translations: {"de":"Was ist eine Kundenfeedback-Schleife im Wachstum?"}, back_translations: {"de":"Ein Prozess, bei dem Kundenfeedback direkt Produktverbesserungen beeinflusst, die wiederum die Zufriedenheit steigern und mehr Empfehlungen generieren. Je enger diese Schleife, desto schneller verbesserst du dich. Sammle Feedback durch Umfragen, Support-Tickets, Interviews und Nutzungsanalysen. Schließe die Schleife, indem du Änderungen kommunizierst."}},

  // === Legal & Operations (196-220) ===
  { id: 'dc-startup-0196', deck_id: 'deck-startup-fundamentals', front: 'What is an LLC (Limited Liability Company)?', back: 'A business structure that provides personal liability protection while offering tax flexibility. Owners (members) are not personally liable for business debts. LLCs can be taxed as sole proprietorships, partnerships, or corporations. Popular for small businesses but less common for VC-backed startups.', sort_order: 196 , front_translations: {"de":"Was ist eine LLC (Limited Liability Company)?"}, back_translations: {"de":"Eine Unternehmensstruktur, die persönlichen Haftungsschutz bietet und gleichzeitig steürliche Flexibilität ermöglicht. Eigentümer (Members) haften nicht persönlich für Geschäftsschulden. LLCs können als Einzelunternehmen, Personengesellschaften oder Kapitalgesellschaften besteürt werden. Beliebt für kleine Unternehmen, aber seltener bei VC-finanzierten Startups."}},
  { id: 'dc-startup-0197', deck_id: 'deck-startup-fundamentals', front: 'What is a C-Corp and why do startups choose it?', back: 'A type of corporation that is a separate legal entity from its owners. C-Corps can issue multiple classes of stock (common and preferred), which is required for venture capital investment. Most VC-backed startups incorporate as Delaware C-Corps due to well-established corporate law.', sort_order: 197 , front_translations: {"de":"Was ist eine C-Corp und warum wählen Startups sie?"}, back_translations: {"de":"Eine Kapitalgesellschaft, die eine eigenständige juristische Person ist, getrennt von ihren Eigentümern. C-Corps können mehrere Aktienklassen ausgeben (Stamm- und Vorzugsaktien), was für Venture-Capital-Investitionen erforderlich ist. Die meisten VC-finanzierten Startups gründen als Delaware C-Corp aufgrund des etablierten Gesellschaftsrechts."}},
  { id: 'dc-startup-0198', deck_id: 'deck-startup-fundamentals', front: 'What is an S-Corp?', back: 'A tax election that allows a corporation to pass income, losses, and deductions through to shareholders, avoiding double taxation. Limited to 100 shareholders, all of whom must be US citizens/residents. Not suitable for VC-backed startups because it cannot issue preferred stock to investors.', sort_order: 198 , front_translations: {"de":"Was ist eine S-Corp?"}, back_translations: {"de":"Eine Steürklassifizierung, die es einer Kapitalgesellschaft ermöglicht, Einkommen, Verluste und Abzüge an die Anteilseigner durchzureichen und so eine Doppelbesteürung zu vermeiden. Begrenzt auf 100 Anteilseigner, die alle US-Bürger oder -Einwohner sein müssen. Nicht geeignet für VC-finanzierte Startups, da keine Vorzugsaktien an Investoren ausgegeben werden können."}},
  { id: 'dc-startup-0199', deck_id: 'deck-startup-fundamentals', front: 'Why do many startups incorporate in Delaware?', back: 'Delaware has the most developed body of corporate law, a specialized business court (Court of Chancery), and predictable legal precedents. Investors and lawyers are familiar with Delaware law, which reduces legal costs and complexity. Most VC-backed startups incorporate there regardless of where they operate.', sort_order: 199 , front_translations: {"de":"Warum gründen viele Startups in Delaware?"}, back_translations: {"de":"Delaware hat das am weitesten entwickelte Gesellschaftsrecht, ein spezialisiertes Wirtschaftsgericht (Court of Chancery) und vorhersehbare Rechtsprechung. Investoren und Anwälte sind mit dem Recht von Delaware vertraut, was Rechtskosten und Komplexität reduziert. Die meisten VC-finanzierten Startups gründen dort, unabhängig vom tatsächlichen Betriebsstandort."}},
  { id: 'dc-startup-0200', deck_id: 'deck-startup-fundamentals', front: 'What is a patent and when should startups file one?', back: 'A government-granted right that excludes others from making, using, or selling an invention for typically 20 years. Filing is expensive ($10K-$30K+) and slow (2-4 years). Startups should file when they have a truly novel, non-obvious invention that is core to their competitive advantage.', sort_order: 200 , front_translations: {"de":"Was ist ein Patent und wann sollten Startups eines anmelden?"}, back_translations: {"de":"Ein staatlich gewährtes Recht, das anderen verbietet, eine Erfindung herzustellen, zu nutzen oder zu verkaufen, typischerweise für 20 Jahre. Die Anmeldung ist teür (10.000-30.000+ $) und langwierig (2-4 Jahre). Startups sollten ein Patent anmelden, wenn sie eine wirklich neuartige, nicht offensichtliche Erfindung haben, die zentral für ihren Wettbewerbsvorteil ist."}},
  { id: 'dc-startup-0201', deck_id: 'deck-startup-fundamentals', front: 'What is a trademark?', back: 'Legal protection for brand identifiers like names, logos, slogans, and sounds. Registration with the USPTO provides nationwide protection and the right to sue for infringement. Startups should trademark their name and logo early to prevent competitors from using similar branding.', sort_order: 201 , front_translations: {"de":"Was ist eine Marke (Trademark)?"}, back_translations: {"de":"Rechtlicher Schutz für Markenidentifikatoren wie Namen, Logos, Slogans und Klänge. Die Registrierung beim USPTO bietet landesweiten Schutz und das Recht, bei Verletzung zu klagen. Startups sollten ihren Namen und ihr Logo früh schützen lassen, um zu verhindern, dass Wettbewerber ähnliches Branding verwenden."}},
  { id: 'dc-startup-0202', deck_id: 'deck-startup-fundamentals', front: 'What is copyright in the context of startups?', back: 'Legal protection for original creative works including software code, written content, designs, and media. Copyright is automatic upon creation but registration provides stronger legal standing. Startups should ensure they own copyrights to all code and content created by employees and contractors.', sort_order: 202 , front_translations: {"de":"Was ist Urheberrecht im Startup-Kontext?"}, back_translations: {"de":"Rechtlicher Schutz für originale kreative Werke, einschliesslich Softwarecode, schriftlicher Inhalte, Designs und Medien. Das Urheberrecht entsteht automatisch bei der Erstellung, aber eine Registrierung bietet stärkeren Rechtsschutz. Startups sollten sicherstellen, dass sie die Urheberrechte an allem Code und allen Inhalten besitzen, die von Mitarbeitern und Auftragnehmern erstellt werden."}},
  { id: 'dc-startup-0203', deck_id: 'deck-startup-fundamentals', front: 'What is a trade secret?', back: 'Confidential business information that provides a competitive advantage, such as algorithms, customer lists, or manufacturing processes. Unlike patents, trade secrets have no expiration but lose protection if disclosed. Protect them with NDAs, access controls, and employee agreements.', sort_order: 203 , front_translations: {"de":"Was ist ein Geschäftsgeheimnis (Trade Secret)?"}, back_translations: {"de":"Vertrauliche Geschäftsinformationen, die einen Wettbewerbsvorteil bieten, wie Algorithmen, Kundenlisten oder Herstellungsverfahren. Im Gegensatz zu Patenten haben Geschäftsgeheimnisse kein Ablaufdatum, verlieren aber ihren Schutz bei Offenlegung. Schützen Sie sie durch NDAs, Zugriffskontrollen und Mitarbeitervereinbarungen."}},
  { id: 'dc-startup-0204', deck_id: 'deck-startup-fundamentals', front: 'What should a co-founder agreement include?', back: 'Key elements: equity split, vesting schedules, roles and responsibilities, decision-making process, IP assignment, salary expectations, what happens if a co-founder leaves, dispute resolution, and non-compete clauses. Put it in writing before writing any code — even with your best friend.', sort_order: 204 , front_translations: {"de":"Was sollte eine Mitgründer-Vereinbarung enthalten?"}, back_translations: {"de":"Wichtige Elemente: Equity-Aufteilung, Vesting-Zeitpläne, Rollen und Verantwortlichkeiten, Entscheidungsprozesse, IP-Uebertragung, Gehaltserwartungen, was passiert wenn ein Mitgründer ausscheidet, Streitbeilegung und Wettbewerbsverbote. Schriftlich festhalten, bevor auch nur eine Zeile Code geschrieben wird — selbst unter besten Freunden."}},
  { id: 'dc-startup-0205', deck_id: 'deck-startup-fundamentals', front: 'What is a standard vesting schedule for founders?', back: 'The most common is 4-year vesting with a 1-year cliff. The cliff means no equity vests until the first anniversary, then 25% vests at once. After the cliff, the remaining 75% vests monthly over 3 years. This protects the company if a co-founder leaves early.', sort_order: 205 , front_translations: {"de":"Was ist der Standard-Vesting-Zeitplan für Gründer?"}, back_translations: {"de":"Am gängigsten ist ein 4-Jahres-Vesting mit einem 1-Jahres-Cliff. Der Cliff bedeutet, dass bis zum ersten Jahrestag kein Equity gevestet wird, dann werden 25% auf einmal zugeteilt. Nach dem Cliff werden die verbleibenden 75% monatlich über 3 Jahre gevestet. Dies schützt das Unternehmen, falls ein Mitgründer früh ausscheidet."}},
  { id: 'dc-startup-0206', deck_id: 'deck-startup-fundamentals', front: 'What is a 1-year cliff in vesting?', back: 'A period during which no equity vests. If a founder or employee leaves before the cliff date (typically 1 year), they get zero equity. After the cliff, a large chunk vests immediately (usually 25%), and the rest vests gradually. It protects against people joining briefly and walking away with equity.', sort_order: 206 , front_translations: {"de":"Was ist ein 1-Jahres-Cliff beim Vesting?"}, back_translations: {"de":"Ein Zeitraum, in dem kein Equity gevestet wird. Wenn ein Gründer oder Mitarbeiter vor dem Cliff-Datum (typischerweise 1 Jahr) ausscheidet, erhält er null Equity. Nach dem Cliff wird ein grosser Anteil sofort zugeteilt (meist 25%), der Rest wird schrittweise gevestet. Es schützt davor, dass Personen kurz beitreten und mit Equity wieder gehen."}},
  { id: 'dc-startup-0207', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between a contractor and an employee?', back: 'Employees work under company direction, use company tools, and receive benefits. Contractors work independently, set their own hours, and provide their own tools. Misclassifying employees as contractors can result in significant legal penalties and back taxes. The IRS uses a multi-factor test.', sort_order: 207 , front_translations: {"de":"Was ist der Unterschied zwischen Auftragnehmer und Angestelltem?"}, back_translations: {"de":"Angestellte arbeiten unter Unternehmensleitung, nutzen Firmengeräte und erhalten Sozialleistungen. Auftragnehmer arbeiten selbstständig, bestimmen ihre eigenen Arbeitszeiten und stellen ihre eigenen Arbeitsmittel. Die Fehlklassifizierung von Angestellten als Auftragnehmer kann zu erheblichen Strafen und Steürnachzahlungen führen. Der IRS verwendet einen Mehrfaktoren-Test."}},
  { id: 'dc-startup-0208', deck_id: 'deck-startup-fundamentals', front: 'Why do startups need Terms of Service?', back: 'Terms of Service define the legal agreement between the company and its users. They set expectations for acceptable use, limit liability, establish dispute resolution procedures, and protect intellectual property. Having clear terms reduces legal risk and is required for most app stores.', sort_order: 208 , front_translations: {"de":"Warum brauchen Startups Nutzungsbedingungen (Terms of Service)?"}, back_translations: {"de":"Nutzungsbedingungen definieren die rechtliche Vereinbarung zwischen Unternehmen und Nutzern. Sie legen Erwartungen für akzeptable Nutzung fest, begrenzen die Haftung, etablieren Streitbeilegungsverfahren und schützen geistiges Eigentum. Klare Bedingungen reduzieren das Rechtsrisiko und sind für die meisten App Stores erforderlich."}},
  { id: 'dc-startup-0209', deck_id: 'deck-startup-fundamentals', front: 'Why do startups need a Privacy Policy?', back: 'A Privacy Policy discloses how you collect, use, store, and share user data. It is legally required in most jurisdictions if you collect any personal data. Required by GDPR, CCPA, and app stores. Lack of a privacy policy can result in fines, lawsuits, and loss of user trust.', sort_order: 209 , front_translations: {"de":"Warum brauchen Startups eine Datenschutzerklärung?"}, back_translations: {"de":"Eine Datenschutzerklärung legt offen, wie Sie Nutzerdaten erheben, verwenden, speichern und weitergeben. Sie ist in den meisten Rechtsgebieten gesetzlich vorgeschrieben, sobald personenbezogene Daten erhoben werden. Erforderlich durch DSGVO, CCPA und App Stores. Das Fehlen einer Datenschutzerklärung kann zu Bussgeldern, Klagen und Vertraünsverlust führen."}},
  { id: 'dc-startup-0210', deck_id: 'deck-startup-fundamentals', front: 'What is GDPR and how does it affect startups?', back: 'The General Data Protection Regulation is an EU law governing personal data collection and processing. It requires explicit user consent, data minimization, the right to be forgotten, and breach notification within 72 hours. Applies to any company serving EU residents, regardless of location. Fines can reach 4% of global revenue.', sort_order: 210 , front_translations: {"de":"Was ist die DSGVO und wie betrifft sie Startups?"}, back_translations: {"de":"Die Datenschutz-Grundverordnung ist ein EU-Gesetz zur Regelung der Erhebung und Verarbeitung personenbezogener Daten. Sie verlangt ausdrückliche Nutzereinwilligung, Datenminimierung, das Recht auf Vergessenwerden und Meldung von Datenpannen innerhalb von 72 Stunden. Gilt für jedes Unternehmen, das EU-Bürger bedient, unabhängig vom Standort. Bussgelder können bis zu 4% des weltweiten Umsatzes betragen."}},
  { id: 'dc-startup-0211', deck_id: 'deck-startup-fundamentals', front: 'What is an IP (Intellectual Property) assignment agreement?', back: 'A legal document transferring ownership of intellectual property created by founders, employees, or contractors to the company. Without it, creators may retain IP rights. Every person who writes code, creates designs, or develops ideas for the startup should sign one.', sort_order: 211 , front_translations: {"de":"Was ist eine IP-Uebertragungsvereinbarung (IP Assignment)?"}, back_translations: {"de":"Ein rechtliches Dokument, das das Eigentum an geistigem Eigentum, das von Gründern, Mitarbeitern oder Auftragnehmern geschaffen wurde, auf das Unternehmen überträgt. Ohne diese Vereinbarung können Urheber IP-Rechte behalten. Jede Person, die Code schreibt, Designs erstellt oder Ideen für das Startup entwickelt, sollte eine solche unterzeichnen."}},
  { id: 'dc-startup-0212', deck_id: 'deck-startup-fundamentals', front: 'What is a Non-Disclosure Agreement (NDA)?', back: 'A legal contract that prevents parties from sharing confidential information. Startups use NDAs with employees, contractors, and sometimes partners. Most VCs will not sign NDAs because they see many similar pitches. Use NDAs selectively — overusing them signals inexperience.', sort_order: 212 , front_translations: {"de":"Was ist eine Vertraulichkeitsvereinbarung (NDA)?"}, back_translations: {"de":"Ein rechtlicher Vertrag, der Parteien daran hindert, vertrauliche Informationen weiterzugeben. Startups verwenden NDAs mit Mitarbeitern, Auftragnehmern und manchmal Partnern. Die meisten VCs werden keine NDAs unterzeichnen, da sie viele ähnliche Pitches sehen. Setzen Sie NDAs gezielt ein — übertriebener Einsatz signalisiert Unerfahrenheit."}},
  { id: 'dc-startup-0213', deck_id: 'deck-startup-fundamentals', front: 'What is a non-compete agreement?', back: 'A contract clause preventing employees or founders from working for competitors or starting competing businesses for a specified period after leaving. Enforceability varies widely by jurisdiction — California generally does not enforce them. Some states have banned them entirely for employees.', sort_order: 213 , front_translations: {"de":"Was ist ein Wettbewerbsverbot (Non-Compete)?"}, back_translations: {"de":"Eine Vertragsklausel, die Mitarbeiter oder Gründer daran hindert, für einen bestimmten Zeitraum nach dem Ausscheiden für Wettbewerber zu arbeiten oder konkurrierende Unternehmen zu gründen. Die Durchsetzbarkeit variiert stark je nach Rechtsgebiet — Kalifornien setzt sie generell nicht durch. Einige Staaten haben sie für Arbeitnehmer vollständig verboten."}},
  { id: 'dc-startup-0214', deck_id: 'deck-startup-fundamentals', front: 'What is 83(b) election and why should founders file it?', back: 'A tax filing that allows founders to pay tax on restricted stock at its current (low) value rather than when it vests at a potentially much higher value. Must be filed within 30 days of receiving stock. Missing the deadline cannot be reversed and can result in enormous tax bills later.', sort_order: 214 , front_translations: {"de":"Was ist die 83(b) Election und warum sollten Gründer sie einreichen?"}, back_translations: {"de":"Eine Steürerklärung, die es Gründern ermöglicht, Steürn auf beschränkte Aktien zu ihrem aktuellen (niedrigen) Wert zu zahlen, anstatt zum Zeitpunkt des Vestings bei einem möglicherweise viel höheren Wert. Muss innerhalb von 30 Tagen nach Erhalt der Aktien eingereicht werden. Die verpasste Frist kann nicht rückgängig gemacht werden und kann später zu enormen Steürrechnungen führen."}},
  { id: 'dc-startup-0215', deck_id: 'deck-startup-fundamentals', front: 'What are the legal requirements to hire employees?', back: 'Key requirements include obtaining an EIN, setting up payroll and tax withholding, verifying employment eligibility (I-9 form), providing workers compensation insurance, complying with wage and hour laws, and following anti-discrimination regulations. Use payroll services like Gusto or Rippling.', sort_order: 215 , front_translations: {"de":"Was sind die rechtlichen Anforderungen für die Einstellung von Mitarbeitern?"}, back_translations: {"de":"Wesentliche Anforderungen umfassen: Beantragung einer EIN, Einrichtung der Gehaltsabrechnung und Steüreinbehaltung, Ueberprüfung der Arbeitsberechtigung (I-9-Formular), Bereitstellung einer Arbeitnehmer-Unfallversicherung, Einhaltung der Lohn- und Arbeitszeitgesetze sowie Antidiskriminierungsvorschriften. Nutzen Sie Payroll-Dienste wie Gusto oder Rippling."}},
  { id: 'dc-startup-0216', deck_id: 'deck-startup-fundamentals', front: 'What is CCPA and how does it affect startups?', back: 'The California Consumer Privacy Act gives California residents the right to know what personal data is collected, request deletion, and opt out of data sales. It applies to businesses meeting certain revenue or data thresholds. Similar to GDPR but with some key differences in scope and enforcement.', sort_order: 216 , front_translations: {"de":"Was ist der CCPA und wie betrifft er Startups?"}, back_translations: {"de":"Der California Consumer Privacy Act gibt kalifornischen Einwohnern das Recht zu erfahren, welche personenbezogenen Daten erhoben werden, deren Löschung zu verlangen und dem Verkauf von Daten zu widersprechen. Er gilt für Unternehmen, die bestimmte Umsatz- oder Datenschwellenwerte erreichen. Aehnlich wie die DSGVO, aber mit einigen wesentlichen Unterschieden bei Umfang und Durchsetzung."}},
  { id: 'dc-startup-0217', deck_id: 'deck-startup-fundamentals', front: 'What is a SaaS service-level agreement (SLA)?', back: 'A contract defining the level of service a customer can expect, including uptime guarantees (e.g., 99.9%), response times for support, and remedies if the provider fails to meet commitments. Enterprise customers often require SLAs before signing. Breaching an SLA can trigger service credits or refunds.', sort_order: 217 , front_translations: {"de":"Was ist ein SaaS Service-Level-Agreement (SLA)?"}, back_translations: {"de":"Ein Vertrag, der das erwartete Serviceniveau definiert, einschliesslich Verfügbarkeitsgarantien (z.B. 99,9%), Reaktionszeiten für den Support und Abhilfemassnahmen bei Nichteinhaltung. Enterprise-Kunden verlangen oft SLAs vor Vertragsabschluss. Ein SLA-Verstoss kann Servicegutschriften oder Erstattungen auslösen."}},
  { id: 'dc-startup-0218', deck_id: 'deck-startup-fundamentals', front: 'What is corporate governance for startups?', back: 'The system of rules and practices governing how a company is directed and controlled. Includes board structure, shareholder rights, meeting protocols, and decision-making processes. Good governance builds investor confidence and prevents conflicts. Start simple and formalize as you grow.', sort_order: 218 , front_translations: {"de":"Was ist Corporate Governance für Startups?"}, back_translations: {"de":"Das System von Regeln und Praktiken, das die Führung und Kontrolle eines Unternehmens regelt. Umfasst Vorstandsstruktur, Gesellschafterrechte, Sitzungsprotokolle und Entscheidungsprozesse. Gute Governance stärkt das Vertraün der Investoren und verhindert Konflikte. Beginnen Sie einfach und formalisieren Sie mit dem Wachstum."}},
  { id: 'dc-startup-0219', deck_id: 'deck-startup-fundamentals', front: 'What is a data processing agreement (DPA)?', back: 'A legally binding contract between a data controller and data processor that outlines how personal data will be handled. Required under GDPR when you share user data with third-party services. It specifies data security measures, breach notification procedures, and subprocessor terms.', sort_order: 219 , front_translations: {"de":"Was ist eine Datenverarbeitungsvereinbarung (DPA)?"}, back_translations: {"de":"Ein rechtlich bindender Vertrag zwischen einem Verantwortlichen und einem Auftragsverarbeiter, der festlegt, wie personenbezogene Daten behandelt werden. Unter der DSGVO erforderlich, wenn Sie Nutzerdaten mit Drittanbietern teilen. Er spezifiziert Datensicherheitsmassnahmen, Verfahren zur Meldung von Datenpannen und Unterauftragsverarbeiter-Bedingungen."}},
  { id: 'dc-startup-0220', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between incorporation and registration?', back: 'Incorporation creates a new legal entity (corporation or LLC) with its own rights and liabilities. Registration (foreign qualification) is notifying a state that your already-incorporated company will do business there. You incorporate once but may need to register in multiple states where you operate.', sort_order: 220 , front_translations: {"de":"Was ist der Unterschied zwischen Gründung und Registrierung?"}, back_translations: {"de":"Die Gründung (Incorporation) schafft eine neü juristische Person (Corporation oder LLC) mit eigenen Rechten und Pflichten. Die Registrierung (Foreign Qualification) informiert einen Staat, dass Ihr bereits gegründetes Unternehmen dort geschäftlich tätig sein wird. Sie gründen einmal, müssen sich aber möglicherweise in mehreren Staaten registrieren."}},

  // === Team & Culture (221-240) ===
  { id: 'dc-startup-0221', deck_id: 'deck-startup-fundamentals', front: 'How should startups approach hiring their first employees?', back: 'Hire generalists who are adaptable and self-directed, not specialists. Look for people who thrive in ambiguity and wear multiple hats. Prioritize culture fit and passion for the mission. Offer equity to compensate for below-market salaries. First hires define your culture — choose carefully.', sort_order: 221 , front_translations: {"de":"Wie sollten Startups die Einstellung ihrer ersten Mitarbeiter angehen?"}, back_translations: {"de":"Stellen Sie Generalisten ein, die anpassungsfähig und selbstgesteürt sind, keine Spezialisten. Suchen Sie Menschen, die mit Ungewissheit umgehen können und mehrere Rollen ausfüllen. Priorisieren Sie kulturelle Passung und Begeisterung für die Mission. Bieten Sie Equity als Ausgleich für unter dem Markt liegende Gehälter. Die ersten Mitarbeiter prägen Ihre Kultur — wählen Sie sorgfältig."}},
  { id: 'dc-startup-0222', deck_id: 'deck-startup-fundamentals', front: 'What is equity compensation for startup employees?', back: 'Offering stock options or restricted stock as part of compensation, letting employees share in the company upside. Typical employee option pools are 10-20% of total shares. Standard vesting is 4 years with a 1-year cliff. Equity aligns employee and company interests.', sort_order: 222 , front_translations: {"de":"Was ist Equity-Vergütung für Startup-Mitarbeiter?"}, back_translations: {"de":"Das Angebot von Stock Options oder Restricted Stock als Teil der Vergütung, damit Mitarbeiter am Unternehmenserfolg teilhaben. Typische Employee Option Pools umfassen 10-20% der Gesamtanteile. Standard-Vesting beträgt 4 Jahre mit einem 1-Jahres-Cliff. Equity bringt Mitarbeiter- und Unternehmensinteressen in Einklang."}},
  { id: 'dc-startup-0223', deck_id: 'deck-startup-fundamentals', front: 'What is an ESOP (Employee Stock Option Pool)?', back: 'A reserved pool of shares set aside for current and future employee stock option grants, typically 10-20% of total shares. Investors usually require creating an ESOP before investment, and it comes from the pre-money valuation (diluting founders, not investors).', sort_order: 223 , front_translations: {"de":"Was ist ein ESOP (Employee Stock Option Pool)?"}, back_translations: {"de":"Ein reservierter Pool von Anteilen für aktuelle und zukünftige Mitarbeiter-Stock-Option-Zuteilungen, typischerweise 10-20% der Gesamtanteile. Investoren verlangen in der Regel die Einrichtung eines ESOP vor der Investition, und er wird aus der Pre-Money-Bewertung gebildet (verwässert Gründer, nicht Investoren)."}},
  { id: 'dc-startup-0224', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between stock options and restricted stock?', back: 'Stock options give the right to buy shares at a set price (strike price) in the future. Restricted stock is actual ownership of shares, subject to vesting. Founders typically receive restricted stock (file 83(b) election). Employees typically receive stock options.', sort_order: 224 , front_translations: {"de":"Was ist der Unterschied zwischen Stock Options und Restricted Stock?"}, back_translations: {"de":"Stock Options geben das Recht, Anteile zu einem festgelegten Preis (Strike Price) in der Zukunft zu kaufen. Restricted Stock ist tatsächlicher Anteilsbesitz, der dem Vesting unterliegt. Gründer erhalten typischerweise Restricted Stock (83(b) Election einreichen). Mitarbeiter erhalten typischerweise Stock Options."}},
  { id: 'dc-startup-0225', deck_id: 'deck-startup-fundamentals', front: 'How do you build company culture from day one?', back: 'Define your core values early and hire people who embody them. Lead by example — culture flows from founder behavior. Create rituals (team lunches, retrospectives, celebrations). Document your culture and share it openly. Culture is not about perks — it is about how decisions are made and how people treat each other.', sort_order: 225 , front_translations: {"de":"Wie baut man von Anfang an eine Unternehmenskultur auf?"}, back_translations: {"de":"Definieren Sie früh Ihre Kernwerte und stellen Sie Menschen ein, die diese verkörpern. Gehen Sie mit gutem Beispiel voran — Kultur kommt vom Verhalten der Gründer. Schaffen Sie Rituale (Team-Mittagessen, Retrospektiven, Feiern). Dokumentieren Sie Ihre Kultur und teilen Sie sie offen. Kultur handelt nicht von Vergünstigungen — sondern davon, wie Entscheidungen getroffen werden und wie Menschen miteinander umgehen."}},
  { id: 'dc-startup-0226', deck_id: 'deck-startup-fundamentals', front: 'What are the pros and cons of remote vs in-person startup teams?', back: 'Remote: access to global talent, lower overhead, flexibility, but harder to build culture and communicate quickly. In-person: faster collaboration, stronger bonds, easier onboarding, but limited talent pool and higher costs. Many startups succeed with hybrid models — remote-first with periodic in-person meetups.', sort_order: 226 , front_translations: {"de":"Was sind die Vor- und Nachteile von Remote- vs. Präsenz-Startup-Teams?"}, back_translations: {"de":"Remote: Zugang zu globalen Talenten, geringere Kosten, Flexibilität, aber schwieriger Kultur aufzubaun und schnell zu kommunizieren. Präsenz: schnellere Zusammenarbeit, stärkere Bindung, einfacheres Onboarding, aber begrenzter Talentpool und höhere Kosten. Viele Startups sind mit Hybridmodellen erfolgreich — Remote-first mit regelmässigen persönlichen Treffen."}},
  { id: 'dc-startup-0227', deck_id: 'deck-startup-fundamentals', front: 'What leadership styles work best for startup founders?', back: 'Servant leadership (removing obstacles for the team), transformational leadership (inspiring through vision), and situational leadership (adapting style to context) all work well. The best founders combine clear vision with humility, decisiveness with openness to feedback, and urgency with empathy.', sort_order: 227 , front_translations: {"de":"Welche Führungsstile funktionieren am besten für Startup-Gründer?"}, back_translations: {"de":"Servant Leadership (Hindernisse für das Team beseitigen), Transformational Leadership (durch Vision inspirieren) und Situational Leadership (Stil an den Kontext anpassen) funktionieren alle gut. Die besten Gründer verbinden klare Vision mit Bescheidenheit, Entschlossenheit mit Offenheit für Feedback und Dringlichkeit mit Empathie."}},
  { id: 'dc-startup-0228', deck_id: 'deck-startup-fundamentals', front: 'How do you manage co-founder relationships?', back: 'Set clear roles and decision-making authority upfront. Communicate regularly and honestly. Address conflicts early — they do not resolve themselves. Have a formal co-founder agreement. Schedule regular check-ins to discuss strategy, concerns, and personal well-being. Co-founder breakups are a top reason startups fail.', sort_order: 228 , front_translations: {"de":"Wie managt man Mitgründer-Beziehungen?"}, back_translations: {"de":"Legen Sie klare Rollen und Entscheidungsbefugnisse von Anfang an fest. Kommunizieren Sie regelmässig und ehrlich. Gehen Sie Konflikte früh an — sie lösen sich nicht von selbst. Haben Sie eine formelle Mitgründer-Vereinbarung. Planen Sie regelmässige Gespräche zu Strategie, Bedenken und persönlichem Wohlbefinden. Mitgründer-Trennungen sind ein Hauptgrund für das Scheitern von Startups."}},
  { id: 'dc-startup-0229', deck_id: 'deck-startup-fundamentals', front: 'What is a startup advisory board?', back: 'A group of experienced individuals who provide strategic advice, introductions, and credibility. Unlike board directors, advisors have no legal authority or fiduciary duty. Compensate with 0.25-1% equity vesting over 2 years. Choose advisors who fill specific knowledge gaps and actively open doors.', sort_order: 229 , front_translations: {"de":"Was ist ein Startup-Beirat (Advisory Board)?"}, back_translations: {"de":"Eine Gruppe erfahrener Personen, die strategische Beratung, Kontakte und Glaubwürdigkeit bieten. Im Gegensatz zu Vorstandsmitgliedern haben Berater keine rechtliche Befugnis oder treuhhänderische Pflicht. Vergütung mit 0,25-1% Equity, gevestet über 2 Jahre. Wählen Sie Berater, die spezifische Wissenslücken füllen und aktiv Türen öffnen."}},
  { id: 'dc-startup-0230', deck_id: 'deck-startup-fundamentals', front: 'What is the role of a mentor for startup founders?', back: 'A mentor provides guidance based on their own experience, acts as a sounding board for difficult decisions, and helps founders avoid common mistakes. The best mentoring relationships are specific (focused on particular challenges) and ongoing. Look for mentors who have built companies in your industry.', sort_order: 230 , front_translations: {"de":"Welche Rolle spielt ein Mentor für Startup-Gründer?"}, back_translations: {"de":"Ein Mentor gibt Orientierung basierend auf eigener Erfahrung, dient als Sparringspartner für schwierige Entscheidungen und hilft Gründern, häufige Fehler zu vermeiden. Die besten Mentoring-Beziehungen sind spezifisch (auf bestimmte Herausforderungen fokussiert) und langfristig. Suchen Sie Mentoren, die Unternehmen in Ihrer Branche aufgebaut haben."}},
  { id: 'dc-startup-0231', deck_id: 'deck-startup-fundamentals', front: 'How should startups approach their first sales hire?', back: 'Founders should sell the product themselves first to understand the process and customer objections. Only hire a salesperson when you have a repeatable sales process. Look for someone who has sold to your target market before and is comfortable with ambiguity. Give them a ramp period of 3-6 months.', sort_order: 231 , front_translations: {"de":"Wie sollten Startups ihre erste Vertriebsperson einstellen?"}, back_translations: {"de":"Gründer sollten das Produkt zuerst selbst verkaufen, um den Prozess und Kundeneinwände zu verstehen. Stellen Sie erst eine Vertriebsperson ein, wenn Sie einen wiederholbaren Verkaufsprozess haben. Suchen Sie jemanden, der bereits an Ihre Zielgruppe verkauft hat und mit Ungewissheit umgehen kann. Geben Sie eine Anlaufzeit von 3-6 Monaten."}},
  { id: 'dc-startup-0232', deck_id: 'deck-startup-fundamentals', front: 'What is founder burnout and how do you prevent it?', back: 'Physical and emotional exhaustion from the sustained intensity of building a startup. Prevent it by setting boundaries, maintaining relationships outside work, exercising regularly, and delegating tasks. Recognize that working 80+ hours per week is not sustainable and leads to worse decisions.', sort_order: 232 , front_translations: {"de":"Was ist Gründer-Burnout und wie beugt man vor?"}, back_translations: {"de":"Körperliche und emotionale Erschöpfung durch die anhaltende Intensität des Startup-Aufbaus. Vorbeugen durch Grenzen setzen, Beziehungen ausserhalb der Arbeit pflegen, regelmässig Sport treiben und Aufgaben delegieren. Erkennen Sie, dass 80+ Stunden pro Woche nicht nachhaltig sind und zu schlechteren Entscheidungen führen."}},
  { id: 'dc-startup-0233', deck_id: 'deck-startup-fundamentals', front: 'What is the ideal founding team composition?', back: 'A strong founding team typically has complementary skills: a builder (technical), a seller (business/sales), and optionally a designer (product/UX). Shared values and work ethic matter more than identical backgrounds. Two to three co-founders is ideal — solo founders face higher burnout risk.', sort_order: 233 , front_translations: {"de":"Was ist die ideale Zusammensetzung eines Gründerteams?"}, back_translations: {"de":"Ein starkes Gründerteam hat typischerweise komplementäre Fähigkeiten: einen Builder (technisch), einen Seller (Business/Vertrieb) und optional einen Designer (Produkt/UX). Gemeinsame Werte und Arbeitsmoral zählen mehr als identische Hintergründe. Zwei bis drei Mitgründer sind ideal — Einzelgründer haben ein höheres Burnout-Risiko."}},
  { id: 'dc-startup-0234', deck_id: 'deck-startup-fundamentals', front: 'What are OKRs (Objectives and Key Results)?', back: 'A goal-setting framework popularized by Google. Objectives are qualitative goals (what you want to achieve). Key Results are quantitative metrics that measure progress (how you know you achieved it). Example: Objective — Improve onboarding. KR1 — Increase activation rate from 30% to 50%.', sort_order: 234 , front_translations: {"de":"Was sind OKRs (Objectives and Key Results)?"}, back_translations: {"de":"Ein Zielsetzungs-Framework, das von Google populär gemacht wurde. Objectives sind qualitative Ziele (was Sie erreichen wollen). Key Results sind quantitative Metriken, die den Fortschritt messen (woran Sie erkennen, dass Sie es erreicht haben). Beispiel: Objective — Onboarding verbessern. KR1 — Aktivierungsrate von 30% auf 50% steigern."}},
  { id: 'dc-startup-0235', deck_id: 'deck-startup-fundamentals', front: 'How do startups create effective onboarding for new hires?', back: 'Prepare a 30-60-90 day plan with clear expectations. Assign a buddy or mentor. Provide documentation on tools, processes, and company context. Schedule meetings with key team members. Give a small, quick-win project in the first week. Good onboarding dramatically improves retention and productivity.', sort_order: 235 , front_translations: {"de":"Wie schaffen Startups ein effektives Onboarding für neü Mitarbeiter?"}, back_translations: {"de":"Erstellen Sie einen 30-60-90-Tage-Plan mit klaren Erwartungen. Weisen Sie einen Buddy oder Mentor zu. Stellen Sie Dokumentation zu Tools, Prozessen und Unternehmenskontext bereit. Planen Sie Meetings mit wichtigen Teammitgliedern. Geben Sie ein kleines Quick-Win-Projekt in der ersten Woche. Gutes Onboarding verbessert Mitarbeiterbindung und Produktivität drastisch."}},
  { id: 'dc-startup-0236', deck_id: 'deck-startup-fundamentals', front: 'What is psychological safety in a startup team?', back: 'An environment where team members feel safe to take risks, voice opinions, ask questions, and admit mistakes without fear of punishment. Google Project Aristotle found it was the number one factor in high-performing teams. Founders create it by responding to vulnerability with support, not criticism.', sort_order: 236 , front_translations: {"de":"Was ist psychologische Sicherheit in einem Startup-Team?"}, back_translations: {"de":"Eine Umgebung, in der Teammitglieder sich sicher fühlen, Risiken einzugehen, Meinungen zu äussern, Fragen zu stellen und Fehler zuzugeben, ohne Angst vor Bestrafung. Googles Project Aristotle fand heraus, dass dies der wichtigste Faktor in leistungsstarken Teams ist. Gründer schaffen sie, indem sie auf Verletzlichkeit mit Unterstützung reagieren, nicht mit Kritik."}},
  { id: 'dc-startup-0237', deck_id: 'deck-startup-fundamentals', front: 'When should a startup make its first executive hire?', back: 'Hire executives (VP of Engineering, VP of Sales) when the function they lead becomes too complex for the founder to manage effectively — typically after finding product-market fit and entering the scaling phase. Hiring too early wastes runway; too late creates bottlenecks and burnout.', sort_order: 237 , front_translations: {"de":"Wann sollte ein Startup seine erste Führungskraft einstellen?"}, back_translations: {"de":"Stellen Sie Führungskräfte (VP of Engineering, VP of Sales) ein, wenn die Funktion, die sie leiten, zu komplex für den Gründer wird — typischerweise nach Erreichen des Product-Market Fit und beim Eintritt in die Skalierungsphase. Zu frühes Einstellen verschwendet Runway; zu spätes schafft Engpässe und Burnout."}},
  { id: 'dc-startup-0238', deck_id: 'deck-startup-fundamentals', front: 'What is a cultural interview and why do startups use them?', back: 'A dedicated interview focused on assessing whether a candidate aligns with the company values and working style, separate from the technical interview. It evaluates communication, collaboration, adaptability, and mindset. Poor culture fit is a leading cause of early employee departures.', sort_order: 238 , front_translations: {"de":"Was ist ein Culture-Interview und warum nutzen Startups es?"}, back_translations: {"de":"Ein spezielles Interview, das bewertet, ob ein Kandidat mit den Unternehmenswerten und dem Arbeitsstil übereinstimmt, getrennt vom technischen Interview. Es evaluiert Kommunikation, Zusammenarbeit, Anpassungsfähigkeit und Denkweise. Schlechte kulturelle Passung ist eine Hauptursache für frühe Mitarbeiterabgänge."}},
  { id: 'dc-startup-0239', deck_id: 'deck-startup-fundamentals', front: 'What is a flat organizational structure in startups?', back: 'A structure with few or no management layers between staff and leadership. Common in early-stage startups because it enables fast decision-making and direct communication. As companies grow beyond 15-20 people, some structure and middle management usually becomes necessary to avoid chaos.', sort_order: 239 , front_translations: {"de":"Was ist eine flache Organisationsstruktur in Startups?"}, back_translations: {"de":"Eine Struktur mit wenigen oder keinen Managementebenen zwischen Mitarbeitern und Führung. Verbreitet in frühen Startup-Phasen, da sie schnelle Entscheidungsfindung und direkte Kommunikation ermöglicht. Wenn Unternehmen über 15-20 Personen hinauswachsen, wird in der Regel etwas Struktur und mittleres Management nötig, um Chaos zu vermeiden."}},
  { id: 'dc-startup-0240', deck_id: 'deck-startup-fundamentals', front: 'How should founders handle firing underperforming employees?', back: 'Act quickly once you have given clear feedback and a reasonable improvement period. Document performance issues. Be direct, compassionate, and brief in the conversation. Offer a severance package if possible. Delaying a necessary termination hurts the team, the company, and the individual.', sort_order: 240 , front_translations: {"de":"Wie sollten Gründer mit der Kündigung leistungsschwacher Mitarbeiter umgehen?"}, back_translations: {"de":"Handeln Sie schnell, nachdem Sie klares Feedback und eine angemessene Verbesserungsfrist gegeben haben. Dokumentieren Sie Leistungsprobleme. Seien Sie direkt, mitfühlend und kurz im Gespräch. Bieten Sie wenn möglich eine Abfindung an. Eine notwendige Kündigung zu verzögern schadet dem Team, dem Unternehmen und der betroffenen Person."}},

  // === Scaling & Advanced (241-250) ===
  { id: 'dc-startup-0241', deck_id: 'deck-startup-fundamentals', front: 'When should a startup begin scaling?', back: 'Scale only after achieving product-market fit, proven unit economics, and a repeatable acquisition process. Premature scaling (hiring, spending on marketing, expanding before these are in place) is the number one cause of startup death. Growth without retention is just expensive churn.', sort_order: 241 , front_translations: {"de":"Wann sollte ein Startup mit der Skalierung beginnen?"}, back_translations: {"de":"Skalieren Sie erst nach Erreichen des Product-Market Fit, bewiesener Unit Economics und eines wiederholbaren Akquisitionsprozesses. Vorzeitige Skalierung (Einstellen, Marketingausgaben, Expansion bevor dies gesichert ist) ist die häufigste Ursache für Startup-Scheitern. Wachstum ohne Retention ist nur teurer Churn."}},
  { id: 'dc-startup-0242', deck_id: 'deck-startup-fundamentals', front: 'How do startups approach international expansion?', back: 'Research local regulations, cultural differences, payment methods, and competition. Start with one market at a time. Consider localization (language, currency, support hours). Test demand with lightweight approaches (translated landing pages, local ads) before committing full resources.', sort_order: 242 , front_translations: {"de":"Wie gehen Startups die internationale Expansion an?"}, back_translations: {"de":"Recherchieren Sie lokale Vorschriften, kulturelle Unterschiede, Zahlungsmethoden und Wettbewerb. Beginnen Sie mit einem Markt nach dem anderen. Berücksichtigen Sie Lokalisierung (Sprache, Währung, Support-Zeiten). Testen Sie die Nachfrage mit leichtgewichtigen Ansätzen (übersetzte Landingpages, lokale Anzeigen), bevor Sie volle Ressourcen einsetzen."}},
  { id: 'dc-startup-0243', deck_id: 'deck-startup-fundamentals', front: 'When should a startup pivot vs persevere?', back: 'Pivot when data consistently shows your current approach is not working despite multiple iterations, or when you discover a bigger opportunity adjacent to your current model. Persevere when metrics are trending in the right direction, even if slowly. Eric Ries suggests pivoting on strategy while keeping the vision.', sort_order: 243 , front_translations: {"de":"Wann sollte ein Startup pivotieren vs. durchhalten?"}, back_translations: {"de":"Pivotieren Sie, wenn Daten durchgehend zeigen, dass Ihr aktueller Ansatz trotz mehrerer Iterationen nicht funktioniert, oder wenn Sie eine grössere Chance neben Ihrem aktuellen Modell entdecken. Halten Sie durch, wenn sich Metriken in die richtige Richtung entwickeln, auch wenn langsam. Eric Ries empfiehlt, die Strategie zu pivotieren und die Vision beizubehalten."}},
  { id: 'dc-startup-0244', deck_id: 'deck-startup-fundamentals', front: 'What are common types of pivots?', back: 'Zoom-in pivot (a feature becomes the product), zoom-out pivot (the product becomes a feature of something larger), customer segment pivot (targeting different users), value capture pivot (changing the revenue model), channel pivot (changing distribution), and technology pivot (using a different technology).', sort_order: 244 , front_translations: {"de":"Was sind gängige Pivot-Arten?"}, back_translations: {"de":"Zoom-in-Pivot (ein Feature wird zum Produkt), Zoom-out-Pivot (das Produkt wird zum Feature von etwas Grösserem), Kundensegment-Pivot (andere Zielgruppe), Value-Capture-Pivot (Aenderung des Erlösmodells), Channel-Pivot (Aenderung des Vertriebswegs) und Technologie-Pivot (Einsatz einer anderen Technologie)."}},
  { id: 'dc-startup-0245', deck_id: 'deck-startup-fundamentals', front: 'What are exit strategies for startup founders?', back: 'IPO (going public on a stock exchange), acquisition (being bought by a larger company), merger (combining with another company), management buyout, or acqui-hire (acquired primarily for the team). Most successful exits are acquisitions. Plan your preferred exit early as it influences strategy.', sort_order: 245 , front_translations: {"de":"Was sind Exit-Strategien für Startup-Gründer?"}, back_translations: {"de":"IPO (Börsengang), Acquisition (Uebernahme durch ein grösseres Unternehmen), Merger (Zusammenschluss mit einem anderen Unternehmen), Management-Buyout oder Acqui-Hire (Uebernahme hauptsächlich wegen des Teams). Die meisten erfolgreichen Exits sind Acquisitions. Planen Sie Ihren bevorzugten Exit früh, da er die Strategie beeinflusst."}},
  { id: 'dc-startup-0246', deck_id: 'deck-startup-fundamentals', front: 'What is an IPO (Initial Public Offering)?', back: 'The first time a company sells shares to the public on a stock exchange. It provides liquidity for founders and investors, raises large amounts of capital, and increases public visibility. Requirements include audited financials, regulatory compliance (SEC), and significant legal costs.', sort_order: 246 , front_translations: {"de":"Was ist ein IPO (Initial Public Offering)?"}, back_translations: {"de":"Das erste Mal, dass ein Unternehmen Aktien öffentlich an einer Börse verkauft. Es bietet Liquidität für Gründer und Investoren, beschafft grosse Kapitalmengen und erhöht die öffentliche Sichtbarkeit. Anforderungen umfassen geprüftes Rechnungswesen, regulatorische Compliance (SEC) und erhebliche Rechtskosten."}},
  { id: 'dc-startup-0247', deck_id: 'deck-startup-fundamentals', front: 'What are key startup metrics and KPIs investors track?', back: 'Revenue growth rate (month-over-month), gross margin, net revenue retention, CAC and LTV, burn rate and runway, DAU/MAU ratio, and churn rate. For pre-revenue startups: user growth, engagement, and activation rates. The specific metrics depend on your business model and stage.', sort_order: 247 , front_translations: {"de":"Welche wichtigen Startup-Metriken und KPIs verfolgen Investoren?"}, back_translations: {"de":"Umsatzwachstumsrate (Monat über Monat), Bruttomarge, Net Revenue Retention, CAC und LTV, Burn Rate und Runway, DAU/MAU-Verhältnis und Churn Rate. Für Pre-Revenue-Startups: Nutzerwachstum, Engagement und Aktivierungsraten. Die spezifischen Metriken hängen vom Geschäftsmodell und der Phase ab."}},
  { id: 'dc-startup-0248', deck_id: 'deck-startup-fundamentals', front: 'What are the most common reasons startups fail?', back: 'Top reasons include: no market need (building something nobody wants), running out of cash, wrong team, getting outcompeted, pricing/cost issues, poor product, ignoring customers, mistiming the market, and losing focus. Most failures trace back to building something the market does not want.', sort_order: 248 , front_translations: {"de":"Was sind die häufigsten Gründe für das Scheitern von Startups?"}, back_translations: {"de":"Top-Gründe: kein Marktbedarf (etwas baun, das niemand will), kein Geld mehr, falsches Team, von Wettbewerbern überholt, Preis-/Kostenprobleme, schlechtes Produkt, Kunden ignorieren, falsches Markttiming und Fokusverlust. Die meisten Misserfolge lassen sich darauf zurückführen, dass etwas gebaut wird, das der Markt nicht will."}},
  { id: 'dc-startup-0249', deck_id: 'deck-startup-fundamentals', front: 'What is an acquisition and how does the process work?', back: 'When a larger company buys a startup. The process includes initial interest, signing an LOI (Letter of Intent), due diligence, negotiation of purchase price and terms, definitive agreement, and closing. Payment can be cash, stock, or a combination. Typical process takes 2-6 months.', sort_order: 249 , front_translations: {"de":"Was ist eine Acquisition und wie läuft der Prozess ab?"}, back_translations: {"de":"Wenn ein grösseres Unternehmen ein Startup kauft. Der Prozess umfasst erstes Interesse, Unterzeichnung eines LOI (Letter of Intent), Dü Diligence, Verhandlung von Kaufpreis und Konditionen, definitiver Vertrag und Abschluss. Die Zahlung kann in bar, in Aktien oder einer Kombination erfolgen. Der typische Prozess dauert 2-6 Monate."}},
  { id: 'dc-startup-0250', deck_id: 'deck-startup-fundamentals', front: 'What is the Rule of 40 for SaaS companies?', back: 'A benchmark stating that a healthy SaaS company revenue growth rate plus profit margin should exceed 40%. For example, 30% growth + 15% profit margin = 45% (good). It balances growth and profitability — investors use it to evaluate whether a company is efficiently scaling.', sort_order: 250 , front_translations: {"de":"Was ist die Rule of 40 für SaaS-Unternehmen?"}, back_translations: {"de":"Ein Benchmark, der besagt, dass bei einem gesunden SaaS-Unternehmen die Umsatzwachstumsrate plus Gewinnmarge über 40% liegen sollte. Beispiel: 30% Wachstum + 15% Gewinnmarge = 45% (gut). Es balanciert Wachstum und Profitabilität — Investoren nutzen es, um zu bewerten, ob ein Unternehmen effizient skaliert."}},
];
